#include <vector>
#include <unordered_map>
using namespace std;

vector<int> twoSum(vector<int>& nums, int target) {
    // Create an unordered_map to store the number and its index
    unordered_map<int, int> numToIndex;
    // Iterate over the vector with index
    for (int i = 0; i < nums.size(); i++) {
        // Calculate the complement needed to reach the target
        int complement = target - nums[i];
        // Check if the complement exists in the map
        if (numToIndex.find(complement) != numToIndex.end()) {
            // Return the indices as a vector
            return {numToIndex[complement], i};
        }
        // Store the number with its index
        numToIndex[nums[i]] = i;
    }
    // Since the problem guarantees one solution, no return is needed here.
}

