// Definition for singly-linked list.
struct ListNode {
    int val;
    ListNode *next;
    ListNode() : val(0), next(nullptr) {}
    ListNode(int x) : val(x), next(nullptr) {}
    ListNode(int x, ListNode *next) : val(x), next(next) {}
};

class Solution {
public:
    ListNode* addTwoNumbers(ListNode* l1, ListNode* l2) {
        // Create a dummy node to simplify linked list construction.
        ListNode dummy(0);
        ListNode* current = &dummy;
        int carry = 0;

        // Continue processing until both lists are finished and there is no remaining carry.
        while (l1 || l2 || carry) {
            // Get the current node values (or use 0 if the node is missing).
            int val1 = l1 ? l1->val : 0;
            int val2 = l2 ? l2->val : 0;

            // Compute sum, update carry, and determine the current digit.
            int total = val1 + val2 + carry;
            carry = total / 10;
            int digit = total % 10;

            // Append the computed digit as a new node.
            current->next = new ListNode(digit);
            current = current->next;

            // Advance to the next nodes.
            if (l1) l1 = l1->next;
            if (l2) l2 = l2->next;
        }

        // Return the result list (next of dummy node since dummy is a placeholder).
        return dummy.next;
    }
};

