// Function to find the median of two sorted arrays
#include <iostream>
#include <vector>
#include <climits>
#include <algorithm>
using namespace std;

double findMedianSortedArrays(vector<int>& nums1, vector<int>& nums2) {
    // Ensure nums1 is the smaller array for binary search efficiency
    if (nums1.size() > nums2.size())
        return findMedianSortedArrays(nums2, nums1);

    int m = nums1.size();
    int n = nums2.size();
    int low = 0, high = m;

    while (low <= high) {
        // Partition indexes for nums1 and nums2
        int partitionNums1 = (low + high) / 2;
        int partitionNums2 = (m + n + 1) / 2 - partitionNums1;

        // Handling edge boundaries with INT_MIN and INT_MAX
        int maxLeftNums1 = (partitionNums1 == 0) ? INT_MIN : nums1[partitionNums1 - 1];
        int minRightNums1 = (partitionNums1 == m) ? INT_MAX : nums1[partitionNums1];

        int maxLeftNums2 = (partitionNums2 == 0) ? INT_MIN : nums2[partitionNums2 - 1];
        int minRightNums2 = (partitionNums2 == n) ? INT_MAX : nums2[partitionNums2];

        // Correct partition found
        if (maxLeftNums1 <= minRightNums2 && maxLeftNums2 <= minRightNums1) {
            // Even total elements -> median is the average of the two middle values
            if ((m + n) % 2 == 0)
                return (max(maxLeftNums1, maxLeftNums2) + min(minRightNums1, minRightNums2)) / 2.0;
            else
                return double(max(maxLeftNums1, maxLeftNums2));
        } else if (maxLeftNums1 > minRightNums2) {
            // Move partition in nums1 to left
            high = partitionNums1 - 1;
        } else {
            // Move partition in nums1 to right
            low = partitionNums1 + 1;
        }
    }
    throw invalid_argument("Input arrays are not sorted properly.");
}

int main() {
    vector<int> nums1 = {1, 3};
    vector<int> nums2 = {2};
    cout << findMedianSortedArrays(nums1, nums2) << endl; // Output: 2.0

    vector<int> nums3 = {1, 2};
    vector<int> nums4 = {3, 4};
    cout << findMedianSortedArrays(nums3, nums4) << endl; // Output: 2.5
    return 0;
}

