#include <iostream>
#include <string>
using namespace std;

// Helper function to expand around the center and return the palindrome substring
string expandFromCenter(const string& s, int left, int right) {
    while(left >= 0 && right < s.size() && s[left] == s[right]) {
        left--;
        right++;
    }
    // Return the substring from the last valid indices
    return s.substr(left + 1, right - left - 1);
}

string longestPalindromicSubstring(string s) {
    if(s.empty()) return "";
    string longest = "";
    for (int i = 0; i < s.size(); i++) {
        // Identify odd-length palindromes
        string oddPalindrome = expandFromCenter(s, i, i);
        if(oddPalindrome.size() > longest.size())
            longest = oddPalindrome;
        // Identify even-length palindromes
        string evenPalindrome = expandFromCenter(s, i, i + 1);
        if(evenPalindrome.size() > longest.size())
            longest = evenPalindrome;
    }
    return longest;
}

int main() {
    string s = "babad";
    cout << longestPalindromicSubstring(s) << endl;
    return 0;
}

