// C++ solution for the myAtoi problem.
#include <iostream>
#include <string>
#include <climits>
using namespace std;

int myAtoi(string s) {
    int i = 0, n = s.length();
    // Skip leading whitespace.
    while (i < n && s[i] == ' ') {
        i++;
    }

    int sign = 1;
    if (i < n && (s[i] == '-' || s[i] == '+')) {
        if (s[i] == '-') {
            sign = -1;
        }
        i++;
    }

    int result = 0;
    // Process digits and form the integer.
    while (i < n && isdigit(s[i])) {
        int digit = s[i] - '0';
        // Check for overflow/underflow.
        if (result > (INT_MAX - digit) / 10) {
            return sign == 1 ? INT_MAX : INT_MIN;
        }
        result = result * 10 + digit;
        i++;
    }

    return result * sign;
}

int main() {
    cout << myAtoi("42") << endl;
    cout << myAtoi(" -042") << endl;
    cout << myAtoi("1337c0d3") << endl;
    cout << myAtoi("0-1") << endl;
    cout << myAtoi("words and 987") << endl;
    return 0;
}

