// C++ solution to check if a number is a palindrome without converting it to a string.
class Solution {
public:
    bool isPalindrome(int x) {
        // Handle negative numbers and numbers ending in 0 (except 0 itself).
        if (x < 0 || (x % 10 == 0 && x != 0))
            return false;
        int reversedHalf = 0;
        // Reverse half of the number.
        while (x > reversedHalf) {
            // Append the last digit of x to reversedHalf.
            reversedHalf = reversedHalf * 10 + x % 10;
            // Remove the last digit from x.
            x /= 10;
        }
        // For odd-digit numbers, discard the middle digit by reversedHalf / 10.
        return x == reversedHalf || x == reversedHalf / 10;
    }
};

