// C++ solution using recursion with memoization and unordered_map for caching
#include <string>
#include <unordered_map>
using namespace std;

class Solution {
public:
    // key will be a combination of i and j.
    unordered_map<string, bool> memo;

    bool dp(const string &s, const string &p, int i, int j) {
        string key = to_string(i) + "," + to_string(j);
        if(memo.find(key) != memo.end()) {
            return memo[key];
        }

        bool ans;
        if(j == p.size()){
            ans = (i == s.size());
        } else {
            // Check if character is matching or pattern has '.'
            bool firstMatch = (i < s.size() && (p[j] == s[i] || p[j] == '.'));
            if(j + 1 < p.size() && p[j+1] == '*'){
                // Two cases: skip or use '*' if there is a match.
                ans = dp(s, p, i, j+2) || (firstMatch && dp(s, p, i+1, j));
            } else {
                ans = firstMatch && dp(s, p, i+1, j+1);
            }
        }

        memo[key] = ans;
        return ans;
    }

    bool isMatch(string s, string p) {
        return dp(s, p, 0, 0);
    }
};

