#include <vector>
#include <algorithm>
using namespace std;

// Function to calculate the maximum water container area
int maxArea(vector<int>& height) {
    int left = 0, right = height.size() - 1;
    int maxWater = 0;

    // Loop until the two pointers meet
    while (left < right) {
        // Calculate current area using the smaller height and the distance between the pointers
        int currentArea = min(height[left], height[right]) * (right - left);
        maxWater = max(maxWater, currentArea);  // Update maximum area if current is larger

        // Move the pointer corresponding to the smaller height inward
        if (height[left] < height[right])
            left++;
        else
            right--;
    }

    return maxWater;
}

// Main function to test the solution
int main() {
    vector<int> inputHeights = {1,8,6,2,5,4,8,3,7};
    cout << maxArea(inputHeights) << endl;  // Expected output: 49
    return 0;
}

