#include <iostream>
#include <vector>
#include <string>
using namespace std;

string longestCommonPrefix(vector<string>& strs) {
    // Return empty string if array is empty
    if (strs.empty()) {
        return "";
    }

    // Loop over the first string's characters
    for (int i = 0; i < strs[0].size(); i++) {
        char currentChar = strs[0][i];
        // Compare currentChar with the same index in each other string
        for (int j = 1; j < strs.size(); j++) {
            // If index exceeds string length or characters mismatch, return the prefix
            if (i >= strs[j].size() || strs[j][i] != currentChar) {
                return strs[0].substr(0, i);
            }
        }
    }
    return strs[0];
}

int main() {
    vector<string> strs = {"flower", "flow", "flight"};
    cout << longestCommonPrefix(strs) << endl;
    return 0;
}

