// C++ solution for 3Sum Closest
#include <vector>
#include <algorithm>
#include <cstdlib> // for abs
using namespace std;

class Solution {
public:
    int threeSumClosest(vector<int>& nums, int target) {
        // Sort the array to apply two pointers technique
        sort(nums.begin(), nums.end());
        // Initialize bestSum with the sum of the first three elements
        int bestSum = nums[0] + nums[1] + nums[2];

        // Iterate through the array to fix the first element
        for (int i = 0; i < nums.size() - 2; i++) {
            int left = i + 1;
            int right = nums.size() - 1;
            // While left pointer is less than right pointer
            while (left < right) {
                int currentSum = nums[i] + nums[left] + nums[right];
                // Update bestSum if currentSum is closer to target
                if (abs(target - currentSum) < abs(target - bestSum)) {
                    bestSum = currentSum;
                }
                // Move left pointer if currentSum is less than target
                if (currentSum < target) {
                    left++;
                } 
                // Move right pointer if currentSum is greater than target
                else if (currentSum > target) {
                    right--;
                } 
                // If exact match is found, return the target sum immediately
                else {
                    return currentSum;
                }
            }
        }
        // Return the closest sum found
        return bestSum;
    }
};

