// C++ solution for Letter Combinations of a Phone Number

#include <vector>
#include <string>
#include <unordered_map>

using namespace std;

class Solution {
public:
    vector<string> letterCombinations(string digits) {
        // Map digits to corresponding letters.
        unordered_map<char, string> digitToLetters = {
            {'2', "abc"}, {'3', "def"}, {'4', "ghi"},
            {'5', "jkl"}, {'6', "mno"}, {'7', "pqrs"},
            {'8', "tuv"}, {'9', "wxyz"}
        };

        vector<string> result;
        // Edge case: if digits are empty, return an empty vector.
        if (digits.empty()) return result;

        // Backtracking function using lambda.
        function<void(int, string)> backtrack = [&](int index, string currentCombination) {
            // If the current combination is complete, add it to the result.
            if (index == digits.size()) {
                result.push_back(currentCombination);
                return;
            }
            // Get letters for the current digit.
            string letters = digitToLetters[digits[index]];
            for (char letter : letters) {
                backtrack(index + 1, currentCombination + letter);
            }
        };

        // Start backtracking from index 0.
        backtrack(0, "");
        return result;
    }
};

