#include <iostream>
#include <stack>
#include <unordered_map>
#include <string>
using namespace std;

bool isValid(string s) {
    // Mapping from closing to opening brackets.
    unordered_map<char, char> parenMap = { {')', '('}, {'}', '{'}, {']', '['} };
    // Stack to store the opening brackets.
    stack<char> stk;
    // Iterate through each character in the string.
    for (char ch : s) {
        // If the character is a closing bracket.
        if (parenMap.find(ch) != parenMap.end()) {
            // If the stack is empty or the top does not match, return false.
            if (stk.empty() || stk.top() != parenMap[ch]) {
                return false;
            }
            // Pop the matched opening bracket.
            stk.pop();
        } else {
            // Push the opening bracket onto the stack.
            stk.push(ch);
        }
    }
    // Return true if no unmatched brackets remain.
    return stk.empty();
}

int main() {
    // Example usage:
    string s = "()[]{}";
    cout << (isValid(s) ? "true" : "false") << endl; // Expected output: true
    return 0;
}

