// Helper function for backtracking
void backtrack(string current, int openCount, int closeCount, int n, vector<string>& result) {
    // When current string length reaches 2*n, it's a valid combination
    if (current.length() == 2 * n) {
        result.push_back(current);
        return;
    }
    // Add an opening parenthesis if the count is less than n
    if (openCount < n)
        backtrack(current + "(", openCount + 1, closeCount, n, result);
    // Add a closing parenthesis if it would not make the string invalid
    if (closeCount < openCount)
        backtrack(current + ")", openCount, closeCount + 1, n, result);
}

vector<string> generateParenthesis(int n) {
    vector<string> result;
    backtrack("", 0, 0, n, result);
    return result;
}

int main() {
    int n = 3;
    vector<string> parentheses = generateParenthesis(n);
    // Print all valid combinations
    for (const auto& s : parentheses) {
        cout << s << endl;
    }
    return 0;
}

