class Solution {
public:
    // Custom comparator for the min-heap (priority queue)
    struct Compare {
        bool operator()(ListNode* a, ListNode* b) {
            return a->val > b->val; // Min-heap based on node value
        }
    };

    ListNode* mergeKLists(vector<ListNode*>& lists) {
        // Create a priority queue (min-heap).
        priority_queue<ListNode*, vector<ListNode*>, Compare> minHeap;

        // Initialize the heap with the head of each non-empty list.
        for (auto node : lists) {
            if (node) {
                minHeap.push(node);
            }
        }

        // Dummy node to simplify list construction.
        ListNode dummy(0);
        ListNode* current = &dummy;

        // Continue until heap is empty.
        while (!minHeap.empty()) {
            // Get the smallest node.
            ListNode* smallest = minHeap.top();
            minHeap.pop();
            // Append it to the merged list.
            current->next = smallest;
            current = current->next;
            // If there is a next node in the list, push it into the heap.
            if (smallest->next) {
                minHeap.push(smallest->next);
            }
        }

        return dummy.next;
    }
};

