class Solution {
public:
    ListNode* swapPairs(ListNode* head) {
        // Create a dummy node to ease pointer handling.
        ListNode dummy(0);
        dummy.next = head;
        ListNode* prev = &dummy; // Pointer to track the node before the current pair.

        // Loop through the list as long as there are at least two nodes for swapping.
        while (head && head->next) {
            // Identify the two nodes to swap.
            ListNode* first = head;
            ListNode* second = head->next;

            // Swap the nodes by reassigning pointers.
            prev->next = second;         // Link previous node to second node.
            first->next = second->next;    // Link first node to the node after second.
            second->next = first;         // Complete the swap.

            // Move pointers to the next pair.
            prev = first;
            head = first->next;
        }

        // Return the new head of the list from dummy node.
        return dummy.next;
    }
};

