class Solution {
public:
    ListNode* reverseKGroup(ListNode* head, int k) {
        // Create a dummy node to facilitate edge handling
        ListNode dummy(0);
        dummy.next = head;
        ListNode* groupPrev = &dummy;

        while (true) {
            // Get the kth node from groupPrev
            ListNode* kth = getKthNode(groupPrev, k);
            if (!kth) break;
            ListNode* groupNext = kth->next;

            // Reverse the nodes within the group
            ListNode* prev = kth->next;
            ListNode* curr = groupPrev->next;
            while (curr != groupNext) {
                ListNode* temp = curr->next; // Temporarily store the next node
                curr->next = prev;           // Reverse pointer
                prev = curr;                 // Move prev forward
                curr = temp;                 // Move current forward
            }

            // Reconnect the reversed group with the previous part of the list
            ListNode* temp = groupPrev->next; // temp holds the original head of the group, now tail after reversal
            groupPrev->next = kth;           // Connect previous part to new head of group
            groupPrev = temp;                // Move groupPrev to the tail of the group

        }
        return dummy.next;
    }

    // Helper function to retrieve the kth node starting from curr
    ListNode* getKthNode(ListNode* curr, int k) {
        while (curr && k > 0) {
            curr = curr->next;
            k--;
        }
        return curr;
    }
};

