class Solution {
public:
    void nextPermutation(vector<int>& nums) {
        int n = nums.size();
        int i = n - 2;
        // Find the first index from the right where the element is less than its next element
        while (i >= 0 && nums[i] >= nums[i + 1])
            i--;
        if (i >= 0) {
            int j = n - 1;
            // Find the first element from the right that is greater than nums[i]
            while (nums[j] <= nums[i])
                j--;
            swap(nums[i], nums[j]);  // Swap the two elements
        }
        // Reverse the subarray from i+1 to the end of the vector
        reverse(nums.begin() + i + 1, nums.end());
    }
};

