// C++ solution using a stack
#include <iostream>
#include <stack>
#include <string>
#include <algorithm>
using namespace std;

int longestValidParentheses(string s) {
    // Initialize a stack with base index -1
    stack<int> indices;
    indices.push(-1);
    int maxLength = 0;

    // Loop through the string by index
    for (int i = 0; i < s.size(); i++) {
        if (s[i] == '(') {
            // Push index for '(' onto the stack
            indices.push(i);
        } else {
            // Pop the last index for ')'
            indices.pop();
            if (indices.empty()) {
                // If stack is empty, push current index as new base
                indices.push(i);
            } else {
                // Calculate the current valid substring length
                maxLength = max(maxLength, i - indices.top());
            }
        }
    }

    return maxLength;
}

int main() {
    string s = ")()())";
    cout << longestValidParentheses(s) << endl;  // Output: 4
    return 0;
