#include <vector>
using namespace std;

class Solution {
public:
    // Helper function to find boundary index (leftmost or rightmost) for target.
    int findBoundary(const vector<int>& nums, int target, bool findLeft) {
        int left = 0, right = nums.size() - 1;
        int boundary = -1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (nums[mid] == target) {
                boundary = mid;
                if (findLeft) {
                    right = mid - 1; // continue searching on left side
                } else {
                    left = mid + 1;  // continue searching on right side
                }
            } else if (nums[mid] < target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return boundary;
    }

    vector<int> searchRange(vector<int>& nums, int target) {
        int leftIndex = findBoundary(nums, target, true);
        if (leftIndex == -1) return {-1, -1};
        int rightIndex = findBoundary(nums, target, false);
        return {leftIndex, rightIndex};
    }
};

