class Solution {
public:
    bool isValidSudoku(vector<vector<char>>& board) {
        // Vectors of unordered sets for rows, columns, and boxes
        vector<unordered_set<char>> rows(9), cols(9), boxes(9);

        // Iterate through the board
        for (int r = 0; r < 9; r++) {
            for (int c = 0; c < 9; c++) {
                char num = board[r][c];
                // Skip if cell is empty
                if (num == '.') continue;
                // Calculate box index
                int boxIndex = (r / 3) * 3 + (c / 3);
                // Check if the number is already seen in row, column or box
                if (rows[r].count(num) || cols[c].count(num) || boxes[boxIndex].count(num)) {
                    return false;
                }
                // Insert the number into the respective sets
                rows[r].insert(num);
                cols[c].insert(num);
                boxes[boxIndex].insert(num);
            }
        }
        return true;
    }
};

