#include <vector>
#include <string>
using namespace std;

class Solution {
public:
    // Check if placing 'ch' at (row, col) is valid.
    bool isValid(vector<vector<char>>& board, int row, int col, char ch) {
        for (int i = 0; i < 9; i++) {
            // Check the row
            if (board[row][i] == ch) return false;
            // Check the column
            if (board[i][col] == ch) return false;
            // Check the 3x3 sub-box
            int subRow = 3 * (row / 3) + i / 3;
            int subCol = 3 * (col / 3) + i % 3;
            if (board[subRow][subCol] == ch) return false;
        }
        return true;
    }

    // Backtracking function to solve the Sudoku puzzle.
    bool backtrack(vector<vector<char>>& board) {
        for (int row = 0; row < 9; row++) {
            for (int col = 0; col < 9; col++) {
                if (board[row][col] == '.') {
                    for (char ch = '1'; ch <= '9'; ch++) {
                        if (isValid(board, row, col, ch)) {
                            board[row][col] = ch;  // Place digit
                            if (backtrack(board))
                                return true;       // If recursion successful, puzzle is solved
                            board[row][col] = '.'; // Undo placement to backtrack
                        }
                    }
                    return false; // No valid digit found, need to backtrack
                }
            }
        }
        return true; // Puzzle solved
    }

    void solveSudoku(vector<vector<char>>& board) {
        backtrack(board);
    }
};

