// Include necessary libraries
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    // Main function to find all unique combinations
    vector<vector<int>> combinationSum(vector<int>& candidates, int target) {
        vector<vector<int>> result;
        vector<int> combination;
        // Sort candidates to allow efficient pruning
        sort(candidates.begin(), candidates.end());
        backtrack(candidates, target, 0, combination, result);
        return result;
    }

    // Backtracking helper function
    void backtrack(vector<int>& candidates, int remaining, int start, vector<int>& combination, vector<vector<int>>& result) {
        // Valid combination found if remaining becomes zero
        if (remaining == 0) {
            result.push_back(combination);
            return;
        }
        // Explore further candidates from the current starting index
        for (int i = start; i < candidates.size(); i++) {
            // If candidate exceeds the remaining sum, further numbers will also be too large
            if (candidates[i] > remaining)
                break;
            // Include candidate in the current combination path
            combination.push_back(candidates[i]);
            // Recurse with updated remaining; "i" is used to allow the same candidate again
            backtrack(candidates, remaining - candidates[i], i, combination, result);
            // Remove candidate and backtrack
            combination.pop_back();
        }
    }
};

