#include <vector>
using namespace std;

class Solution {
public:
    vector<vector<int>> permute(vector<int>& nums) {
        vector<vector<int>> result;
        vector<int> current;
        backtrack(nums, current, result);
        return result;
    }

    void backtrack(vector<int>& remaining, vector<int>& current, vector<vector<int>>& result) {
        // If no numbers left, current permutation is complete.
        if (remaining.empty()) {
            result.push_back(current);
            return;
        }
        // Iterate over the remaining numbers.
        for (int i = 0; i < remaining.size(); i++) {
            int chosen = remaining[i];
            current.push_back(chosen);
            // Create a new vector excluding the chosen number.
            vector<int> newRemaining = remaining;
            newRemaining.erase(newRemaining.begin() + i);
            backtrack(newRemaining, current, result);
            // Backtrack by removing the chosen number.
            current.pop_back();
        }
    }
};

