// C++ solution for grouping anagrams
#include <iostream>
#include <vector>
#include <string>
#include <unordered_map>
#include <algorithm>

using namespace std;

vector<vector<string>> groupAnagrams(vector<string>& strs) {
    // Create a hash map to store strings grouped by their sorted version
    unordered_map<string, vector<string>> anagrams;
    // Iterate over each string in the input vector
    for (string s : strs) {
        // Copy the string and sort it to create a key
        string key = s;
        sort(key.begin(), key.end());
        // Append the original string to the vector associated with the sorted key
        anagrams[key].push_back(s);
    }
    // Prepare the result vector of vectors
    vector<vector<string>> result;
    for (auto& pair : anagrams) {
        result.push_back(pair.second);
    }
    return result;
}

int main() {
    vector<string> strs = {"eat","tea","tan","ate","nat","bat"};
    vector<vector<string>> result = groupAnagrams(strs);

    // Output the grouped anagrams
    for (auto group : result) {
        for (string s : group) {
            cout << s << " ";
        }
        cout << endl;
    }
    return 0;
}

