// C++ implementation of pow(x, n) using exponentiation by squaring
#include <iostream>
using namespace std;

double myPow(double x, int n) {
    // If exponent is negative, flip x and convert n to positive
    long long exponent = n;  // using long long to handle edge cases with INT_MIN
    if (exponent < 0) {
        x = 1 / x;
        exponent = -exponent;
    }

    double result = 1.0;  // initialize result
    while (exponent > 0) {
        // If exponent is odd, multiply result by x
        if (exponent % 2 == 1)
            result *= x;
        x = x * x;           // square base
        exponent /= 2;       // reduce exponent by half
    }
    return result;
}

int main() {
    cout << myPow(2.0, 10) << endl;  // Output: 1024
    cout << myPow(2.1, 3) << endl;   // Output: 9.261
    cout << myPow(2.0, -2) << endl;  // Output: 0.25
    return 0;
}

