#include <iostream>
#include <vector>
#include <string>
#include <unordered_set>

using namespace std;

class Solution {
public:
    vector<vector<string>> solveNQueens(int n) {
        vector<vector<string>> results;
        vector<string> board(n, string(n, '.'));
        unordered_set<int> columns, diag1, diag2;
        backtrack(n, 0, board, columns, diag1, diag2, results);
        return results;
    }

    void backtrack(int n, int row, vector<string>& board, 
                   unordered_set<int>& columns, 
                   unordered_set<int>& diag1,
                   unordered_set<int>& diag2,
                   vector<vector<string>>& results) {
        if (row == n) {
            results.push_back(board);
            return;
        }
        for (int col = 0; col < n; col++) {
            // Check if the column or diagonals are occupied
            if (columns.count(col) || diag1.count(row - col) || diag2.count(row + col))
                continue;

            // Place queen and mark the positions
            board[row][col] = 'Q';
            columns.insert(col);
            diag1.insert(row - col);
            diag2.insert(row + col);

            // Recurse to place queen in next row
            backtrack(n, row + 1, board, columns, diag1, diag2, results);

            // Remove queen and unmark the positions (backtrack)
            board[row][col] = '.';
            columns.erase(col);
            diag1.erase(row - col);
            diag2.erase(row + col);
        }
    }
};

// Example usage:
int main() {
    Solution sol;
    int n = 4;
    vector<vector<string>> solutions = sol.solveNQueens(n);
    for (const auto &board : solutions) {
        for (const auto &row : board)
            cout << row << endl;
        cout << endl;
    }
    return 0;
}

