// C++ solution using Kadane's Algorithm
#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int maxSubArray(vector<int>& nums) {
    // Initialize currentSum and maxSum to the first element of the vector
    int currentSum = nums[0];
    int maxSum = nums[0];
    // Traverse the vector starting from the second element
    for (size_t i = 1; i < nums.size(); i++) {
        // Update currentSum to be either the current element or the sum with currentSum
        currentSum = max(nums[i], currentSum + nums[i]);
        // Update maxSum if currentSum is larger
        maxSum = max(maxSum, currentSum);
    }
    return maxSum;
}

int main() {
    vector<int> sample = {-2,1,-3,4,-1,2,1,-5,4};
    cout << maxSubArray(sample) << endl; // Output: 6
    return 0;
}

