// C++ implementation to determine if it is possible to jump to the last index in the array
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    bool canJump(vector<int>& nums) {
        // maxReach keeps track of the furthest index that can be reached.
        int maxReach = 0;
        // Iterate through each index in the array
        for (int i = 0; i < nums.size(); i++) {
            // If current index is greater than maxReach, it's unreachable.
            if (i > maxReach) {
                return false;
            }
            // Update maxReach with the maximum of current maxReach and index + jump at index i
            maxReach = max(maxReach, i + nums[i]);
            // If maxReach is greater or equal to the last index, return true
            if (maxReach >= nums.size() - 1) {
                return true;
            }
        }
        return true;
    }
};

