class Solution {
public:
    ListNode* rotateRight(ListNode* head, int k) {
        if (!head || !head->next || k == 0) { // Check if rotation is necessary
            return head;
        }

        // Compute the length of the list and locate the tail node
        int length = 1;
        ListNode* tail = head;
        while (tail->next) {
            tail = tail->next;
            length++;
        }

        // Calculate the effective number of rotations
        k = k % length;
        if (k == 0) {
            return head;
        }

        // Find the new tail: (length - k - 1) steps from the head
        int stepsToNewTail = length - k - 1;
        ListNode* newTail = head;
        for (int i = 0; i < stepsToNewTail; i++) {
            newTail = newTail->next;
        }

        // Set the new head and break the list
        ListNode* newHead = newTail->next;
        newTail->next = nullptr;

        // Connect the old tail to the original head
        tail->next = head;

        return newHead;
    }
};

