// C++ solution using Dynamic Programming

#include <iostream>
#include <vector>
using namespace std;

int uniquePaths(int m, int n) {
    // Create a 2D vector dp with dimensions m x n initialized with 1's
    vector<vector<int>> dp(m, vector<int>(n, 1));

    // Fill in the dp table from cell (1,1) onwards
    for (int i = 1; i < m; i++) {
        for (int j = 1; j < n; j++) {
            // dp[i][j] is sum of ways to come from top and left cell
            dp[i][j] = dp[i - 1][j] + dp[i][j - 1];
        }
    }
    // Return the result from the bottom-right corner of the grid
    return dp[m - 1][n - 1];
}

int main() {
    cout << uniquePaths(3, 7) << endl;
    return 0;
}

