// Binary search solution in C++ to find the integer square root
#include <iostream>
using namespace std;

class Solution {
public:
    int mySqrt(int x) {
        // Edge case for numbers less than 2
        if (x < 2) {
            return x;
        }

        int low = 0, high = x, ans = 0;
        // Binary search loop
        while (low <= high) {
            int mid = low + (high - low) / 2;
            // Check if mid squared equals x
            if (mid * mid == x) {
                return mid;
            }
            // If mid squared is less than x, update candidate and search right half
            else if (mid * mid < x) {
                ans = mid; // store mid as a candidate
                low = mid + 1;
            }
            // Otherwise, search left half
            else {
                high = mid - 1;
            }
        }
        return ans;
    }
};

int main() {
    Solution sol;
    // Example usage:
    cout << sol.mySqrt(4) << endl; // Output: 2
    cout << sol.mySqrt(8) << endl; // Output: 2
    return 0;
}

