// C++ solution to climb stairs problem
#include <iostream>
#include <vector>
using namespace std;

int climbStairs(int n) {
    // Base case: if there is only one step, return 1.
    if(n == 1) return 1;

    // Create a vector to store the ways to climb each step.
    vector<int> dp(n + 1, 0);
    dp[1] = 1; // One way to climb 1 step.
    dp[2] = 2; // Two ways to climb 2 steps.

    // Fill the dp vector using the recurrence relation.
    for (int i = 3; i <= n; i++) {
        dp[i] = dp[i - 1] + dp[i - 2];  // ways[i] = ways[i-1] + ways[i-2]
    }
    return dp[n];
}

int main() {
    // Example usage:
    cout << climbStairs(3) << endl;  // Output: 3
    return 0;
