// C++ solution to compute the Edit Distance
#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int minDistance(string word1, string word2) {
    int m = word1.size();
    int n = word2.size();

    // Create a dp table of size (m+1) x (n+1)
    vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));

    // Initialize base cases
    for (int i = 0; i <= m; i++) {
        dp[i][0] = i; // deletions required to form an empty string
    }
    for (int j = 0; j <= n; j++) {
        dp[0][j] = j; // insertions required to form word2
    }

    // Fill the dp table
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (word1[i - 1] == word2[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1]; // characters match, no new edit needed
            } else {
                dp[i][j] = 1 + min({ dp[i - 1][j],     // deletion
                                     dp[i][j - 1],     // insertion
                                     dp[i - 1][j - 1]  // replacement
                                   });
            }
        }
    }
    return dp[m][n];
}

int main() {
    string word1 = "horse", word2 = "ros";
    cout << minDistance(word1, word2);
    return 0;
}

