// Function to sort the colors using Dutch National Flag algorithm
#include <vector>
#include <iostream>
using namespace std;

void sortColors(vector<int>& nums) {
    // Initialize pointers for low, mid, and high
    int low = 0, mid = 0;
    int high = nums.size() - 1;

    // Iterate until mid pointer exceeds high pointer
    while (mid <= high) {
        if (nums[mid] == 0) {
            // Swap element at mid with element at low pointer
            swap(nums[low], nums[mid]);
            low++;
            mid++;
        } else if (nums[mid] == 1) {
            // Move mid pointer forward if element is 1
            mid++;
        } else { // nums[mid] == 2
            // Swap element at mid with element at high pointer
            swap(nums[mid], nums[high]);
            high--;
        }
    }
}

// Example usage:
int main() {
    vector<int> nums = {2,0,2,1,1,0};
    sortColors(nums);
    // Output the sorted array
    for (int num : nums)
        cout << num << " ";
    // Expected Output: 0 0 1 1 2 2
    return 0;
}

