// Include necessary libraries.
#include <iostream>
#include <vector>
using namespace std;

// Function to generate all subsets using backtracking.
void backtrack(vector<int>& nums, int start, vector<int>& curr, vector<vector<int>>& result) {
    // Append current subset to result.
    result.push_back(curr);
    // Loop through numbers starting from index 'start'
    for (int i = start; i < nums.size(); i++) {
        // Include nums[i] into the current subset.
        curr.push_back(nums[i]);
        // Recurse with next starting index.
        backtrack(nums, i + 1, curr, result);
        // Backtrack: remove last element.
        curr.pop_back();
    }
}

vector<vector<int>> subsets(vector<int>& nums) {
    vector<vector<int>> result;
    vector<int> curr;
    // Start backtracking from index 0.
    backtrack(nums, 0, curr, result);
    return result;
}

int main() {
    vector<int> nums = {1, 2, 3};
    vector<vector<int>> result = subsets(nums);
    // Output the result.
    for (auto subset : result) {
        cout << "[";
        for (int num : subset) {
            cout << num << " ";
        }
        cout << "]" << endl;
    }
    return 0;
}

