// C++ solution

#include <iostream>
#include <vector>
#include <stack>
#include <algorithm>
using namespace std;

class Solution {
public:
    int largestRectangleArea(vector<int>& heights) {
        // Append a sentinel value (0) to flush out the stack at the end
        heights.push_back(0);
        stack<int> indices;  // Stack to store indices of bars
        int maxArea = 0;

        // Iterate through each bar in the histogram
        for (int i = 0; i < heights.size(); i++) {
            // While the current bar is lower than the bar at the top of the stack
            while (!indices.empty() && heights[indices.top()] > heights[i]) {
                int height = heights[indices.top()];  // Height of the popped bar
                indices.pop();

                // If stack is empty, width is 'i'; otherwise, it is the difference between current index and new top index - 1
                int width = indices.empty() ? i : i - indices.top() - 1;
                maxArea = max(maxArea, height * width);
            }
            indices.push(i);
        }

        return maxArea;
    }
};

int main() {
    Solution sol;
    vector<int> histogram = {2, 1, 5, 6, 2, 3};
    cout << sol.largestRectangleArea(histogram) << endl;
    return 0;
}

