#include <vector>
using namespace std;

void merge(vector<int>& nums1, int m, vector<int>& nums2, int n) {
    // Initialize pointers for nums1, nums2 and the tail index of nums1
    int p1 = m - 1, p2 = n - 1, tail = m + n - 1;

    // Merge arrays starting from the end
    while (p1 >= 0 && p2 >= 0) {
        if (nums1[p1] > nums2[p2]) {
            nums1[tail] = nums1[p1];
            p1--;  // Move pointer in nums1
        } else {
            nums1[tail] = nums2[p2];
            p2--;  // Move pointer in nums2
        }
        tail--;  // Move the tail pointer
    }

    // Copy any remaining elements from nums2 into nums1
    while (p2 >= 0) {
        nums1[tail] = nums2[p2];
        p2--;
        tail--;
    }
}

