#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    vector<vector<int>> subsetsWithDup(vector<int>& nums) {
        vector<vector<int>> result; // Final list of subsets
        vector<int> subset;         // Current subset being built
        // Sort numbers to simplify duplicate handling
        sort(nums.begin(), nums.end());
        backtrack(nums, 0, subset, result);
        return result;
    }

    void backtrack(vector<int>& nums, int start, vector<int>& subset, vector<vector<int>>& result) {
        // Record the current subset
        result.push_back(subset);
        // Explore further elements
        for (int i = start; i < nums.size(); i++) {
            // Skip duplicates if this duplicate hasn't been processed in this recursion branch
            if (i > start && nums[i] == nums[i - 1])
                continue;
            // Include the current element
            subset.push_back(nums[i]);
            // Recurse for the next elements
            backtrack(nums, i + 1, subset, result);
            // Backtrack by removing the last included element
            subset.pop_back();
        }
    }
};

// Example usage:
// int main() {
