// C++ solution using dynamic programming
#include <iostream>
#include <vector>
#include <string>
using namespace std;

int numDecodings(string s) {
    // If the string is empty or starts with '0', return 0 decodings.
    if(s.empty() || s[0] == '0') return 0;

    int n = s.size();
    vector<int> dp(n + 1, 0);
    dp[0] = 1; // Base case: empty string

    for(int i = 1; i <= n; i++){
        // Single digit decoding: if current digit is not '0'
        if(s[i - 1] != '0'){
            dp[i] += dp[i - 1];
        }
        // Two-digit decoding: check if i>=2 and the two-digit number is valid
        if(i >= 2 && s[i - 2] != '0'){
            int twoDigit = (s[i - 2] - '0') * 10 + (s[i - 1] - '0');
            if(twoDigit >= 10 && twoDigit <= 26){
                dp[i] += dp[i - 2];
            }
        }
    }
    return dp[n];
}

int main() {
    // Example usage
    string s = "12";
    cout << numDecodings(s); // Expected output: 2
    return 0;
}

