class Solution {
public:
    TreeNode* buildTree(vector<int>& preorder, vector<int>& inorder) {
        // Map to store the index of each value in inorder traversal
        unordered_map<int, int> inorderIndex;
        for (int i = 0; i < inorder.size(); i++) {
            inorderIndex[inorder[i]] = i;
        }
        // Start recursive construction of tree
        return helper(preorder, 0, inorder.size() - 1, 0, inorderIndex);
    }

private:
    // Helper function to build tree recursively
    TreeNode* helper(vector<int>& preorder, int in_left, int in_right, int pre_start, unordered_map<int, int>& inorderIndex) {
        // Base case: no elements to construct subtree
        if (in_left > in_right) return nullptr;

        // The first element in preorder is the current root
        int rootVal = preorder[pre_start];
        TreeNode* root = new TreeNode(rootVal);

        // Get index of the current root in inorder traversal
        int in_index = inorderIndex[rootVal];
        // Number of nodes in left subtree
        int leftSubtreeSize = in_index - in_left;

        // Build left subtree recursively
        root->left = helper(preorder, in_left, in_index - 1, pre_start + 1, inorderIndex);
        // Build right subtree recursively
        root->right = helper(preorder, in_index + 1, in_right, pre_start + leftSubtreeSize + 1, inorderIndex);

        return root;
    }
};

