class Solution {
public:
    // Main function to check if the tree is balanced.
    bool isBalanced(TreeNode* root) {
        // If helper returns -1, tree is not balanced.
        return dfsHeight(root) != -1;
    }

    // Helper function returns height if balanced, -1 otherwise.
    int dfsHeight(TreeNode* node) {
        if (node == nullptr)
            return 0; // An empty tree is balanced with height 0.

        // Recursively check height of left subtree.
        int leftHeight = dfsHeight(node->left);
        if (leftHeight == -1)
            return -1;  // Early exit if left subtree is unbalanced.

        // Recursively check height of right subtree.
        int rightHeight = dfsHeight(node->right);
        if (rightHeight == -1)
            return -1;  // Early exit if right subtree is unbalanced.

        // If the difference exceeds 1, the tree is unbalanced.
        if (abs(leftHeight - rightHeight) > 1)
            return -1;

        // Return the height of the current subtree.
        return max(leftHeight, rightHeight) + 1;
    }
};

