class Solution {
public:
    vector<vector<int>> pathSum(TreeNode* root, int targetSum) {
        vector<vector<int>> result; // To store all valid paths
        vector<int> currentPath;
        dfs(root, targetSum, currentPath, result);
        return result;
    }

    void dfs(TreeNode* node, int remainingSum, vector<int>& currentPath, vector<vector<int>>& result) {
        if (!node) return; // Base case

        // Include the current node's value in currentPath
        currentPath.push_back(node->val);

        // Check if it's a leaf node and if we have achieved target sum
        if (!node->left && !node->right && node->val == remainingSum) {
            result.push_back(currentPath); // Append a copy of currentPath
        } else {
            // Recurse on left and right subtrees
            dfs(node->left, remainingSum - node->val, currentPath, result);
            dfs(node->right, remainingSum - node->val, currentPath, result);
        }

        // Backtracking step: remove the last element before returning
        currentPath.pop_back();
    }
};

