// C++ solution for Distinct Subsequences
#include <iostream>
#include <vector>
#include <string>
using namespace std;

int numDistinct(string s, string t) {
    int m = s.size(), n = t.size();
    // Initialize dp table with dimensions (m+1) x (n+1)
    vector<vector<unsigned long long>> dp(m + 1, vector<unsigned long long>(n + 1, 0));

    // Base case: empty t can be formed from any prefix of s
    for (int i = 0; i <= m; i++) {
        dp[i][0] = 1;
    }

    // Fill the dp table
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (s[i - 1] == t[j - 1])
                dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j];
            else
                dp[i][j] = dp[i - 1][j];
        }
    }

    return dp[m][n];
}

int main() {
    // Example usage:
    cout << numDistinct("rabbbit", "rabbit") << endl; // Output: 3
    return 0;
}

