// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    int globalMax = numeric_limits<int>::min();

    int maxPathSum(TreeNode* root) {
        dfs(root);
        return globalMax;
    }

    int dfs(TreeNode* node) {
        if (!node) return 0;

        // Compute maximum gain from left and right, ignoring negative gains
        int leftGain = max(dfs(node->left), 0);
        int rightGain = max(dfs(node->right), 0);

        // Maximum path sum using the current node as the highest node
        int currentMax = node->val + leftGain + rightGain;
        globalMax = max(globalMax, currentMax);

        // Return the maximum gain to the parent node (only one branch could be selected)
        return node->val + max(leftGain, rightGain);
    }
};

