// C++ solution for Word Ladder II

#include <vector>
#include <string>
#include <unordered_set>
#include <unordered_map>
#include <queue>
#include <algorithm>
using namespace std;

class Solution {
public:
    vector<vector<string>> findLadders(string beginWord, string endWord, vector<string>& wordList) {
        // Convert wordList to unordered_set for fast lookup.
        unordered_set<string> wordSet(wordList.begin(), wordList.end());
        vector<vector<string>> result;
        if (wordSet.find(endWord) == wordSet.end()) return result;

        // Map to store each word's parents in the BFS tree.
        unordered_map<string, vector<string>> parents;
        // Initialize BFS.
        unordered_set<string> level{beginWord};
        bool found = false;

        while (!level.empty() && !found) {
            unordered_set<string> nextLevel;
            // Remove the words in current level from wordSet to prevent re-processing.
            for (const auto &word : level)
                wordSet.erase(word);

            for (const auto &word : level) {
                string curr = word;
                for (size_t i = 0; i < curr.size(); ++i) {
                    char original = curr[i];
                    for (char c = 'a'; c <= 'z'; c++) {
                        curr[i] = c;
                        if (wordSet.find(curr) != wordSet.end()) {
                            // Record 'word' as a parent of 'curr'
                            parents[curr].push_back(word);
                            nextLevel.insert(curr);
                            if (curr == endWord) {
                                found = true;
                            }
                        }
                    }
                    curr[i] = original;
                }
            }
            level = nextLevel;
        }

        // Backtracking to build all sequences from endWord to beginWord.
        vector<string> path;
        backtrack(endWord, beginWord, parents, path, result);
        return result;
    }

private:
    void backtrack(const string &word, const string &beginWord,
                   unordered_map<string, vector<string>> &parents, 
                   vector<string> &path, vector<vector<string>> &result) {
        // Add current word to the current path.
        path.push_back(word);
        if (word == beginWord) {
            vector<string> validPath = path;
            reverse(validPath.begin(), validPath.end());
            result.push_back(validPath);
        } else {
            // Recursively backtrack using the parent's mapping.
            for (const auto &parent : parents[word]) {
                backtrack(parent, beginWord, parents, path, result);
            }
        }
        // Remove current word from the path before backtracking.
        path.pop_back();
    }
};

