// C++ solution using BFS

#include <iostream>
#include <vector>
#include <queue>
#include <unordered_set>
#include <unordered_map>
#include <string>
using namespace std;

int ladderLength(string beginWord, string endWord, vector<string>& wordList) {
    unordered_set<string> wordSet(wordList.begin(), wordList.end());
    if (wordSet.find(endWord) == wordSet.end()) return 0;

    int L = beginWord.size();
    unordered_map<string, vector<string>> allComboDict;

    // Preprocessing: build dictionary of intermediate states
    for (const string& word : wordSet) {
        for (int i = 0; i < L; i++) {
            string key = word.substr(0, i) + '*' + word.substr(i + 1);
            allComboDict[key].push_back(word);
        }
    }

    // BFS initialization
    queue<pair<string, int>> bfsQueue;
    bfsQueue.push(make_pair(beginWord, 1));
    unordered_set<string> visited;
    visited.insert(beginWord);

    while (!bfsQueue.empty()) {
        auto current = bfsQueue.front();
        bfsQueue.pop();
        string currentWord = current.first;
        int level = current.second;

        for (int i = 0; i < L; i++) {
            string intermediate = currentWord.substr(0, i) + '*' + currentWord.substr(i + 1);
            for (const string& word : allComboDict[intermediate]) {
                if (word == endWord) return level + 1;
                if (visited.find(word) == visited.end()) {
                    visited.insert(word);
                    bfsQueue.push(make_pair(word, level + 1));
                }
            }
            // Optional: clear the intermediate words list to optimize
            allComboDict[intermediate].clear();
        }
    }
    return 0;
}

