class Solution {
public:
    void solve(vector<vector<char>>& board) {
        if(board.empty() || board[0].empty())
            return;
        int rows = board.size(), cols = board[0].size();

        // Lambda function for DFS to mark safe cells
        auto dfs = [&](auto& dfs, int r, int c) -> void {
            if(r < 0 || c < 0 || r >= rows || c >= cols || board[r][c] != 'O')
                return;
            board[r][c] = '*';  // Mark current cell as safe
            dfs(dfs, r + 1, c);
            dfs(dfs, r - 1, c);
            dfs(dfs, r, c + 1);
            dfs(dfs, r, c - 1);
        };

        // Process all border cells
        for(int i = 0; i < rows; i++){
            if(board[i][0] == 'O')
                dfs(dfs, i, 0);
            if(board[i][cols - 1] == 'O')
                dfs(dfs, i, cols - 1);
        }
        for(int j = 0; j < cols; j++){
            if(board[0][j] == 'O')
                dfs(dfs, 0, j);
            if(board[rows - 1][j] == 'O')
                dfs(dfs, rows - 1, j);
        }

        // Convert unmarked 'O's to 'X' and revert marked safe cells
        for(int i = 0; i < rows; i++){
            for(int j = 0; j < cols; j++){
                if(board[i][j] == 'O')
                    board[i][j] = 'X';
                else if(board[i][j] == '*')
                    board[i][j] = 'O';
            }
        }
    }
};

