#include <vector>
#include <string>
#include <algorithm>
using namespace std;

class Solution {
public:
    int minCut(string s) {
        int n = s.size();
        // Table to check if substring s[i...j] is a palindrome.
        vector<vector<bool>> isPal(n, vector<bool>(n, false));
        // dp[i] represents the minimum cuts needed for substring s[0...i]
        vector<int> dp(n, 0);

        for (int i = 0; i < n; i++) {
            int minCut = i; // Maximum cuts (cut before every character)
            for (int j = 0; j <= i; j++) {
                // Check if s[j...i] is a palindrome:
                if (s[j] == s[i] && (i - j < 2 || isPal[j+1][i-1])) {
                    isPal[j][i] = true;  // Mark as palindrome.
                    // If this palindrome starts at index 0, no cut is needed.
                    minCut = (j == 0) ? 0 : min(minCut, dp[j-1] + 1);
                }
            }
            dp[i] = minCut; // Record minimum cuts for substring s[0...i]
        }
        return dp[n-1];
    }
};

