#include <iostream>
#include <vector>
#include <string>
#include <unordered_set>
using namespace std;

bool wordBreak(string s, vector<string>& wordDict) {
    // Convert wordDict into an unordered_set for O(1) look-ups.
    unordered_set<string> wordSet(wordDict.begin(), wordDict.end());

    int n = s.size();
    // dp[i] is true if s[0:i] can be segmented into dictionary words.
    vector<bool> dp(n + 1, false);

    // Base case: empty string
    dp[0] = true;

    // Traverse through each index of the string.
    for (int i = 1; i <= n; i++) {
        // Check every possible partition point j
        for (int j = 0; j < i; j++) {
            // If s[0:j] can be segmented and s[j:i] is in the dictionary
            if (dp[j] && wordSet.count(s.substr(j, i - j))) {
                dp[i] = true;
                break;  // Early exit if a valid segmentation is found
            }
        }
    }
    return dp[n];
}

int main() {
    string s = "leetcode";
    vector<string> wordDict = {"leet", "code"};

    cout << (wordBreak(s, wordDict) ? "true" : "false") << endl;  // Output: true
    return 0;
}

