    Node* prev;
    Node* next;
    Node(int _key, int _value): key(_key), value(_value), prev(nullptr), next(nullptr) {}
};

class LRUCache {
private:
    int capacity;
    unordered_map<int, Node*> cache; // hash map to store key-node pairs
    Node *head, *tail; // dummy head and tail nodes

    // Remove a node from the doubly linked list
    void remove(Node* node) {
        Node* prev_node = node->prev;
        Node* next_node = node->next;
        prev_node->next = next_node;
        next_node->prev = prev_node;
    }

    // Insert a node right after the dummy head
    void add(Node* node) {
        node->next = head->next;
        node->prev = head;
        head->next->prev = node;
        head->next = node;
    }

public:
    // Initialize the LRU cache with positive capacity.
    LRUCache(int cap): capacity(cap) {
        head = new Node(0, 0);
        tail = new Node(0, 0);
        head->next = tail;
        tail->prev = head;
    }

    // Return the value of the key if it exists, otherwise -1.
    int get(int key) {
        if (cache.find(key) != cache.end()) {
            Node* node = cache[key];
            // Move the accessed node to the head as it becomes most recently used.
            remove(node);
            add(node);
            return node->value;
        }
        return -1;
    }

    // Update the value of the key if it exists. Otherwise, add the key/value pair.
    // If capacity is exceeded, evict the least recently used element.
    void put(int key, int value) {
        if (cache.find(key) != cache.end()) {
            // Remove the old node.
            remove(cache[key]);
            delete cache[key];
            cache.erase(key);
        }
        Node* newNode = new Node(key, value);
        add(newNode);
        cache[key] = newNode;

        if (cache.size() > capacity) {
            // Remove least recently used node
            Node* lru = tail->prev;
            remove(lru);
            cache.erase(lru->key);
            delete lru;
        }
    }
};

