#include <vector>
#include <string>
#include <stack>
#include <cstdlib>
using namespace std;

int evalRPN(vector<string>& tokens) {
    // Use stack to store numbers
    stack<int> st;
    // Iterate through each token in the vector
    for (const string &token : tokens) {
        // If token is an operator
        if (token == "+" || token == "-" || token == "*" || token == "/") {
            // Pop two numbers from the stack (order matters)
            int b = st.top();
            st.pop();
            int a = st.top();
            st.pop();
            int result;
            // Calculate result based on the operator
            if (token == "+") {
                result = a + b;
            } else if (token == "-") {
                result = a - b;
            } else if (token == "*") {
                result = a * b;
            } else { // token == "/"
                // Integer division truncates toward zero in C++
                result = a / b;
            }
            // Push the result back onto the stack
            st.push(result);
        } else {
            // Convert string token to integer and push onto the stack
            st.push(atoi(token.c_str()));
        }
    }
    // The result is the top of the stack
    return st.top();
}

