// Function to find the minimum element in a rotated sorted array
#include <vector>
using namespace std;

int findMin(vector<int>& nums) {
    int left = 0, right = nums.size() - 1;
    // Binary search loop until left equals right
    while (left < right) {
        int mid = left + (right - left) / 2; // Calculate middle index to avoid overflow
        // If middle element is greater than the rightmost element,
        // then the minimum is in the right half.
        if (nums[mid] > nums[right]) {
            left = mid + 1;
        } else {
            // Otherwise, the minimum is in the left half (including mid)
            right = mid;
        }
    }
    // At loop termination, left equals right and points to the minimum element
    return nums[left];
}

