// C++ implementation of MinStack with detailed comments

#include <stack>
using namespace std;

class MinStack {
private:
    // Main stack to store all integers
    stack<int> stackData;
    // Auxiliary stack to store minimum values
    stack<int> minStack;

public:
    // Constructor initializes the stack objects
    MinStack() { }

    // Pushes the element val onto the stack
    void push(int val) {
        stackData.push(val);
        // If minStack is empty or val is less than or equal to current minimum, push it onto minStack
        if (minStack.empty() || val <= minStack.top()) {
            minStack.push(val);
        }
    }

    // Removes the element on the top of the stack
    void pop() {
        int poppedValue = stackData.top();
        stackData.pop();
        // If the popped value equals the current minimum, pop it from minStack as well
        if (poppedValue == minStack.top()) {
            minStack.pop();
        }
    }

    // Gets the top element of the stack
    int top() {
        return stackData.top();
    }

    // Retrieves the minimum element in the stack
    int getMin() {
        return minStack.top();
    }
};

