// C++ solution for Longest Substring with At Most Two Distinct Characters
class Solution {
public:
    int lengthOfLongestSubstringTwoDistinct(string s) {
        int left = 0, maxLength = 0;
        unordered_map<char, int> charCount; // Hash table to count characters in the window

        for (int right = 0; right < s.size(); right++) {
            charCount[s[right]]++;  // Increase count for the character at the right pointer

            // While there are more than 2 distinct characters, shrink the window from the left
            while (charCount.size() > 2) {
                char leftChar = s[left];
                charCount[leftChar]--;
                if (charCount[leftChar] == 0) {
                    charCount.erase(leftChar);
                }
                left++;  // Move left pointer forward
            }

            // Update maximum window size if current window is larger
            maxLength = max(maxLength, right - left + 1);
        }
        return maxLength;
    }
};

