// C++ solution for Two Sum II - Input Array Is Sorted
#include <vector>
using namespace std;

class Solution {
public:
    vector<int> twoSum(vector<int>& numbers, int target) {
        // Initialize two pointers: left starts at 0, right starts at end of array
        int left = 0;
        int right = numbers.size() - 1;

        // Loop until the two pointers meet
        while (left < right) {
            int currentSum = numbers[left] + numbers[right];
            // Check if the current sum equals the target
            if (currentSum == target) {
                // Return 1-indexed positions as the result
                return {left + 1, right + 1};
            }
            // If sum is less than target, move left pointer to the right to increase sum
            else if (currentSum < target) {
                left++;
            }
            // If sum is greater than target, move right pointer to the left to decrease sum
            else {
                right--;
            }
        }
        // By problem guarantee, a solution always exists so we do not reach here.
        return {};
    }
};

