// C++ implementation of the Boyer-Moore Voting Algorithm

#include <vector>
using namespace std;

class Solution {
public:
    int majorityElement(vector<int>& nums) {
        // Candidate for the majority element
        int candidate = 0;
        // Counter for the candidate occurrences
        int count = 0;

        // Iterate through each number in the vector
        for (int num : nums) {
            // If counter drops to 0, set candidate to current number
            if (count == 0) {
                candidate = num;
            }
            // Increment counter if current number equals candidate; otherwise, decrement
            count += (num == candidate) ? 1 : -1;
        }
        // Candidate is guaranteed to be the majority element
        return candidate;
    }
};

