/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
 * };
 */
class BSTIterator {
private:
    // Stack to store the nodes during in-order traversal
    stack<TreeNode*> nodeStack;

    // Helper function to push all left children of a node onto the stack
    void pushLeftBranch(TreeNode* node) {
        while (node != nullptr) {
            nodeStack.push(node);
            node = node->left;
        }
    }
public:
    BSTIterator(TreeNode* root) {
        // Initialize the stack with the left branch of the root
        pushLeftBranch(root);
    }

    int next() {
        // Retrieve the top element from the stack, which is the next smallest
        TreeNode* node = nodeStack.top();
        nodeStack.pop();
        // If there is a right subtree, push its left branch
        if (node->right) {
            pushLeftBranch(node->right);
        }
        return node->val;
    }

    bool hasNext() {
        // There is a next element if the stack is not empty
        return !nodeStack.empty();
    }
};

