// Function to reverse the elements in a vector between indices left and right.
void reverseRange(vector<char>& s, int left, int right) {
    while (left < right) {
        swap(s[left], s[right]);
        ++left;
        --right;
    }
}

void reverseWords(vector<char>& s) {
    // Step 1: Reverse the entire character vector.
    reverseRange(s, 0, s.size() - 1);

    int n = s.size();
    int start = 0;
    // Step 2: Reverse each word individually.
    for (int i = 0; i <= n; i++) {
        if (i == n || s[i] == ' ') {
            reverseRange(s, start, i - 1);
            start = i + 1;
        }
    }
}

