class Solution {
public:
    int rob(vector<int>& nums) {
        // Initialize variables to track maximum money robbed so far
        int prev1 = 0, prev2 = 0;

        // Process each house's money
        for (int money : nums) {
            // Compute the maximum money if we choose to rob the current house or skip it
            int current = max(prev1, prev2 + money);
            // Update previous values for the next iteration
            prev2 = prev1;
            prev1 = current;
        }

        // Return the maximum money robbed
        return prev1;
    }
};

