// C++ solution using BFS
#include <vector>
#include <queue>
using namespace std;

// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    vector<int> rightSideView(TreeNode* root) {
        vector<int> rightView;
        if (!root) return rightView; // Return empty vector if tree is empty

        queue<TreeNode*> nodeQueue;
        nodeQueue.push(root);

        while (!nodeQueue.empty()) {
            int levelSize = nodeQueue.size(); // Number of nodes at current level
            for (int i = 0; i < levelSize; i++) {
                TreeNode* node = nodeQueue.front();
                nodeQueue.pop();
                // if it's the last node in the current level, add its value
                if (i == levelSize - 1) {
                    rightView.push_back(node->val);
                }
                // add left child if exists
                if (node->left) {
                    nodeQueue.push(node->left);
                }
                // add right child if exists
                if (node->right) {
                    nodeQueue.push(node->right);
                }
            }
        }

        return rightView;
    }
};

