class Solution {
public:
    // Function to count the number of islands in the grid
    int numIslands(vector<vector<string>>& grid) {
        if (grid.empty() || grid[0].empty()) return 0;
        int rows = grid.size();
        int cols = grid[0].size();
        int islands = 0;

        // Traverse each cell in the grid
        for (int r = 0; r < rows; ++r) {
            for (int c = 0; c < cols; ++c) {
                if (grid[r][c] == "1") {
                    islands++;
                    dfs(grid, r, c, rows, cols);
                }
            }
        }
        return islands;
    }

    // DFS helper function to mark an island as visited
    void dfs(vector<vector<string>>& grid, int r, int c, int rows, int cols) {
        // Check boundaries and if the cell is water
        if (r < 0 || r >= rows || c < 0 || c >= cols || grid[r][c] == "0")
            return;
        // Mark the current cell as visited by setting to "0"
        grid[r][c] = "0";
        // Recursively visit all adjacent cells
        dfs(grid, r + 1, c, rows, cols);
        dfs(grid, r - 1, c, rows, cols);
        dfs(grid, r, c + 1, rows, cols);
        dfs(grid, r, c - 1, rows, cols);
    }
};

