#include <iostream>
using namespace std;

struct ListNode {
    int val;              // Node value
    ListNode* next;       // Pointer to the next node
    ListNode(int x) : val(x), next(nullptr) {}
};

// Iterative approach to reverse the linked list.
ListNode* reverseList(ListNode* head) {
    ListNode* prev = nullptr;       // Previous pointer initialized to nullptr
    ListNode* current = head;         // Start from the head of the list
    while (current != nullptr) {
        ListNode* next_node = current->next;  // Save next node
        current->next = prev;         // Reverse the pointer of current node
        prev = current;               // Move previous pointer forward
        current = next_node;          // Proceed to next node
    }
    return prev;  // The new head of the reversed list
}

// Recursive approach to reverse the linked list.
ListNode* reverseListRecursive(ListNode* head) {
    // Base case: if the list is empty or contains only one node, return head.
    if (head == nullptr || head->next == nullptr)
        return head;
    ListNode* newHead = reverseListRecursive(head->next); // Recursively reverse the rest of the list
    head->next->next = head;   // Reverse the pointer for the current node
    head->next = nullptr;      // Set current node's next pointer to nullptr
    return newHead;            // Return the new head of the reversed list
}

