        int m = board.size(), n = board[0].size();

        // DFS lambda function.
        function<void(int, int, TrieNode*)> dfs = [&](int i, int j, TrieNode* node) {
            char c = board[i][j];
            if (!node->children.count(c)) return;
            TrieNode* nextNode = node->children[c];
            if (!nextNode->word.empty()) {
                result.push_back(nextNode->word);
                nextNode->word = ""; // Avoid duplicates.
            }
            board[i][j] = '#'; // Mark cell as visited.
            int dirs[4][2] = {{0,1}, {1,0}, {0,-1}, {-1,0}};
            for (auto& d : dirs) {
                int ni = i + d[0], nj = j + d[1];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n && board[ni][nj] != '#')
                    dfs(ni, nj, nextNode);
            }
            board[i][j] = c; // Restore cell character.
        };

        // Start DFS from every cell in the board.
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                dfs(i, j, root);
            }
        }
        return result;
    }
};

