// Function to determine if there are any duplicates in the vector.
bool containsDuplicate(const vector<int>& nums) {
    // Create an unordered_set to track seen numbers.
    unordered_set<int> seen;
    // Iterate over each number in the vector.
    for (int num : nums) {
        // If number is found in the set, a duplicate exists.
        if (seen.find(num) != seen.end()) {
            return true;
        }
        // Insert the number into the set.
        seen.insert(num);
    }
    // No duplicates found, return false.
    return false;
}

