// Include necessary libraries
#include <vector>
#include <algorithm>
#include <queue>
using namespace std;

class Solution {
public:
    vector<vector<int>> getSkyline(vector<vector<int>>& buildings) {
        // Each event: x-coordinate, height, end. For start events, height is negative.
        vector<vector<int>> events;
        for (auto& b : buildings) {
            // Push start event: negative height to ensure it sorts before end event at same x
            events.push_back({b[0], -b[2], b[1]});
            // Push end event: height zero.
            events.push_back({b[1], 0, 0});
        }

        // Sort events by x, then by height.
        sort(events.begin(), events.end(), [](const vector<int>& a, const vector<int>& b) {
            if (a[0] == b[0])
                return a[1] < b[1];
            return a[0] < b[0];
        });

        // Result vector
        vector<vector<int>> result;
        // Priority queue (max heap) storing pairs of (height, end)
        priority_queue<pair<int, int>> live;
        // Initialize with a dummy building with height 0 lasting infinitely.
        live.push({0, 2147483647});

        for (auto& e: events) {
            int x = e[0];
            int h = e[1];
            int r = e[2];

            // Remove all the buildings that have ended.
            while (!live.empty() && live.top().second <= x)
                live.pop();

            // If it's a start event, add building to the heap.
            if (h < 0)
                live.push({-h, r});

            int currHeight = live.top().first;
            // If result is empty or current height changes, add new key point.
            if (result.empty() || result.back()[1] != currHeight)
                result.push_back({x, currHeight});
        }

        return result;
    }
};

