// C++ solution for the Basic Calculator problem

#include <iostream>
#include <stack>
#include <string>
using namespace std;

int calculate(string s) {
    stack<int> stk;
    int result = 0, number = 0;
    int sign = 1; // 1 means positive, -1 means negative

    for (int i = 0; i < s.size(); i++) {
        char ch = s[i];
        if (isdigit(ch)) {
            // Build the current number
            number = number * 10 + (ch - '0');
        } else if (ch == '+' || ch == '-') {
            // Add current number to result with its sign
            result += sign * number;
            number = 0;
            // Update sign based on the operator
            sign = (ch == '+') ? 1 : -1;
        } else if (ch == '(') {
            // Push the current result and sign onto the stack for later
            stk.push(result);
            stk.push(sign);
            // Reset the result and sign for the new sub-expression
            result = 0;
            sign = 1;
        } else if (ch == ')') {
            // First complete the current number within the parenthesis
            result += sign * number;
            number = 0;
            // Pop the sign and then the previous result
            int prevSign = stk.top(); stk.pop();
            int prevResult = stk.top(); stk.pop();
            result = prevResult + prevSign * result;
        }
        // Skip spaces automatically
    }
    // Add any remaining number
    result += sign * number;
    return result;
}

int main() {
    cout << calculate("1 + 1") << endl;  // Expected output: 2
    cout << calculate(" 2-1 + 2 ") << endl;  // Expected output: 3
    cout << calculate("(1+(4+5+2)-3)+(6+8)") << endl;  // Expected output: 23
    return 0;
}

