// C++ solution for Basic Calculator II

#include <iostream>
#include <string>
#include <stack>
#include <cctype>
using namespace std;

int calculate(string s) {
    stack<int> st;
    int currentNumber = 0;
    char previousOperator = '+';

    for (int i = 0; i < s.size(); i++) {
        char currentChar = s[i];

        // Build the current number digit by digit.
        if (isdigit(currentChar)) {
            currentNumber = currentNumber * 10 + (currentChar - '0');
        }
        // If the character is an operator or we are at the end, process the number.
        if ((!isdigit(currentChar) && !isspace(currentChar)) || i == s.size() - 1) {
            if (previousOperator == '+') {
                st.push(currentNumber);
            } else if (previousOperator == '-') {
                st.push(-currentNumber);
            } else if (previousOperator == '*') {
                int lastNumber = st.top();
                st.pop();
                st.push(lastNumber * currentNumber);
            } else if (previousOperator == '/') {
                int lastNumber = st.top();
                st.pop();
                // C++ division truncates toward zero.
                st.push(lastNumber / currentNumber);
            }
            previousOperator = currentChar;
            currentNumber = 0;
        }
    }

    int result = 0;
    // Sum all remaining numbers in the stack.
    while (!st.empty()) {
        result += st.top();
        st.pop();
    }
    return result;
}

int main() {
    cout << calculate("3+2*2") << endl;    // Output: 7
    cout << calculate(" 3/2 ") << endl;      // Output: 1
    cout << calculate(" 3+5 / 2 ") << endl;   // Output: 5
    return 0;
}

