// Definition for singly-linked list.
struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    bool isPalindrome(ListNode* head) {
        // Initialize slow and fast pointers to find the middle of the list
        ListNode* slow = head;
        ListNode* fast = head;
        while (fast && fast->next) {
            slow = slow->next;          // Move slow pointer by one
            fast = fast->next->next;    // Move fast pointer by two
        }

        // Reverse the second half of the list
        ListNode* prev = nullptr;
        while (slow) {
            ListNode* nextNode = slow->next; // Store next node
            slow->next = prev;         // Reverse the link
            prev = slow;               // Move prev to current node
            slow = nextNode;           // Advance slow pointer
        }

        // Compare the first half and the reversed second half
        ListNode* left = head;
        ListNode* right = prev;
        while (right) {              // Only need to iterate till the end of reversed half
            if (left->val != right->val)
                return false;      // A mismatch means the list is not a palindrome
            left = left->next;       // Move left pointer
            right = right->next;     // Move right pointer
        }

        return true;                 // The list is a palindrome
    }
};

