// C++ solution using deque from the STL
#include <vector>
#include <deque>
using namespace std;

class Solution {
public:
    vector<int> maxSlidingWindow(vector<int>& nums, int k) {
        // Result vector to store maximums of each window
        vector<int> result;
        // Deque to store indices of potential maximum elements
        deque<int> deq;

        for (int i = 0; i < nums.size(); i++) {
            // Remove the index if it is out of the window
            if (!deq.empty() && deq.front() == i - k) {
                deq.pop_front();
            }

            // Remove indices from the back if the current element is greater
            while (!deq.empty() && nums[deq.back()] < nums[i]) {
                deq.pop_back();
            }

            // Add current index to the deque
            deq.push_back(i);

            // If our window has hit size k, record the max (front of deque)
            if (i >= k - 1) {
                result.push_back(nums[deq.front()]);
            }
        }

        return result;
    }
};

