// C++ solution for grouping shifted strings
#include <iostream>
#include <vector>
#include <string>
#include <unordered_map>
#include <sstream>
using namespace std;

// Function to compute a key for each string based on differences
string getKey(const string &s) {
    if (s.length() == 1)
        return "0";
    ostringstream oss;
    for (size_t i = 1; i < s.size(); i++) {
        int diff = (s[i] - s[i - 1] + 26) % 26;
        // Append the difference and a comma to separate values
        oss << diff;
        if (i < s.size() - 1)
            oss << ",";
    }
    return oss.str();
}

vector<vector<string>> groupShiftedStrings(vector<string>& strings) {
    unordered_map<string, vector<string>> groups;
    // Group strings by computed key
    for (const string &s : strings) {
        string key = getKey(s);
        groups[key].push_back(s);
    }
    // Extract results from the hash table
    vector<vector<string>> result;
    for (auto &entry : groups) {
        result.push_back(entry.second);
    }
    return result;
}

// Example usage
int main() {
    vector<string> strings = {"abc","bcd","acef","xyz","az","ba","a","z"};
    vector<vector<string>> grouped = groupShiftedStrings(strings);
    // Print groups
    for (auto &group : grouped) {
        for (auto &str : group) {
            cout << str << " ";
        }
        cout << endl;
    }
    return 0;
}

