// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    // Constructor for a new node with a value, left and right pointers.
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    int count = 0;  // Global counter to store number of univalue subtrees

    // Helper function that performs postorder DFS and returns if the subtree is univalue.
    bool isUnival(TreeNode* node) {
        if (!node) return true; // A null node is considered univalue.

        // Recursively check left and right subtree.
        bool leftUnival = isUnival(node->left);
        bool rightUnival = isUnival(node->right);

        // If the left child exists and does not match the current node's value, mark left as false.
        if (node->left && node->left->val != node->val)
            leftUnival = false;
        // If the right child exists and does not match the current node's value, mark right as false.
        if (node->right && node->right->val != node->val)
            rightUnival = false;

        // If both left and right subtrees are univalue, then the current subtree is univalue.
        if (leftUnival && rightUnival) {
            count++;
            return true;
        }
        return false;
    }

    int countUnivalSubtrees(TreeNode* root) {
        isUnival(root);
        return count;
    }
};

