// C++ solution using a monotonic stack with detailed comments
#include <vector>
#include <stack>
#include <limits>
using namespace std;

class Solution {
public:
    bool verifyPreorder(vector<int>& preorder) {
        int lowerBound = numeric_limits<int>::min(); // Set initial lower bound
        stack<int> st; // Stack to simulate BST construction
        for (int value : preorder) {
            // If current value is below the lower bound, BST property is violated
            if (value < lowerBound)
                return false;
            // If current value is greater than stack's top, pop and update lowerBound
            while (!st.empty() && value > st.top()) {
                lowerBound = st.top(); // Update lowerBound to the popped element
                st.pop();
            }
            // Push the current value into the stack
            st.push(value);
        }
        return true;
    }
};

