// C++ solution for the Paint House problem

#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    int minCost(vector<vector<int>>& costs) {
        int n = costs.size();
        // Base case: if no houses, cost is 0
        if(n == 0) return 0;

        // Iterate through houses starting from the second one
        for (int i = 1; i < n; ++i) {
            // Cost to paint current house red
            costs[i][0] += min(costs[i-1][1], costs[i-1][2]);
            // Cost to paint current house blue
            costs[i][1] += min(costs[i-1][0], costs[i-1][2]);
            // Cost to paint current house green
            costs[i][2] += min(costs[i-1][0], costs[i-1][1]);
        }

        // Return the minimal cost among the three choices for the last house
        return min({costs[n-1][0], costs[n-1][1], costs[n-1][2]});
    }
};

