// C++ solution with DFS

#include <iostream>
#include <vector>
#include <unordered_set>
using namespace std;

bool dfs(int node, int parent, const vector<vector<int>>& graph, vector<bool>& visited) {
    visited[node] = true;
    // Traverse all neighbors of the current node
    for (int neighbor : graph[node]) {
        // Skip the parent node to prevent trivial cycle detection
        if (neighbor == parent) continue;
        // If already visited, a cycle exists
        if (visited[neighbor]) return false;
        // Recurse on neighbor; if cycle found, propagate false
        if (!dfs(neighbor, node, graph, visited)) return false;
    }
    return true;
}

bool validTree(int n, vector<vector<int>>& edges) {
    // A tree must have exactly n - 1 edges
    if (edges.size() != n - 1) return false;

    // Construct the graph as an adjacency list
    vector<vector<int>> graph(n);
    for (const auto& edge : edges) {
        int a = edge[0], b = edge[1];
        graph[a].push_back(b);
        graph[b].push_back(a);
    }

    // Initialize visited array
    vector<bool> visited(n, false);

    // Start DFS from node 0
    if (!dfs(0, -1, graph, visited)) return false;

    // Check if all nodes are visited (graph is connected)
    for (bool nodeVisited : visited) {
        if (!nodeVisited) return false;
    }
    return true;
}

// Example usage:
int main() {
    vector<vector<int>> edges1 = {{0,1}, {0,2}, {0,3}, {1,4}};
    vector<vector<int>> edges2 = {{0,1}, {1,2}, {2,3}, {1,3}, {1,4}};
    cout << boolalpha << validTree(5, edges1) << endl; // Expected output: true
    cout << boolalpha << validTree(5, edges2) << endl; // Expected output: false
    return 0;
}

