using namespace std;

// Function to find the missing number in the array
int missingNumber(vector<int>& nums) {
    // n is the length of the vector nums which represents the count of numbers provided
    int n = nums.size();
    // Calculate expected sum of the sequence from 0 to n using arithmetic sum formula
    int expected_sum = n * (n + 1) / 2;
    // Calculate the actual sum of elements inside the vector
    int actual_sum = 0; 
    for (int num : nums) {
        actual_sum += num;  // Accumulate each element
    }
    // The missing number is the difference between expected and actual sums
    return expected_sum - actual_sum;
}

