// C++ solution for Alien Dictionary
#include <iostream>
#include <vector>
#include <string>
#include <unordered_map>
#include <unordered_set>
#include <queue>
using namespace std;

string alienOrder(vector<string>& words) {
    // Create a graph and in-degree map for all unique characters.
    unordered_map<char, unordered_set<char>> graph;
    unordered_map<char, int> inDegree;
    for (const string &word : words) {
        for (char c : word) {
            inDegree[c] = 0; // initialize each character's inDegree to 0.
        }
    }

    // Build the graph by comparing adjacent words.
    for (size_t i = 0; i < words.size() - 1; i++) {
        string word1 = words[i], word2 = words[i+1];
        // Check invalid case: prefix condition.
        if (word1.size() > word2.size() && word1.substr(0, word2.size()) == word2)
            return "";
        for (size_t j = 0; j < min(word1.size(), word2.size()); j++) {
            char parent = word1[j], child = word2[j];
            if (parent != child) {
                // Add edge if it does not already exist.
                if (graph[parent].find(child) == graph[parent].end()) {
                    graph[parent].insert(child);
                    inDegree[child]++;
                }
                break;
            }
        }
    }

    // Topological sort using Kahn's algorithm.
    queue<char> zeroInDegree;
    for (auto pair : inDegree) {
        if (pair.second == 0)
            zeroInDegree.push(pair.first);
    }

    string order;
    while (!zeroInDegree.empty()) {
        char current = zeroInDegree.front();
        zeroInDegree.pop();
        order.push_back(current);
        for (char neighbor : graph[current]) {
            inDegree[neighbor]--;
            if (inDegree[neighbor] == 0)
                zeroInDegree.push(neighbor);
        }
    }

    // If order size doesn't match unique characters, return empty string (cycle exists).
    return order.size() == inDegree.size() ? order : "";
}

