// C++ solution for Closest Binary Search Tree Value

/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode() : val(0), left(nullptr), right(nullptr) {}
 *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:
    int closestValue(TreeNode* root, double target) {
        // Initialize the best_value with root's value.
        int best_value = root->val;
        TreeNode* current = root;

        // Iterate through the BST
        while (current) {
            // Compute the absolute differences.
            double current_diff = fabs(current->val - target);
            double best_diff = fabs(best_value - target);

            // Update best_value if current node is closer or equal (but smaller)
            if (current_diff < best_diff || (current_diff == best_diff && current->val < best_value)) {
                best_value = current->val;
            }

            // Move left or right depending on the target comparison.
            if (target < current->val) {
                current = current->left;
            } else {
                current = current->right;
            }
        }

        return best_value;
    }
};

