// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    vector<int> closestKValues(TreeNode* root, double target, int k) {
        vector<TreeNode*> preds, succs;

        // Initialize predecessor stack
        auto initPredecessor = [&](TreeNode* node) {
            while (node) {
                if (node->val <= target) {
                    preds.push_back(node);
                    node = node->right;
                } else {
                    node = node->left;
                }
            }
        };

        // Initialize successor stack
        auto initSuccessor = [&](TreeNode* node) {
            while (node) {
                if (node->val > target) {
                    succs.push_back(node);
                    node = node->left;
                } else {
                    node = node->right;
                }
            }
        };

        initPredecessor(root);
        initSuccessor(root);

        // Helper lambdas to get next predecessor and successor
        auto getPredecessor = [&]() -> int {
            TreeNode* node = preds.back();
            preds.pop_back();
            int val = node->val;
            node = node->left;
            while (node) {
                preds.push_back(node);
                node = node->right;
            }
            return val;
        };

        auto getSuccessor = [&]() -> int {
            TreeNode* node = succs.back();
            succs.pop_back();
            int val = node->val;
            node = node->right;
            while (node) {
                succs.push_back(node);
                node = node->left;
            }
            return val;
        };

        // Avoid duplicate if both stacks contain same element
        if (!preds.empty() && !succs.empty() && preds.back()->val == succs.back()->val)
            getPredecessor();

        vector<int> result;
        for (int i = 0; i < k; ++i) {
            if (preds.empty()) {
                result.push_back(getSuccessor());
            } else if (succs.empty()) {
                result.push_back(getPredecessor());
            } else {
                if (abs(preds.back()->val - target) <= abs(succs.back()->val - target))
                    result.push_back(getPredecessor());
                else
                    result.push_back(getSuccessor());
            }
        }
        return result;
    }
};

