// C++ implementation of First Bad Version
class Solution {
public:
    int firstBadVersion(int n) {
        // Initialize left and right pointers for binary search
        int left = 1, right = n;
        while (left < right) {
            // Compute mid to avoid potential overflow
            int mid = left + (right - left) / 2;
            // Call the API isBadVersion to check if mid is bad
            if (isBadVersion(mid)) {
                // If mid is bad, narrow the search to the left half including mid
                right = mid;
            } else {
                // If mid is not bad, narrow the search to the right half excluding mid
                left = mid + 1;
            }
        }
        // The first bad version is located when left equals right
        return left;
    }
};

