// C++ solution to find the duplicate number using Floyd's Tortoise and Hare algorithm.
#include <vector>
#include <iostream>
using namespace std;

class Solution {
public:
    int findDuplicate(vector<int>& nums) {
        // Phase 1: Detect the cycle.
        int tortoise = nums[0];  // Initialize tortoise pointer.
        int hare = nums[0];      // Initialize hare pointer.
        do {
            tortoise = nums[tortoise];          // Move tortoise one step.
            hare = nums[nums[hare]];              // Move hare two steps.
        } while (tortoise != hare);               // Loop until they meet.

        // Phase 2: Find the entrance to the cycle.
        int pointer = nums[0];
        while (pointer != tortoise) {
            pointer = nums[pointer];             // Move both pointers one step.
            tortoise = nums[tortoise];
        }
        return pointer;  // The duplicate number.
    }
};

// Example usage:
int main() {
    Solution sol;
    vector<int> sample = {3, 1, 3, 4, 2};
    cout << sol.findDuplicate(sample) << endl;  // Expected output: 3
    return 0;
}

