    // DFS helper function.
    void dfs(TreeNode* node, int parentVal, int currentLength) {
        if (!node) return;
        // If the node value is consecutive, increment current length.
        if (node->val == parentVal + 1) {
            currentLength++;
        } else {
            currentLength = 1;
        }
        // Update the maximum sequence length.
        maxLength = std::max(maxLength, currentLength);
