// Function to calculate length of longest increasing subsequence
int lengthOfLIS(vector<int>& nums) {
    vector<int> dp; // dp array storing the smallest tail for each subsequence length
    for (int num : nums) {
        // Use lower_bound to perform binary search over dp array
        auto it = lower_bound(dp.begin(), dp.end(), num);
        if (it == dp.end()) {
            dp.push_back(num); // Extend dp if num is greater than all current tails
        } else {
            *it = num; // Replace to maintain the smallest possible tail
        }
    }
    return dp.size(); // The size of dp is the length of the longest increasing subsequence
