// C++ implementation using Union Find with path compression and union by rank.
#include <vector>
using namespace std;

class UnionFind {
public:
    vector<int> parent;
    vector<int> rank;
    int count; // number of islands

    UnionFind(int size) : parent(size, -1), rank(size, 0), count(0) {}

    int find(int x) {
        if (parent[x] != x)
            parent[x] = find(parent[x]); // path compression
        return parent[x];
    }

    bool unionNodes(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX == rootY) 
            return false;
        if (rank[rootX] < rank[rootY])
            parent[rootX] = rootY;
        else if (rank[rootX] > rank[rootY])
            parent[rootY] = rootX;
        else {
            parent[rootY] = rootX;
            rank[rootX]++;
        }
        count--; // merge reduces island count
        return true;
    }
};

class Solution {
public:
    vector<int> numIslands2(int m, int n, vector<vector<int>>& positions) {
        UnionFind uf(m * n);
        vector<int> result;
        vector<vector<int>> directions = {{0,1}, {1,0}, {0,-1}, {-1,0}};

        for (auto& pos : positions) {
            int r = pos[0];
            int c = pos[1];
            int idx = r * n + c;

            // If already land, push the current count.
            if (uf.parent[idx] != -1) {
                result.push_back(uf.count);
                continue;
            }

            // Mark cell as land.
            uf.parent[idx] = idx;
            uf.count++;

            // Union with all four neighbors.
            for (auto& d: directions) {
                int nr = r + d[0], nc = c + d[1];
                int nidx = nr * n + nc;
                if (nr >= 0 && nr < m && nc >= 0 && nc < n && uf.parent[nidx] != -1) {
                    uf.unionNodes(idx, nidx);
                }
            }

            result.push_back(uf.count);
        }
        return result;
    }
};

