// C++ Solution with line-by-line comments
#include <vector>
#include <algorithm>
#include <iostream>
using namespace std;

int maxProfit(vector<int>& prices) {
    // Return 0 if prices list is empty
    if(prices.empty()) return 0;

    // Initialize states:
    // s0: maximum profit when ready to buy
    // s1: maximum profit when holding a stock
    // s2: maximum profit in cooldown (after selling a stock)
    int s0 = 0, s1 = -prices[0], s2 = 0;

    // Iterate over the days, starting from the second day
    for (size_t i = 1; i < prices.size(); i++) {
        int prev_s0 = s0, prev_s1 = s1, prev_s2 = s2;
        // Update s0: remain in s0 or come out of cooldown
        s0 = max(prev_s0, prev_s2);
        // Update s1: either continue holding or buy new stock today (using s0)
        s1 = max(prev_s1, prev_s0 - prices[i]);
        // Update s2: only can transition to cooldown by selling the stock
        s2 = prev_s1 + prices[i];
    }
    // The answer is the maximum profit when not holding a stock: either in s0 or s2
    return max(s0, s2);
}

// Example usage:
int main() {
    vector<int> prices = {1, 2, 3, 0, 2};
    cout << maxProfit(prices) << endl;
    return 0;
}

