    vector<vector<int>> sparseMatrixMultiplication(vector<vector<int>>& mat1, vector<vector<int>>& mat2) {
        int m = mat1.size();
        int k = mat1[0].size();
        int n = mat2[0].size();

        // Initialize the result matrix with zeros.
        vector<vector<int>> result(m, vector<int>(n, 0));

        // Iterate through each row of mat1.
        for (int i = 0; i < m; ++i) {
            // For each column element in the current row of mat1.
            for (int p = 0; p < k; ++p) {
                if (mat1[i][p] != 0) { // Check if the element in mat1 is non-zero.
                    // Multiply with corresponding elements of mat2.
                    for (int j = 0; j < n; ++j) {
                        if (mat2[p][j] != 0) { // Check if the element in mat2 is non-zero.
                            result[i][j] += mat1[i][p] * mat2[p][j];
                        }
                    }
                }
            }
        }
        return result;
    }
