// C++ implementation of the solution
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    int maxCoins(vector<int>& nums) {
        int n = nums.size();
        // Create extended vector with virtual boundaries
        vector<int> extended;
        extended.push_back(1);
        for (int num : nums) {
            extended.push_back(num);
        }
        extended.push_back(1);

        // Create dp table initialized with 0's; dimensions: (n+2) x (n+2)
        vector<vector<int>> dp(n + 2, vector<int>(n + 2, 0));

        // Fill dp using interval DP approach
        for (int length = 2; length < n + 2; ++length) {
            for (int left = 0; left < n + 2 - length; ++left) {
                int right = left + length;
                // Try bursting each balloon k as the last burst in the interval (left, right)
                for (int k = left + 1; k < right; ++k) {
                    int coins = extended[left] * extended[k] * extended[right] + dp[left][k] + dp[k][right];
                    dp[left][right] = max(dp[left][right], coins);
                }
            }
        }

        // The result is stored in dp[0][n+1]
        return dp[0][n+1];
    }
};

