#include <vector>
#include <queue>
#include <map>
using namespace std;

// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    vector<vector<int>> verticalOrder(TreeNode* root) {
        // Result vector to store final vertical order.
        vector<vector<int>> result;
        if (!root) return result;

        // Map to hold nodes grouped by their column index; keys sorted automatically.
        map<int, vector<int>> colTable;
        // Queue for BFS; pair contains the node pointer and its column index.
        queue<pair<TreeNode*, int>> bfsQueue;
        bfsQueue.push({root, 0});

        while (!bfsQueue.empty()) {
            auto cur = bfsQueue.front();
            bfsQueue.pop();
            TreeNode* node = cur.first;
            int col = cur.second;

            // Append the current node value into its corresponding column in the map.
            colTable[col].push_back(node->val);

            // Process left child with column index decremented by 1.
            if (node->left) {
                bfsQueue.push({node->left, col - 1});
            }
            // Process right child with column index incremented by 1.
            if (node->right) {
                bfsQueue.push({node->right, col + 1});
            }
        }

        // Iterate over the sorted columns and add the vectors to the result.
        for (auto& entry : colTable) {
            result.push_back(entry.second);
        }
        return result;
    }
};

