// C++ solution using merge sort approach

#include <vector>
#include <utility>
using namespace std;

class Solution {
public:
    vector<int> countSmaller(vector<int>& nums) {
        int n = nums.size();
        vector<int> counts(n, 0);
        // Create pairs of (value, original index)
        vector<pair<int, int>> enumArr;
        for (int i = 0; i < n; i++) {
            enumArr.push_back({nums[i], i});
        }
        mergeSort(enumArr, 0, n, counts);
        return counts;
    }

    // Recursively sort and count
    void mergeSort(vector<pair<int,int>>& arr, int start, int end, vector<int>& counts) {
        if (end - start <= 1) return; // base case: one element
        int mid = start + (end - start) / 2;
        mergeSort(arr, start, mid, counts);
        mergeSort(arr, mid, end, counts);
        merge(arr, start, mid, end, counts);
    }

    // Merge step with counting
    void merge(vector<pair<int,int>>& arr, int start, int mid, int end, vector<int>& counts) {
        vector<pair<int,int>> temp;
        int left = start, right = mid, rightCount = 0;
        // Merge left and right subarrays
        while (left < mid && right < end) {
            if (arr[left].first <= arr[right].first) {
                counts[arr[left].second] += rightCount;
                temp.push_back(arr[left]);
                left++;
            } else {
                rightCount++;
                temp.push_back(arr[right]);
                right++;
            }
        }
        // Remaining elements in left array update counts by rightCount
        while (left < mid) {
            counts[arr[left].second] += rightCount;
            temp.push_back(arr[left]);
            left++;
        }
        // Append remaining elements in right array
        while (right < end) {
            temp.push_back(arr[right]);
            right++;
        }
        // Copy back to original array
        for (int i = start; i < end; i++) {
            arr[i] = temp[i - start];
        }
    }
};

