int shortestDistance(vector<vector<int>>& grid) {
    int m = grid.size(), n = grid[0].size();
    int totalBuildings = 0;
    vector<vector<int>> totalDistance(m, vector<int>(n, 0));
    vector<vector<int>> reachableCount(m, vector<int>(n, 0));

    auto bfs = [&](int start_i, int start_j) {
        vector<vector<bool>> visited(m, vector<bool>(n, false));
        queue<tuple<int,int,int>> q;
        q.push({start_i, start_j, 0});
        visited[start_i][start_j] = true;

        while (!q.empty()) {
            auto [i, j, dist] = q.front();
            q.pop();
            vector<pair<int, int>> directions = {{-1,0},{1,0},{0,-1},{0,1}};
            for (auto [di, dj] : directions) {
                int x = i + di, y = j + dj;
                if (x >= 0 && x < m && y >= 0 && y < n && !visited[x][y] && grid[x][y] == 0) {
                    visited[x][y] = true;
                    totalDistance[x][y] += dist + 1;
                    reachableCount[x][y] += 1;
                    q.push({x, y, dist+1});
                }
            }
        }
    };

    for (int i = 0; i < m; i++){
        for (int j = 0; j < n; j++){
            if (grid[i][j] == 1) {
                totalBuildings++;
                bfs(i, j);
            }
        }
    }

    int minDistance = INT_MAX;
    for (int i = 0; i < m; i++){
        for (int j = 0; j < n; j++){
            if (grid[i][j] == 0 && reachableCount[i][j] == totalBuildings) {
                minDistance = min(minDistance, totalDistance[i][j]);
            }
        }
    }

    return minDistance == INT_MAX ? -1 : minDistance;
}

