// Definition for singly-linked list.
struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* oddEvenList(ListNode* head) {
        // Return if the list is empty or contains only one element.
        if (!head || !head->next) return head;

        ListNode* odd = head;         // Pointer to odd nodes.
        ListNode* even = head->next;    // Pointer to even nodes.
        ListNode* even_head = even;     // Keep the head of even sublist.

        // Rearrange nodes.
        while (even && even->next) {
            odd->next = even->next;    // Link odd node to the next odd node.
            odd = odd->next;           // Move odd pointer.

            even->next = odd->next;    // Link even node to the next even node.
            even = even->next;         // Move even pointer.
        }

        // Attach even list after odd list.
        odd->next = even_head;
        return head;
    }
};

