// C++ implementation for Longest Increasing Path in a Matrix

class Solution {
public:
    int longestIncreasingPath(vector<vector<int>>& matrix) {
        // Check for empty matrix
        if (matrix.empty() || matrix[0].empty()) return 0;

        int m = matrix.size(), n = matrix[0].size();
        // Create a memoization table initialized to 0
        vector<vector<int>> memo(m, vector<int>(n, 0));
        int longestPath = 0;

        // Lambda function for DFS with memoization
        function<int(int, int)> dfs = [&](int i, int j) -> int {
            // Return the cached value if already computed
            if (memo[i][j] != 0) return memo[i][j];

            int maxLen = 1;
            // Define four possible directions
            vector<pair<int,int>> directions = {{-1,0}, {1,0}, {0,-1}, {0,1}};

            for (auto &dir : directions) {
                int ni = i + dir.first, nj = j + dir.second;
                // Check boundaries and increasing condition
                if (ni >= 0 && ni < m && nj >= 0 && nj < n && matrix[ni][nj] > matrix[i][j]) {
                    maxLen = max(maxLen, 1 + dfs(ni, nj));
                }
            }
            memo[i][j] = maxLen;
            return maxLen;
        };

        // Iterate over every cell to get the global maximum path length
        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                longestPath = max(longestPath, dfs(i, j));
            }
        }

        return longestPath;
    }
};

