    vector<string> words = {"abcd", "dcba", "lls", "s", "sssll"};
    vector<vector<int>> pairs = palindromePairs(words);
    // Expected Output: [ [0,1], [1,0], [3,2], [2,4] ]
    for (const auto& pair : pairs) {
        cout << "[" << pair[0] << "," << pair[1] << "] ";
    }
    return 0;
}

