#include <vector>
using namespace std;

class Solution {
public:
    vector<int> countBits(int n) {
        // Create a vector to store the count of 1's for each number from 0 to n
        vector<int> dp(n + 1, 0);
        // Build the solution from 1 to n using the relation dp[i] = dp[i >> 1] + (i & 1)
        for (int i = 1; i <= n; ++i) {
            dp[i] = dp[i >> 1] + (i & 1);
        }
        return dp;
    }
};

