#include <queue>
#include <unordered_map>
#include <string>
#include <vector>
#include <deque>
using namespace std;

string rearrangeString(string s, int k) {
    if (k == 0) return s;

    // Count frequency of each character
    unordered_map<char, int> freqMap;
    for (char ch : s) {
        freqMap[ch]++;
    }

    // Max-heap using pair: (frequency, character)
    auto cmp = [](pair<int, char> a, pair<int, char> b) {
        return a.first < b.first; // Higher frequency first
    };
    priority_queue<pair<int, char>, vector<pair<int, char>>, decltype(cmp)> maxHeap(cmp);

    for (auto &entry : freqMap) {
        maxHeap.push({entry.second, entry.first});
    }

    // Queue to hold characters used in the last k iterations
    deque<pair<int, char>> waitQueue;
    string result;

    while (!maxHeap.empty()) {
        auto current = maxHeap.top();
        maxHeap.pop();
        result.push_back(current.second);
        current.first--; // decrease frequency

        waitQueue.push_back(current);
        if (waitQueue.size() < (unsigned)k)
            continue;

        auto front = waitQueue.front();
        waitQueue.pop_front();
        if (front.first > 0) {
            maxHeap.push(front);
        }
    }

    return result.length() == s.size() ? result : "";
}

