    queue<pair<int, int>> hitsQueue;

public:
    // Constructor to initialize the HitCounter
    HitCounter() {
        // No initialization required
    }

    // Record a hit at the given timestamp
    void hit(int timestamp) {
        if (!hitsQueue.empty() && hitsQueue.back().first == timestamp) {
            // Increase count if last timestamp matches
            hitsQueue.back().second++;
        } else {
            // Otherwise, push a new pair with count 1
            hitsQueue.push({timestamp, 1});
        }
    }

    // Return the count of hits in the past 300 seconds
    int getHits(int timestamp) {
        // Remove outdated hits from the front of the queue
        while (!hitsQueue.empty() && hitsQueue.front().first <= timestamp - 300) {
            hitsQueue.pop();
        }

        // Sum the counts in the queue
        int totalHits = 0;
        queue<pair<int,int>> tempQueue = hitsQueue; // temporary copy for iteration
        while (!tempQueue.empty()) {
            totalHits += tempQueue.front().second;
            tempQueue.pop();
        }
        return totalHits;
    }
};

