// Definition for a binary tree node.
struct TreeNode {
    int val;                   // The value stored in the node.
    TreeNode *left;            // Pointer to the left child.
    TreeNode *right;           // Pointer to the right child.
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    vector<vector<int>> findLeaves(TreeNode* root) {
        vector<vector<int>> result;  // List to store nodes at each removal step.
        getHeight(root, result);       // Compute height and populate result.
        return result;
    }

    // Recursive helper function: returns the height of the current node.
    int getHeight(TreeNode* node, vector<vector<int>>& result) {
        if (!node) return 0;  // Base case: if node is null, height is 0.
        // Recursively compute the height of left and right subtrees.
        int leftHeight = getHeight(node->left, result);
        int rightHeight = getHeight(node->right, result);
        // Current node height is max of left/right heights plus one.
        int currentHeight = max(leftHeight, rightHeight) + 1;
        // Ensure the result vector has a subvector for the current height.
        if (result.size() < currentHeight) {
            result.push_back(vector<int>());
        }
        // Append the current node's value to the corresponding list.
        result[currentHeight - 1].push_back(node->val);
        return currentHeight;
    }
};

