// Definition for singly-linked list.
struct ListNode {
  int val;
  ListNode *next;
  ListNode(int x) : val(x), next(nullptr) {}
};

// Helper function to reverse the linked list
ListNode* reverseList(ListNode* head) {
  ListNode* prev = nullptr;
  ListNode* curr = head;
  while (curr) {
    ListNode* nxt = curr->next;  // store the next node
    curr->next = prev;           // reverse the current node's pointer
    prev = curr;                 // move prev forward
    curr = nxt;                  // move to the next node
  }
  return prev;
}

class Solution {
public:
    ListNode* plusOne(ListNode* head) {
        // Reverse the list to start processing from the least significant digit
        head = reverseList(head);

        ListNode* current = head;
        int carry = 1;  // initialize carry for the plus one
        while (current && carry) {
            current->val += carry;    // add carry to current digit
            carry = current->val / 10;  // compute new carry
            current->val %= 10;         // update the node's value
            // If at the end of the list and a carry still exists, add a new node.
            if (!current->next && carry) {
                current->next = new ListNode(0);
            }
            current = current->next;
        }
        // Reverse the list back to its original order and return it.
        return reverseList(head);
    }
};

