// C++ solution using binary search
class Solution {
public:
    int guessNumber(int n) {
        // Initialize low and high pointers for binary search
        int low = 1, high = n;
        // Loop until low exceeds high
        while (low <= high) {
            // Calculate mid safely to avoid overflow
            int mid = low + (high - low) / 2;
            // Call the guess API function
            int result = guess(mid);
            // If result is 0, mid is the correct guess
            if (result == 0) return mid;
            // If result is -1, adjust high since guess is too high
            else if (result == -1) high = mid - 1;
            // Else result is 1, adjust low since guess is too low
            else low = mid + 1;
        }
        // Return low (this line is logically unreachable)
        return low;
    }
};

