// C++ solution using dynamic programming

#include <vector>
using namespace std;

class Solution {
public:
    int combinationSum4(vector<int>& nums, int target) {
        // Create a dp vector where dp[i] stores the number of ways to reach sum i
        vector<unsigned int> dp(target + 1, 0);
        // Base case: one way to reach sum 0
        dp[0] = 1;

        // Build the dp table from 1 to target
        for (int i = 1; i <= target; i++) {
            for (int num : nums) {
                if (i - num >= 0) {
                    dp[i] += dp[i - num];
                }
            }
        }
        return dp[target];
    }
};

