#include <string>
#include <unordered_map>
using namespace std;

bool canConstruct(string ransomNote, string magazine) {
    // Use an unordered_map to hold frequency counts of each character in magazine
    unordered_map<char, int> frequency;
    for (char ch : magazine) {
        frequency[ch]++;
    }

    // Iterate through each character in ransom note and decrease its count
    for (char ch : ransomNote) {
        if (frequency[ch] == 0) {
            return false; // Character not available or already fully used
        }
        frequency[ch]--;
    }

    return true;
}

