class Solution {
public:
    // Helper function that returns the decoded string starting at index i by reference
    string helper(const string &s, int &i) {
        string decoded;
        while (i < s.size()) {
            if (isdigit(s[i])) {
                // Build the number k
                int k = 0;
                while (i < s.size() && isdigit(s[i])) {
                    k = k * 10 + (s[i] - '0');
                    i++;
                }
                i++; // skip the '['
                // Recursively decode the substring
                string sub = helper(s, i);
                // Append the substring k times
                while (k--) {
                    decoded += sub;
                }
            } else if (s[i] == ']') {
                // End of current context, move past the ']'
                i++;
                return decoded;
            } else {
                // Append letter characters directly
                decoded.push_back(s[i]);
                i++;
            }
        }
        return decoded;
    }

    string decodeString(string s) {
        int i = 0;
        return helper(s, i);
