// C++ solution for Split Array Largest Sum

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
using namespace std;

// Helper function to determine if the array can be split into <= k subarrays
// with each subarray sum not exceeding maxSum
bool canSplit(const vector<int>& nums, int k, long long maxSum) {
    int subarrayCount = 1;
    long long currentSum = 0;
    for (int num : nums) {
        if (currentSum + num > maxSum) {
            subarrayCount++; // start a new subarray
            currentSum = num;  // reset current sum with current number
        } else {
            currentSum += num; // add current number to subarray
        }
    }
    return subarrayCount <= k;
}

int splitArray(vector<int>& nums, int k) {
    int low = *max_element(nums.begin(), nums.end());
    long long high = accumulate(nums.begin(), nums.end(), 0LL);

    while (low < high) {
        int mid = low + (high - low) / 2;  // candidate maximum subarray sum
        if (canSplit(nums, k, mid)) {
            high = mid;  // candidate valid, attempt lower candidate
        } else {
            low = mid + 1;  // candidate too low, increase it
        }
    }
    return low;
}

