// C++ solution for Partition Equal Subset Sum

#include <vector>
using namespace std;

class Solution {
public:
    bool canPartition(vector<int>& nums) {
        // Calculate the total sum of the array
        int totalSum = 0;
        for (int num : nums) {
            totalSum += num;
        }

        // If the total sum is odd, equal partition is not possible
        if (totalSum % 2 != 0) return false;

        // Set the target sum to half of the total sum
        int target = totalSum / 2;

        // Initialize dp vector where dp[i] indicates if subset sum i is achievable
        vector<bool> dp(target + 1, false);
        dp[0] = true; // Base case: subset sum of 0 is always possible

        // Iterate through each number in the array
        for (int num : nums) {
            // Iterate backwards to avoid using the same number multiple times
            for (int i = target; i >= num; i--) {
                if (dp[i - num])
                    dp[i] = true;
            }
        }

        // Return true if the target sum is achievable
        return dp[target];
    }
};

