// C++ solution for Pacific Atlantic Water Flow

#include <vector>
using namespace std;

class Solution {
public:
    void dfs(vector<vector<int>>& heights, int r, int c, vector<vector<bool>>& reachable) {
        int rows = heights.size(), cols = heights[0].size();
        reachable[r][c] = true;
        // Directions for up, down, left, right
        int dirs[4][2] = {{-1,0}, {1,0}, {0,-1}, {0,1}};
        for (auto &dir : dirs) {
            int newR = r + dir[0], newC = c + dir[1];
            // Check if next cell is within bounds and can be visited
            if (newR >= 0 && newR < rows && newC >= 0 && newC < cols &&
                !reachable[newR][newC] && heights[newR][newC] >= heights[r][c]) {
                dfs(heights, newR, newC, reachable);
            }
        }
    }

    vector<vector<int>> pacificAtlantic(vector<vector<int>>& heights) {
        if (heights.empty() || heights[0].empty()) return {};
        int rows = heights.size(), cols = heights[0].size();
        vector<vector<bool>> pacificReachable(rows, vector<bool>(cols, false));
        vector<vector<bool>> atlanticReachable(rows, vector<bool>(cols, false));

        // DFS from Pacific borders (left and top)
        for (int i = 0; i < rows; i++) {
            dfs(heights, i, 0, pacificReachable);
        }
        for (int j = 0; j < cols; j++) {
            dfs(heights, 0, j, pacificReachable);
        }

        // DFS from Atlantic borders (right and bottom)
        for (int i = 0; i < rows; i++) {
            dfs(heights, i, cols - 1, atlanticReachable);
        }
        for (int j = 0; j < cols; j++) {
            dfs(heights, rows - 1, j, atlanticReachable);
        }

        // Gather the cells that can reach both oceans
        vector<vector<int>> result;
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (pacificReachable[i][j] && atlanticReachable[i][j])
                    result.push_back({i, j});
            }
        }
        return result;
    }
};

