// C++ solution using sliding window technique
#include <iostream>
#include <unordered_map>
#include <algorithm>
using namespace std;

int characterReplacement(string s, int k) {
    unordered_map<char, int> charCounts; // Hash table for frequency count
    int maxFreq = 0;   // Maximum frequency of a single character in the window
    int maxLength = 0;
    int left = 0;      // Left pointer of the sliding window

    // Traverse the string with the right pointer
    for (int right = 0; right < s.size(); right++) {
        // Increment frequency of the current character
        charCounts[s[right]]++;
        // Update the maximum frequency in the window
        maxFreq = max(maxFreq, charCounts[s[right]]);

        // If the number of changes needed exceeds k, shrink the window
        if ((right - left + 1) - maxFreq > k) {
            charCounts[s[left]]--;
            left++;
        }
        // Update the maximum length observed
        maxLength = max(maxLength, right - left + 1);
    }

    return maxLength;
}

