// Definition for a Node.
class Node {
public:
    int val;
    Node* prev;
    Node* next;
    Node* child;

    Node(int _val, Node* _prev = nullptr, Node* _next = nullptr, Node* _child = nullptr)
      : val(_val), prev(_prev), next(_next), child(_child) {}
};

class Solution {
public:
    Node* flatten(Node* head) {
        if (!head) return head;
        flattenDFS(head);
        return head;
    }
private:
    // Helper function to perform DFS and return the tail of the flattened list.
    Node* flattenDFS(Node* node) {
        Node* current = node;
        Node* last = node;
        while (current) {
            Node* next = current->next;  // Store next pointer.
            // If a child is present, recursively flatten the child list.
            if (current->child) {
                Node* childTail = flattenDFS(current->child);
                // Connect the current node with its child.
                current->next = current->child;
                current->child->prev = current;
                // If next exists, connect it after the child list.
                if (next) {
                    childTail->next = next;
                    next->prev = childTail;
                }
                // Set child pointer to nullptr.
                current->child = nullptr;
                last = childTail;
            } else {
                last = current;
            }
            current = next;
        }
        return last;
    }
};

