// Include necessary libraries.
#include <unordered_map>
#include <unordered_set>
#include <string>
using namespace std;

// Definition of Node representing a frequency node in a doubly-linked list.
struct Node {
    int count;                          // frequency count
    unordered_set<string> keys;         // set of keys with this frequency
    Node* prev;                         // previous node
    Node* next;                         // next node
    Node(int c): count(c), prev(nullptr), next(nullptr) {}
};

class AllOne {
public:
    AllOne() {
        head = new Node(INT_MIN);       // sentinel head with very low count.
        tail = new Node(INT_MAX);       // sentinel tail with very high count.
        head->next = tail;
        tail->prev = head;
    }

    void inc(string key) {
        Node* curr;
        // If key is new, treat current node as head.
        if (keyToNode.find(key) == keyToNode.end()) {
            curr = head;
        } else {
            curr = keyToNode[key];
            curr->keys.erase(key);
        }
        int targetCount = (curr == head ? 0 : curr->count) + 1;
        Node* nextNode = curr->next;
        // If next node does not have the target count, create it.
        if (nextNode == tail || nextNode->count != targetCount) {
            Node* newNode = new Node(targetCount);
            insertNodeAfter(curr, newNode);
            nextNode = newNode;
        }
        nextNode->keys.insert(key);
        keyToNode[key] = nextNode;
        // Remove current node if it's not head and becomes empty.
        if (curr != head && curr->keys.empty()) {
            removeNode(curr);
        }
    }

    void dec(string key) {
        Node* curr = keyToNode[key];
        curr->keys.erase(key);
        if (curr->count == 1) {
            // Remove key completely if count becomes zero.
            keyToNode.erase(key);
        } else {
            int targetCount = curr->count - 1;
            Node* prevNode = curr->prev;
            // If previous node does not have the target count, create it.
            if (prevNode == head || prevNode->count != targetCount) {
                Node* newNode = new Node(targetCount);
                insertNodeAfter(prevNode, newNode);
                prevNode = newNode;
            }
            prevNode->keys.insert(key);
            keyToNode[key] = prevNode;
        }
        if (curr->keys.empty()) {
            removeNode(curr);
        }
    }

    string getMaxKey() {
        // Return an arbitrary key from the node before tail.
        if (tail->prev == head) return "";
        return *(tail->prev->keys.begin());
    }

    string getMinKey() {
        // Return an arbitrary key from the node after head.
        if (head->next == tail) return "";
        return *(head->next->keys.begin());
    }

private:
    Node* head;
    Node* tail;
    unordered_map<string, Node*> keyToNode;

    // Helper: insert newNode after prevNode.
    void insertNodeAfter(Node* prevNode, Node* newNode) {
        newNode->prev = prevNode;
        newNode->next = prevNode->next;
        prevNode->next->prev = newNode;
        prevNode->next = newNode;
    }

    // Helper: remove node from the doubly linked list.
    void removeNode(Node* node) {
        node->prev->next = node->next;
        node->next->prev = node->prev;
        delete node;
    }
};

