// C++ solution for Path Sum III
#include <unordered_map>
using namespace std;

// Definition for a binary tree node.
struct TreeNode {
    int val;                     // node value
    TreeNode *left;              // left child
    TreeNode *right;             // right child
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    int pathSum(TreeNode* root, int targetSum) {
        unordered_map<long long, int> prefixSums;
        prefixSums[0] = 1; // base case: empty path has sum = 0
        return dfs(root, 0, targetSum, prefixSums);
    }

private:
    int dfs(TreeNode* node, long long currentSum, int targetSum, unordered_map<long long, int>& prefixSums) {
        if (!node) return 0;

        // Update the running sum
        currentSum += node->val;
        // Check for the number of valid paths ending at the current node
        int numPaths = prefixSums[currentSum - targetSum];

        // Update the hash map with the current running sum
        prefixSums[currentSum]++;

        // Recurse into left and right subtrees
        numPaths += dfs(node->left, currentSum, targetSum, prefixSums);
        numPaths += dfs(node->right, currentSum, targetSum, prefixSums);

        // Backtrack: decrement the current sum count so not to affect other paths
        prefixSums[currentSum]--;
        return numPaths;
    }
};

