// C++ solution for finding all anagram start indices in a string
#include <vector>
#include <string>
#include <unordered_map>
using namespace std;

class Solution {
public:
    vector<int> findAnagrams(string s, string p) {
        vector<int> result;
        int sLength = s.size(), pLength = p.size();
        if(sLength < pLength) return result;

        // Frequency maps using arrays for 26 lowercase letters
        int pCount[26] = {0}, sCount[26] = {0};

        // Initialize frequency counts for p and the first window in s
        for (int i = 0; i < pLength; i++) {
            pCount[p[i] - 'a']++;
            sCount[s[i] - 'a']++;
        }

        // Compare frequency arrays. If they match, record index 0.
        auto matches = [&]() -> bool {
            for (int i = 0; i < 26; i++)
                if (pCount[i] != sCount[i])
                    return false;
            return true;
        };

        if (matches())
            result.push_back(0);

        // Slide the window across s
        for (int i = pLength; i < sLength; i++) {
            sCount[s[i] - 'a']++;                 // Add new character
            sCount[s[i - pLength] - 'a']--;         // Remove old character
            if (matches())
                result.push_back(i - pLength + 1);
        }

        return result;
    }
};

