string parseTernary(const string &expression) {
    // Initialize a stack to store characters/results during evaluation
    stack<char> st;
    int i = expression.size() - 1;
    // Process the expression from right to left
    while(i >= 0) {
        if(expression[i] == '?'){
            // Pop the true and false expressions from the stack
            char trueExpr = st.top();
            st.pop();
            char falseExpr = st.top();
            st.pop();
            i--; // Move to the condition character
            // Evaluate the condition and push the corresponding result
            st.push(expression[i] == 'T' ? trueExpr : falseExpr);
        }
        else if(expression[i] == ':'){
            // Skip the colon separator
        }
        else{
            // Push digits, 'T', and 'F' onto the stack
            st.push(expression[i]);
        }
        i--;
    }
    // The final result is the top element on the stack
    return string(1, st.top());
}

int main() {
    cout << parseTernary("T?2:3") << endl;  // Expected output "2"
