using namespace std;

class Solution {
public:
    int fourSumCount(vector<int>& nums1, vector<int>& nums2, vector<int>& nums3, vector<int>& nums4) {
        unordered_map<int, int> sumCount;
        // Create all possible sums of pairs from nums1 and nums2
        for (int num1 : nums1) {
            for (int num2 : nums2) {
                ++sumCount[num1 + num2];
            }
        }

        int count = 0;
        // For each pair from nums3 and nums4, look for the complement in the unordered_map
        for (int num3 : nums3) {
            for (int num4 : nums4) {
                count += sumCount[-(num3 + num4)];
            }
        }
        return count;
    }
};

