#include <unordered_map>
#include <list>
using namespace std;

class LFUCache {
    int capacity, minFreq;
    // Map key to {value, frequency}
    unordered_map<int, pair<int,int>> keyToValFreq;
    // Map frequency to list of keys to maintain LRU order within the same frequency.
    unordered_map<int, list<int>> freqToList;
    // Map key to its iterator in the corresponding list.
    unordered_map<int, list<int>::iterator> keyToIter;
public:
    LFUCache(int capacity) {
        this->capacity = capacity;
        minFreq = 0;
    }

    int get(int key) {
        // Return -1 if key not present.
        if(keyToValFreq.find(key) == keyToValFreq.end()) return -1;

        int currFreq = keyToValFreq[key].second;
        int value = keyToValFreq[key].first;
        // Remove the key from its current frequency list.
        freqToList[currFreq].erase(keyToIter[key]);

        // If the list becomes empty, update minFreq.
        if(freqToList[currFreq].empty()){
            freqToList.erase(currFreq);
            if(minFreq == currFreq)
                minFreq++;
        }

        int newFreq = currFreq + 1;
        // Insert key into the new frequency list.
        freqToList[newFreq].push_back(key);
        keyToIter[key] = --freqToList[newFreq].end();
        // Update the frequency mapping.
        keyToValFreq[key].second = newFreq;
        return value;
    }

    void put(int key, int value) {
        if(capacity <= 0) return;

        if(keyToValFreq.find(key) != keyToValFreq.end()){
            // If key exists, update its value and frequency.
            keyToValFreq[key].first = value;
            get(key);
            return;
        }

        // If cache is full, evict the LFU and LRU key.
        if(keyToValFreq.size() == capacity){
            int keyToRemove = freqToList[minFreq].front();
            freqToList[minFreq].pop_front();
            if(freqToList[minFreq].empty()){
                freqToList.erase(minFreq);
            }
            keyToValFreq.erase(keyToRemove);
            keyToIter.erase(keyToRemove);
        }
        // Insert new key with initial frequency 1.
        keyToValFreq[key] = {value, 1};
        freqToList[1].push_back(key);
        keyToIter[key] = --freqToList[1].end();
        minFreq = 1; // Reset minFreq.
    }
};

