// C++ solution for Island Perimeter
#include <vector>
using namespace std;

class Solution {
public:
    int islandPerimeter(vector<vector<int>>& grid) {
        int perimeter = 0;
        int rows = grid.size();
        int cols = grid[0].size();

        // Iterate through each cell in the grid
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                // Only process if the current cell is land
                if (grid[i][j] == 1) {
                    int cellPerimeter = 4;  // Each land cell contributes 4 initially

                    // Check the upper neighbor
                    if (i > 0 && grid[i - 1][j] == 1)
                        cellPerimeter--;
                    // Check the lower neighbor
                    if (i < rows - 1 && grid[i + 1][j] == 1)
                        cellPerimeter--;
                    // Check the left neighbor
                    if (j > 0 && grid[i][j - 1] == 1)
                        cellPerimeter--;
                    // Check the right neighbor
                    if (j < cols - 1 && grid[i][j + 1] == 1)
                        cellPerimeter--;

                    perimeter += cellPerimeter;
                }
            }
        }
        return perimeter;
    }
};

