    vector<int> stack;  // Stack to help reverse sequences for 'D'
    // Iterate through indices from 0 to s.size() inclusive
    for (int i = 0; i <= s.size(); i++) {
        // Push the current number (i+1)
        stack.push_back(i + 1);
        // When end of string or current character is 'I', flush the stack.
        if (i == s.size() || s[i] == 'I') {
            while (!stack.empty()) {
                result.push_back(stack.back());
                stack.pop_back();
            }
        }
    }
    return result;
}

// Main function to test the solution
int main(){
    string s = "DI"; // Example input
    vector<int> permutation = findPermutation(s);
    // Print the resulting permutation
    for (int num : permutation) {
        cout << num << " ";
    }
    return 0;
}

