// C++ solution using the sliding window technique
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    int findMaxConsecutiveOnes(vector<int>& nums) {
        int maxLength = 0;  // Maximum consecutive ones length
        int left = 0;       // Left pointer for the window
        int zeroCount = 0;  // Count of zeros in the current window

        // Iterate with the right pointer
        for (int right = 0; right < nums.size(); right++) {
            if (nums[right] == 0)
                zeroCount++;  // Increase zero count if element is zero

            // Contract the window from the left if there are more than one zero
            while (zeroCount > 1) {
                if (nums[left] == 0)
                    zeroCount--;
                left++;
            }
            // Update the maximum window length
            maxLength = max(maxLength, right - left + 1);
        }
        return maxLength;
    }
};

