#include <vector>
#include <queue>
using namespace std;

class Solution {
public:
    bool hasPath(vector<vector<int>>& maze, vector<int>& start, vector<int>& destination) {
        int rows = maze.size(), cols = maze[0].size();
        // Create a 2D visited array initialized to false
        vector<vector<bool>> visited(rows, vector<bool>(cols, false));
        queue<pair<int, int>> q;
        q.push({start[0], start[1]});
        visited[start[0]][start[1]] = true;

        // Define directions for up, down, left, and right
        vector<pair<int, int>> directions = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};

        // Process the queue using BFS
        while (!q.empty()) {
            auto [curX, curY] = q.front();
            q.pop();
            // Check if destination is reached
            if (curX == destination[0] && curY == destination[1]) {
                return true;
            }
            // Try all four possible directions
            for (auto dir : directions) {
                int nextX = curX, nextY = curY;
                // Roll the ball until it hits a wall or boundary
                while (nextX + dir.first >= 0 && nextX + dir.first < rows &&
                       nextY + dir.second >= 0 && nextY + dir.second < cols &&
                       maze[nextX + dir.first][nextY + dir.second] == 0) {
                    nextX += dir.first;
                    nextY += dir.second;
                }
                // If the stopping point is not visited, mark and add to the queue
                if (!visited[nextX][nextY]) {
                    visited[nextX][nextY] = true;
                    q.push({nextX, nextY});
                }
            }
        }
        return false;
    }
};

