/*
Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode() : val(0), left(nullptr), right(nullptr) {}
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
};
*/
class Solution {
public:
    vector<int> findMode(TreeNode* root) {
        vector<int> modes;
        int currentCount = 0, maxCount = 0;
        TreeNode* prev = nullptr;

        // First pass: in-order traversal to compute maxCount.
        function<void(TreeNode*)> inorderFirst = [&](TreeNode* node) {
            if (!node)
                return;
            inorderFirst(node->left);
            // If current node's value differs from previous, reset count.
            if (prev == nullptr || node->val != prev->val)
                currentCount = 1;
            else
                currentCount++;
            prev = node;
            maxCount = max(maxCount, currentCount);
            inorderFirst(node->right);
        };

        inorderFirst(root);

        // Second pass: in-order traversal to collect nodes with frequency equal to maxCount.
        prev = nullptr;
        currentCount = 0;
        function<void(TreeNode*)> inorderSecond = [&](TreeNode* node) {
            if (!node)
                return;
            inorderSecond(node->left);
            if (prev == nullptr || node->val != prev->val)
                currentCount = 1;
            else
                currentCount++;
            prev = node;
            if (currentCount == maxCount)
                modes.push_back(node->val);
            inorderSecond(node->right);
        };

        inorderSecond(root);
        return modes;
    }
};

