int shortestDistance(vector<vector<int>>& maze, vector<int>& start, vector<int>& destination) {
    int m = maze.size(), n = maze[0].size();
    // Initialize distance matrix with maximum integer values
    vector<vector<int>> dist(m, vector<int>(n, INT_MAX));
    dist[start[0]][start[1]] = 0;
    // min-heap: each element is {distance, row, col}
    priority_queue<vector<int>, vector<vector<int>>, greater<vector<int>>> heap;
    heap.push({0, start[0], start[1]});
    vector<vector<int>> directions = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};

    while (!heap.empty()) {
        auto curr = heap.top();
        heap.pop();
        int d = curr[0], row = curr[1], col = curr[2];
        if (row == destination[0] && col == destination[1])
            return d;
        if (d > dist[row][col])
            continue;
        for (auto dir : directions) {
            int nextRow = row, nextCol = col, count = 0;
            // Roll the ball until a wall is reached
            while (nextRow + dir[0] >= 0 && nextRow + dir[0] < m &&
                   nextCol + dir[1] >= 0 && nextCol + dir[1] < n &&
                   maze[nextRow + dir[0]][nextCol + dir[1]] == 0) {
                nextRow += dir[0];
                nextCol += dir[1];
                count++;
            }
            if (d + count < dist[nextRow][nextCol]) {
                dist[nextRow][nextCol] = d + count;
                heap.push({dist[nextRow][nextCol], nextRow, nextCol});
            }
        }
    }
    return -1;
}

