// Include necessary libraries and setup the solution function
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
using namespace std;

int longestPalindromicSubseq(string s) {
    int n = s.size();
    // Create a 2D DP table of size n x n, initialized to 0.
    vector<vector<int>> dp(n, vector<int>(n, 0));

    // Base case: every single character is a palindrome of length 1.
    for (int i = 0; i < n; i++) {
        dp[i][i] = 1;
    }

    // Build the table for all substring lengths starting from 2.
    for (int subLen = 2; subLen <= n; subLen++) {
        for (int i = 0; i <= n - subLen; i++) {
            int j = i + subLen - 1;  // Calculate the end index of the substring.
            if (s[i] == s[j]) {
                // Characters match; add 2 to the inner substring result.
                dp[i][j] = 2 + (subLen > 2 ? dp[i+1][j-1] : 0);
            } else {
                // Characters do not match, get the maximum result from either substring.
                dp[i][j] = max(dp[i+1][j], dp[i][j-1]);
            }
        }
    }
    // dp[0][n-1] is the result for the full string.
    return dp[0][n-1];
}

int main() {
    string s = "bbbab";
    cout << longestPalindromicSubseq(s) << endl;  // Expected output: 4
    return 0;
}

