    // Constructor: build prefix sum array from weights.
    Solution(vector<int>& w) {
        totalSum = 0;
        for (int weight : w) {
            totalSum += weight;
            prefixSums.push_back(totalSum);
        }
        // Seed the random number generator.
        srand(time(NULL));
