// C++ solution to find the number of lonely black pixels in a picture.
#include <iostream>
#include <vector>
using namespace std;

int findLonelyPixel(vector<vector<char>>& picture) {
    int rows = picture.size();
    int cols = picture[0].size();

    // Create vectors to count black pixels in each row and column.
    vector<int> rowCount(rows, 0);
    vector<int> colCount(cols, 0);

    // First pass: Count the 'B's in each row and column.
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            if (picture[i][j] == 'B') {
                rowCount[i]++;
                colCount[j]++;
            }
        }
    }

    // Second pass: Count lonely black pixels.
    int lonelyPixels = 0;
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            if (picture[i][j] == 'B' && rowCount[i] == 1 && colCount[j] == 1) {
                lonelyPixels++;
            }
        }
    }

    return lonelyPixels;
}

// Example test
