// Include necessary libraries
#include <vector>
#include <queue>
using namespace std;

class Solution {
public:
    vector<vector<int>> updateMatrix(vector<vector<int>>& mat) {
        int rows = mat.size();
        int cols = mat[0].size();
        queue<pair<int, int>> bfsQueue;

        // Mark the cells; enqueue 0s and mark 1s as unvisited (-1)
        for (int r = 0; r < rows; ++r) {
            for (int c = 0; c < cols; ++c) {
                // If cell is 0, add to BFS queue
                if (mat[r][c] == 0) {
                    bfsQueue.push({r, c});
                } else {
                    // Mark 1 as unvisited
                    mat[r][c] = -1;
                }
            }
        }

        // Directions for neighbor cells: up, down, left, right
        vector<pair<int, int>> directions = {{1,0}, {-1,0}, {0,1}, {0,-1}};

        while (!bfsQueue.empty()) {
            auto [r, c] = bfsQueue.front();
            bfsQueue.pop();
            // Explore each neighbor cell
            for (auto& dir : directions) {
                int nr = r + dir.first;
                int nc = c + dir.second;
                // Check boundaries and if the neighbor is unvisited
                if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && mat[nr][nc] == -1) {
                    // Update neighbor distance and add it to the queue
                    mat[nr][nc] = mat[r][c] + 1;
                    bfsQueue.push({nr, nc});
                }
            }
        }
        return mat;
    }
};

