        auto isLeaf = [&](TreeNode* node) {
            return !node->left && !node->right;
        };

        // Add left boundary (excluding leaves).
        auto addLeftBoundary = [&](TreeNode* node, vector<int>& b) {
            while (node) {
                if (!isLeaf(node))
                    b.push_back(node->val);
                // Prefer left, else use right.
                if (node->left)
                    node = node->left;
                else
                    node = node->right;
            }
        };

        // Add leaves using DFS.
        function<void(TreeNode*)> addLeaves = [&](TreeNode* node) {
            if (!node) return;
            if (isLeaf(node)) {
                boundary.push_back(node->val);
                return;
            }
            addLeaves(node->left);
            addLeaves(node->right);
        };

        // Add right boundary (excluding leaves) in reverse order.
        auto addRightBoundary = [&](TreeNode* node, vector<int>& b) {
            vector<int> tmp;
            while (node) {
                if (!isLeaf(node))
                    tmp.push_back(node->val);
                if (node->right)
                    node = node->right;
                else
                    node = node->left;
            }
            // Append in reverse order.
            for (int i = tmp.size()-1; i >= 0; i--) {
                b.push_back(tmp[i]);
            }
        };

        if (!isLeaf(root))
            boundary.push_back(root->val); // Add root

        addLeftBoundary(root->left, boundary);
        addLeaves(root, boundary);
        addRightBoundary(root->right, boundary);

        return boundary;
    }
};

