};

class Solution {
public:
    int maxLength = 0;

    // Returns a pair: first -> increasing, second -> decreasing
    pair<int, int> dfs(TreeNode* node) {
        if (!node) return {0, 0};

        int inc = 1, dec = 1;  // Path including only the current node

        // Process left child
        if (node->left) {
            auto leftPair = dfs(node->left);
            if (node->left->val == node->val + 1) {
                inc = max(inc, leftPair.first + 1);
            } else if (node->left->val == node->val - 1) {
                dec = max(dec, leftPair.second + 1);
            }
        }

        // Process right child
        if (node->right) {
            auto rightPair = dfs(node->right);
            if (node->right->val == node->val + 1) {
                inc = max(inc, rightPair.first + 1);
            } else if (node->right->val == node->val - 1) {
                dec = max(dec, rightPair.second + 1);
            }
        }

        // Combine paths through current node
        maxLength = max(maxLength, inc + dec - 1);
        return {inc, dec};
    }

    int longestConsecutive(TreeNode* root) {
        dfs(root);
        return maxLength;
    }
};

