// Function to calculate the number of subarrays that sum to k
int subarraySum(vector<int>& nums, int k) {
    // Unordered map to keep track of the frequency of prefix sums
    unordered_map<int, int> prefixCounts;
    prefixCounts[0] = 1;  // Initialize with prefix sum 0
    int currentSum = 0;   // Running sum initialization
    int count = 0;        // Counter for valid subarrays
    // Iterate through each number in the array
    for (int num : nums) {
        currentSum += num;  // Update running sum
        // If (currentSum - k) is present, it indicates valid subarrays ending at current index
        if (prefixCounts.find(currentSum - k) != prefixCounts.end()) {
            count += prefixCounts[currentSum - k];
        }
        // Increment the frequency of currentSum
        prefixCounts[currentSum]++;
    }
    return count;
}

int main() {
    // Example usage
    vector<int> nums = {1, 1, 1};
    int k = 2;
    cout << subarraySum(nums, k) << endl;  // Expected output: 2
    return 0;
}

