// Function to reshape the matrix using C++
#include <vector>
using namespace std;

class Solution {
public:
    vector<vector<int>> matrixReshape(vector<vector<int>>& mat, int r, int c) {
        int m = mat.size();
        int n = mat[0].size();
        // Check if reshaping is possible
        if(m * n != r * c) {
            return mat;
        }

        // Flatten the matrix
        vector<int> flat;
        for(int i = 0; i < m; i++) {
            for(int j = 0; j < n; j++) {
                flat.push_back(mat[i][j]);
            }
        }

        // Build the new reshaped matrix
        vector<vector<int>> reshaped;
        for(int i = 0; i < flat.size(); i += c) {
            vector<int> row(flat.begin() + i, flat.begin() + i + c);
            reshaped.push_back(row);
        }
        return reshaped;
    }
};

