#include <iostream>
#include <vector>
using namespace std;
const int MOD = 1e9 + 7;

class Solution {
public:
    int findPaths(int m, int n, int maxMove, int startRow, int startColumn) {
        // 3D dp array: dp[move][i][j]
        vector<vector<vector<int>>> dp(maxMove + 1, vector<vector<int>>(m, vector<int>(n, 0)));
        int count = 0;

        // Loop over moves from 1 to maxMove.
        for (int move = 1; move <= maxMove; move++) {
            // Temporary 2D dp for current move calculation
            vector<vector<int>> temp(m, vector<int>(n, 0));
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    // Four possible directions from (i, j)
                    int up    = (i == 0) ? 1 : dp[move - 1][i - 1][j];
                    int down  = (i == m - 1) ? 1 : dp[move - 1][i + 1][j];
                    int left  = (j == 0) ? 1 : dp[move - 1][i][j - 1];
                    int right = (j == n - 1)? 1 : dp[move - 1][i][j + 1];
                    temp[i][j] = ((up + down) % MOD + (left + right) % MOD) % MOD;
                }
            }
            dp[move] = temp;
            // Accumulate result from the start position for each move count.
            count = (count + dp[move][startRow][startColumn]) % MOD;
        }
        return count;
    }
};

// Example usage:
int main() {
    Solution sol;
    cout << sol.findPaths(2, 2, 2, 0, 0) << endl; // Expected output: 6
    return 0;
}

