    result.push_back(kill);
    // Recursively call DFS on each child
    if (tree.find(kill) != tree.end()) {
        for (int child : tree[kill]) {
            dfs(child, tree, result);
        }
    }
}

vector<int> killProcess(vector<int>& pid, vector<int>& ppid, int kill) {
    // Build a mapping from parent process id to list of child process ids
    unordered_map<int, vector<int>> tree;
    int n = pid.size();
    for (int i = 0; i < n; i++) {
        tree[ppid[i]].push_back(pid[i]);
    }

    vector<int> result;
    dfs(kill, tree, result);
    return result;
}

// Example usage:
// pid = [1,3,10,5]
// ppid = [3,0,5,3]
// kill = 5
// Expected output: [5,10]

