#include <string>
#include <map>
#include <vector>
#include <sstream>
#include <algorithm>
using namespace std;

class Node {
public:
    bool isFile;
    string content;
    map<string, Node*> children;

    Node() : isFile(false) {}
};

class FileSystem {
private:
    Node* root;

    // Helper function to split the path by '/'
    vector<string> split(const string& path) {
        vector<string> parts;
        stringstream ss(path);
        string item;
        while(getline(ss, item, '/')) {
            if (!item.empty()) {
                parts.push_back(item);
            }
        }
        return parts;
    }

public:
    FileSystem() {
        root = new Node();
    }

    // ls function: returns sorted names of directory entries or file name if path is a file
    vector<string> ls(string path) {
        Node* node = root;
        vector<string> parts = split(path);
        for (auto &part : parts) {
            node = node->children[part];
        }
        if (node->isFile) {
            return { parts.back() };
        }
        vector<string> res;
        for (auto &p : node->children) {
            res.push_back(p.first);
        }
        sort(res.begin(), res.end());
        return res;
    }

    // mkdir creates all directories in the given path if they do not exist
    void mkdir(string path) {
        Node* node = root;
        vector<string> parts = split(path);
        for (auto &part : parts) {
            if (node->children.find(part) == node->children.end()) {
                node->children[part] = new Node();
            }
            node = node->children[part];
        }
    }

    // addContentToFile appends content to file or creates a new file with the content if not exists
    void addContentToFile(string filePath, string content) {
        Node* node = root;
        vector<string> parts = split(filePath);
        for (auto &part : parts) {
            if (node->children.find(part) == node->children.end()) {
                node->children[part] = new Node();
            }
            node = node->children[part];
        }
        node->isFile = true;
        node->content += content;
    }

    // readContentFromFile returns the content of the file specified by filePath
    string readContentFromFile(string filePath) {
        Node* node = root;
        vector<string> parts = split(filePath);
        for (auto &part : parts) {
            node = node->children[part];
        }
        return node->content;
    }
};

