#include <iostream>
#include <vector>
#include <string>
using namespace std;

string addBoldTag(string s, vector<string>& words) {
    int n = s.size();
    // Boolean vector to mark bold positions
    vector<bool> bold(n, false);

    // Mark every occurrence of each word in the input string
    for (const string& word : words) {
        size_t pos = s.find(word);
        while (pos != string::npos) {
            // Mark the interval as bold
            for (int i = pos; i < pos + word.size(); i++) {
                bold[i] = true;
            }
            pos = s.find(word, pos + 1);
        }
    }

    // Build the final string with <b> and </b> tags
    string result;
    int i = 0;
    while (i < n) {
        if (!bold[i]) {
            result.push_back(s[i]);
            i++;
        } else {
            result.append("<b>");
            while (i < n && bold[i]) {
                result.push_back(s[i]);
                i++;
            }
            result.append("</b>");
        }
    }
    return result;
}

