#include <vector>
#include <queue>
#include <limits>
#include <iostream>
using namespace std;

struct Element {
    int value;
    int listIndex;
    int elementIndex;
    // Custom comparator for the min-heap
    bool operator>(const Element &other) const {
        return value > other.value;
    }
};

vector<int> smallestRange(vector<vector<int>>& nums) {
    int k = nums.size();
    int currentMax = numeric_limits<int>::min();
    priority_queue<Element, vector<Element>, greater<Element>> minHeap;

    // Add the first element from each list to the heap
    for (int i = 0; i < k; i++) {
        int val = nums[i][0];
        minHeap.push({val, i, 0});
        currentMax = max(currentMax, val);
    }

    vector<int> bestRange = {numeric_limits<int>::min(), numeric_limits<int>::max()};

    while (true) {
        Element currentMin = minHeap.top();
        minHeap.pop();

        // Update the best range if a smaller one is found
        if (currentMax - currentMin.value < bestRange[1] - bestRange[0] ||
           (currentMax - currentMin.value == bestRange[1] - bestRange[0] && currentMin.value < bestRange[0])) {
            bestRange[0] = currentMin.value;
            bestRange[1] = currentMax;
        }

        // If no more elements in the current list, break out
        if (currentMin.elementIndex + 1 == nums[currentMin.listIndex].size()) {
            break;
        }

        int nextVal = nums[currentMin.listIndex][currentMin.elementIndex + 1];
        minHeap.push({nextVal, currentMin.listIndex, currentMin.elementIndex + 1});
        currentMax = max(currentMax, nextVal);
    }

    return bestRange;
}

// Example usage:
int main() {
    vector<vector<int>> nums = {{4,10,15,24,26}, {0,9,12,20}, {5,18,22,30}};
    vector<int> result = smallestRange(nums);
    cout << "[" << result[0] << ", " << result[1] << "]" << endl;
    return 0;
}

