    vector<int> retrieve(string start, string end, string granularity) {
        // Map granularity to the appropriate substring length.
        int idx;
        if(granularity == "Year") {
            idx = 4;
        } else if(granularity == "Month") {
            idx = 7;
        } else if(granularity == "Day") {
            idx = 10;
        } else if(granularity == "Hour") {
            idx = 13;
        } else if(granularity == "Minute") {
            idx = 16;
        } else {  // "Second"
            idx = 19;
        }

        string startSlice = start.substr(0, idx);
        string endSlice = end.substr(0, idx);
        vector<int> result;
        // Check each log entry's timestamp slice against the start and end slices
        for (auto &log : logs) {
            if (log.first.substr(0, idx) >= startSlice && log.first.substr(0, idx) <= endSlice) {
                result.push_back(log.second);
            }
        }
        return result;
    }
};

