#include <iostream>
#include <vector>
#include <unordered_map>
#include <string>
#include <algorithm>
using namespace std;

struct TrieNode {
    unordered_map<char, TrieNode*> children;
    // Map the sentence to its frequency count
    unordered_map<string, int> counts;
};

class AutocompleteSystem {
private:
    TrieNode* root;
    TrieNode* currentNode;
    string currentInput;
public:
    // Constructor: initializes Trie with given sentences and times
    AutocompleteSystem(vector<string>& sentences, vector<int>& times) {
        root = new TrieNode();
        currentNode = root;
        for (int i = 0; i < sentences.size(); i++) {
            addSentence(sentences[i], times[i]);
        }
    }

    // Method to add or update a sentence in the Trie
    void addSentence(const string &sentence, int freq) {
        TrieNode* node = root;
        for (char c : sentence) {
            if (node->children.find(c) == node->children.end())
                node->children[c] = new TrieNode();
            node = node->children[c];
            node->counts[sentence] += freq;
        }
    }

    // Processes input character by character and returns the top 3 suggestions
    vector<string> input(char c) {
        vector<string> results;
        if (c == '#') {
            addSentence(currentInput, 1);
            currentInput = "";
            currentNode = root;
            return results;
        }

        currentInput.push_back(c);
        if (currentNode) {
            currentNode = currentNode->children.count(c) ? currentNode->children[c] : nullptr;
        }
        if (!currentNode) return results;

        // Convert the map to vector pair and sort by frequency descending and then lexicographical order
        vector<pair<string, int>> items(currentNode->counts.begin(), currentNode->counts.end());
        sort(items.begin(), items.end(), [](const pair<string, int>& a, const pair<string, int>& b) {
            if (a.second == b.second)
                return a.first < b.first;
            return a.second > b.second;
        });

        for (int i = 0; i < min(3, (int)items.size()); i++) {
            results.push_back(items[i].first);
        }
        return results;
    }
};

