#include <queue>
#include <utility>
#include <algorithm>
using namespace std;

class Solution {
public:
    int widthOfBinaryTree(TreeNode* root) {
        if (!root) return 0;
        int maxWidth = 0;
        // Queue of pair: (node pointer, index)
        queue<pair<TreeNode*, unsigned long long>> q;
        q.push({root, 1});

        while(!q.empty()){
            int levelSize = q.size();
            // Record the starting index of this level
            unsigned long long levelStartIndex = q.front().second;
            unsigned long long levelEndIndex = q.back().second;
            // Update the maximum width
            maxWidth = max(maxWidth, (int)(levelEndIndex - levelStartIndex + 1));

            for(int i = 0; i < levelSize; i++){
                auto [node, index] = q.front();
                q.pop();
                // For left child, assign index 2 * index
                if(node->left) q.push({node->left, index * 2});
                // For right child, assign index 2 * index + 1
                if(node->right) q.push({node->right, index * 2 + 1});
            }
        }
        return maxWidth;
    }
};

