            int count = 0;
            for (int i = 1; i <= m; i++) {
                // For each row, count numbers that are <= x
                count += min(x / i, n);
            }
            return count;
        };

        int low = 1, high = m * n;
        while (low < high) {
            int mid = low + (high - low) / 2;
            if (countLessEqual(mid) >= k) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }
};

