// Include necessary headers
#include <iostream>
#include <vector>
#include <set>
#include <string>
#include <sstream>
#include <algorithm>
using namespace std;

class Solution {
public:
    void dfs(int r, int c, int origin_r, int origin_c, vector<vector<int>>& grid, vector<pair<int,int>>& shape) {
        int rows = grid.size();
        int cols = grid[0].size();
        // Check boundaries and if the cell is unvisited land
        if (r < 0 || c < 0 || r >= rows || c >= cols || grid[r][c] == 0)
            return;
        // Mark cell as visited
        grid[r][c] = 0;
        // Record the relative position
        shape.push_back({r - origin_r, c - origin_c});
        // Explore all 4 directions
        dfs(r + 1, c, origin_r, origin_c, grid, shape);
        dfs(r - 1, c, origin_r, origin_c, grid, shape);
        dfs(r, c + 1, origin_r, origin_c, grid, shape);
        dfs(r, c - 1, origin_r, origin_c, grid, shape);
    }

    int numDistinctIslands(vector<vector<int>>& grid) {
        int rows = grid.size();
        if(rows == 0) return 0;
        int cols = grid[0].size();
        // Set to store unique island shapes as strings
        set<string> distinctShapes;

        for(int i = 0; i < rows; i++){
            for(int j = 0; j < cols; j++){
                if(grid[i][j] == 1){
                    vector<pair<int,int>> shape;
                    dfs(i, j, i, j, grid, shape);
                    // Sort the shape to get a canonical representation
                    sort(shape.begin(), shape.end());
                    // Convert shape coordinates to a string signature
                    stringstream ss;
                    for(auto& p : shape){
                        ss << p.first << ":" << p.second << ",";
                    }
                    distinctShapes.insert(ss.str());
                }
            }
        }
        return distinctShapes.size();
    }
};

