// C++ solution using DFS to calculate maximum area of an island
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    int maxAreaOfIsland(vector<vector<int>>& grid) {
        int maxArea = 0;
        int rows = grid.size();
        int cols = rows ? grid[0].size() : 0;

        // Traverse each cell in the grid
        for (int i = 0; i < rows; ++i) {
            for (int j = 0; j < cols; ++j) {
                if (grid[i][j] == 1) {
                    // Update maxArea with the area calculated from current island
                    maxArea = max(maxArea, dfs(grid, i, j, rows, cols));
                }
            }
        }
        return maxArea;
    }

    // Helper DFS function that returns the area of an island
    int dfs(vector<vector<int>>& grid, int i, int j, int rows, int cols) {
        // Boundary and water check
        if (i < 0 || j < 0 || i >= rows || j >= cols || grid[i][j] == 0)
            return 0;
        // Mark the current cell as visited
        grid[i][j] = 0;
        int area = 1;  // Count current cell

        // Explore all four adjacent cells
        area += dfs(grid, i + 1, j, rows, cols);
        area += dfs(grid, i - 1, j, rows, cols);
        area += dfs(grid, i, j + 1, rows, cols);
        area += dfs(grid, i, j - 1, rows, cols);
        return area;
    }
};

