#include <vector>
#include <iostream>
using namespace std;

int search(const vector<int>& nums, int target) {
    // Set initial boundaries for the search
    int left = 0, right = nums.size() - 1;

    // Loop until the boundaries cross
    while (left <= right) {
        // Calculate middle index carefully to prevent overflow
        int mid = left + (right - left) / 2;

        // Check if the target is found
        if (nums[mid] == target)
            return mid;
        // If target is smaller than mid element, narrow search to left half
        else if (target < nums[mid])
            right = mid - 1;
        // Otherwise, narrow search to right half
        else
            left = mid + 1;
    }

    // Target not found, return -1
    return -1;
}

// Example usage
