// Node class for linked list in each bucket
class ListNode {
public:
    int key, value;
    ListNode* next;
    ListNode(int key, int value, ListNode* next = nullptr) : key(key), value(value), next(next) {}
};

class MyHashMap {
private:
    int size;                       // Total number of buckets
    vector<ListNode*> buckets;      // Array of bucket pointers

    int hash(int key) {
        // Hash function: modulus with bucket size
        return key % size;
    }
public:
    MyHashMap() {
        size = 1000;              // Set bucket size
        buckets.resize(size, nullptr);
    }

    void put(int key, int value) {
        int index = hash(key);
        if (buckets[index] == nullptr) {
            // Create new node if bucket is empty
            buckets[index] = new ListNode(key, value);
        } else {
            ListNode* current = buckets[index];
            while (true) {
                if (current->key == key) {
                    // Update value if key is found
                    current->value = value;
                    return;
                }
                if (current->next == nullptr) break;
                current = current->next;
            }
            // Append new node to the chain
            current->next = new ListNode(key, value);
        }
    }

    int get(int key) {
        int index = hash(key);
        ListNode* current = buckets[index];
        while (current != nullptr) {
            if (current->key == key)
                return current->value;
            current = current->next;
        }
        // Key not found; return -1
        return -1;
    }

    void remove(int key) {
        int index = hash(key);
        ListNode* current = buckets[index];
        if (current == nullptr) return;
        if (current->key == key) {
            // Remove head node
            buckets[index] = current->next;
            delete current;
            return;
        }
        ListNode* prev = current;
        current = current->next;
        while (current != nullptr) {
            if (current->key == key) {
                // Skip the node to remove it
                prev->next = current->next;
                delete current;
                return;
            }
            prev = current;
            current = current->next;
        }
    }
};

