using namespace std;

// Definition of a singly linked list node.
struct ListNode {
    int val;
    ListNode* next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class MyLinkedList {
private:
    int size;
    ListNode* head; // Dummy head node for simpler operations.
public:
    MyLinkedList() {
        size = 0;
        head = new ListNode(0);
    }

    int get(int index) {
        // If index is invalid, return -1.
        if (index < 0 || index >= size) return -1;
        ListNode* curr = head->next;
        // Traverse to the index'th node.
        for (int i = 0; i < index; i++) {
            curr = curr->next;
        }
        return curr->val;
    }

    void addAtHead(int val) {
        addAtIndex(0, val);
    }

    void addAtTail(int val) {
        addAtIndex(size, val);
    }

    void addAtIndex(int index, int val) {
        // Normalize negative index.
        if (index < 0) index = 0;
        if (index > size) return;
        size++;
        ListNode* pred = head;
        // Traverse to the node before insertion point.
        for (int i = 0; i < index; i++) {
            pred = pred->next;
        }
        ListNode* toAdd = new ListNode(val);
        toAdd->next = pred->next;
        pred->next = toAdd;
    }

    void deleteAtIndex(int index) {
        if (index < 0 || index >= size) return;
        size--;
        ListNode* pred = head;
        // Traverse to the predecessor node.
        for (int i = 0; i < index; i++) {
            pred = pred->next;
        }
        // Delete the node from the list.
        ListNode* toDelete = pred->next;
        pred->next = pred->next->next;
        delete toDelete;
    }
};

