// Definition for a Node.
class Node {
public:
    int val;
    Node* next;
    Node() : val(0), next(nullptr) {}
    Node(int _val) : val(_val), next(nullptr) {}
    Node(int _val, Node* _next) : val(_val), next(_next) {}
};

class Solution {
public:
    Node* insert(Node* head, int insertVal) {
        // If head is null, create a new node that points to itself.
        if (!head) {
            Node* newNode = new Node(insertVal);
            newNode->next = newNode;
            return newNode;
        }
        Node* curr = head;
        while (true) {
            // Case 1: Proper place: insertVal lies between curr and curr->next.
            if (curr->val <= insertVal && insertVal <= curr->next->val) {
                break;
            }
            // Case 2: At the pivot where the list wraps around.
            if (curr->val > curr->next->val) {
                if (insertVal >= curr->val || insertVal <= curr->next->val) {
                    break;
                }
            }
            curr = curr->next;
            // If we come full circle, break to insert the value.
            if (curr == head) break;
        }
        // Insert the new node.
        Node* newNode = new Node(insertVal, curr->next);
        curr->next = newNode;
        return head;
    }
};

