#include <vector>
#include <unordered_set>
#include <unordered_map>
#include <cstdlib>

using namespace std;

class Solution {
private:
    int W; // Total count of valid numbers
    unordered_map<int, int> mapping; // Mapping for blacklisted numbers in [0, W-1]
public:
    Solution(int n, vector<int>& blacklist) {
        // Compute the number of valid numbers
        W = n - blacklist.size();
        unordered_set<int> blacklistSet(blacklist.begin(), blacklist.end());

        int available = W;
        for (int b : blacklist) {
            if (b < W) {
                // Find the next available number that is not in the blacklist
                while (blacklistSet.count(available)) {
                    available++;
                }
                mapping[b] = available;
                available++;
            }
        }
    }

    int pick() {
        // Generate a random index in [0, W-1]
        int idx = rand() % W;
        // Return the mapped value if exists, else return idx
        if (mapping.count(idx)) {
            return mapping[idx];
        }
        return idx;
    }
};

