// C++ solution implementing the MaxStack data structure.
#include <set>
#include <list>
#include <unordered_map>
using namespace std;

class MaxStack {
public:
    // Each node stores the value.
    list<int> dll;
    // Multimap to hold value and iterator to list node.
    // We use a set of pair <value, iterator> ordered by value.
    // We need to differentiate nodes with same value; for that, the iterator works since list iterators are unique.
    set<pair<int, list<int>::iterator>> bst;
    // Mapping from list iterator to set iterator for fast removal.
    unordered_map<list<int>::iterator, set<pair<int, list<int>::iterator>>::iterator> nodeMap;

    MaxStack() {}

    void push(int x) {
        dll.push_back(x);
        auto it = prev(dll.end());
        // Insert into bst: (value, iterator)
        auto sit = bst.insert({x, it}).first;
        nodeMap[it] = sit;
    }

    int pop() {
        // Get last element in list
        auto it = prev(dll.end());
        int x = *it;
        // Remove from bst and map.
        bst.erase(nodeMap[it]);
        nodeMap.erase(it);
        dll.pop_back();
        return x;
    }

    int top() {
        return dll.back();
    }

    int peekMax() {
        // The maximum is the last element in the bst (largest value).
        return (*bst.rbegin()).first;
    }

    int popMax() {
        auto it = prev(bst.end());
        int maxVal = it->first;
        auto listIt = it->second;
        // Remove from list and auxiliary structures.
        bst.erase(it);
        nodeMap.erase(listIt);
        dll.erase(listIt);
        return maxVal;
    }
};

