// C++ solution for Longest Word in Dictionary
#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
using namespace std;

string longestWord(vector<string>& words) {
    // Sort words by length and lexicographical order
    sort(words.begin(), words.end(), [](const string &a, const string &b) {
        if(a.size() == b.size())
            return a < b;
        return a.size() < b.size();
    });

    set<string> validWords;
    string result = "";

    // Process each word
    for (const auto &word : words) {
        // If single character or the prefix exists, add to the valid set
        if (word.size() == 1 || validWords.count(word.substr(0, word.size() - 1))) {
            validWords.insert(word);
            // Update result if conditions are met
            if (word.size() > result.size() || (word.size() == result.size() && word < result)) {
                result = word;
            }
        }
    }

    return result;
}

