// C++ solution to Candy Crush simulation problem
#include <vector>
#include <cmath>
using namespace std;

class Solution {
public:
    vector<vector<int>> candyCrush(vector<vector<int>>& board) {
        int m = board.size(), n = board[0].size();
        bool crushFlag = true;

        while(crushFlag) {
            crushFlag = false;
            // Mark candies to crush by using negative values
            vector<vector<bool>> mark(m, vector<bool>(n, false));

            // Check horizontal groups
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n - 2; j++) {
                    int val = abs(board[i][j]);
                    if (val != 0 && abs(board[i][j+1]) == val && abs(board[i][j+2]) == val) {
                        mark[i][j] = mark[i][j+1] = mark[i][j+2] = true;
                        crushFlag = true;
                    }
                }
            }

            // Check vertical groups
            for (int i = 0; i < m - 2; i++) {
                for (int j = 0; j < n; j++) {
                    int val = abs(board[i][j]);
                    if (val != 0 && abs(board[i+1][j]) == val && abs(board[i+2][j]) == val) {
                        mark[i][j] = mark[i+1][j] = mark[i+2][j] = true;
                        crushFlag = true;
                    }
                }
            }

            // Crush marked candies
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    if (mark[i][j]) {
                        board[i][j] = 0;
                    }
                }
            }

            // Apply gravity per column
            for (int j = 0; j < n; j++) {
                int writeIndex = m - 1;
                for (int i = m - 1; i >= 0; i--) {
                    if (board[i][j] != 0) {
                        board[writeIndex][j] = board[i][j];
                        writeIndex--;
                    }
                }
                // Set remaining cells to 0
                for (int i = writeIndex; i >= 0; i--) {
                    board[i][j] = 0;
                }
            }
        }
        return board;
    }
};

