#include <vector>
using namespace std;

class Solution {
public:
    // Recursive DFS helper function to perform the flood fill
    void dfs(vector<vector<int>>& image, int r, int c, int origColor, int newColor) {
        // Check boundaries and whether current pixel matches the original color
        if (r < 0 || r >= image.size() || c < 0 || c >= image[0].size() || image[r][c] != origColor)
            return;
        // Update the pixel's color
        image[r][c] = newColor;
        // Recursively call DFS on all four adjacent directions
        dfs(image, r - 1, c, origColor, newColor); // up
        dfs(image, r + 1, c, origColor, newColor); // down
        dfs(image, r, c - 1, origColor, newColor); // left
        dfs(image, r, c + 1, origColor, newColor); // right
    }

    vector<vector<int>> floodFill(vector<vector<int>>& image, int sr, int sc, int color) {
        int origColor = image[sr][sc];
        // If the target color is the same as the original, return the image immediately
        if (origColor == color) return image;
        dfs(image, sr, sc, origColor, color);
        return image;
    }
};

