using namespace std;

// Function to simulate asteroid collisions
vector<int> asteroidCollision(vector<int>& asteroids) {
    vector<int> stack; // Stack to hold surviving asteroids
    // Iterate over each asteroid in the input vector
    for (int ast : asteroids) {
        bool exploded = false; // Flag to indicate if current asteroid has exploded
        // Process potential collisions while stack is not empty and a collision is possible
        while (!stack.empty() && ast < 0 && stack.back() > 0) {
            // If the current left-moving asteroid is larger than the right-moving one
            if (abs(ast) > abs(stack.back())) {
                stack.pop_back();  // Remove the smaller right-moving asteroid
                continue;  // Continue checking with next asteroid in stack
            } else if (abs(ast) == abs(stack.back())) {
                // If both asteroids are the same size, pop the stack and mark explosion
                stack.pop_back();
            }
            // Mark the current asteroid as exploded and break out of the loop
            exploded = true;
            break;
        }
        // If it did not explode, add the current asteroid to the stack
        if (!exploded) {
            stack.push_back(ast);
        }
    }
    return stack;  // The stack now represents the surviving asteroids
}

