#include <vector>
using namespace std;

class Solution {
public:
    vector<int> dailyTemperatures(vector<int>& temperatures) {
        int n = temperatures.size();
        // Initialize answer vector with zeros
        vector<int> answer(n, 0);
        // Stack to hold indices of unresolved temperatures
        vector<int> stack;

        // Iterate through each temperature by index
        for (int i = 0; i < n; i++) {
            // While stack is not empty and current temperature is greater than temperature at top index
            while (!stack.empty() && temperatures[i] > temperatures[stack.back()]) {
                int prevIndex = stack.back(); // Index of a day with a lower temperature
                stack.pop_back(); // Remove that index from stack
                answer[prevIndex] = i - prevIndex; // Calculate the wait duration
            }
            // Push current index onto the stack
            stack.push_back(i);
        }
        return answer;
    }
};

