#include <vector>
#include <unordered_map>
#include <deque>
using namespace std;

vector<int> anagramMappings(vector<int>& nums1, vector<int>& nums2) {
    // Map each number in nums2 to a deque of its indices
    unordered_map<int, deque<int>> indexMap;
    for (int i = 0; i < nums2.size(); i++) {
        indexMap[nums2[i]].push_back(i);
    }

    vector<int> mapping;
    // For each number in nums1, use the next available index from nums2.
    for (int num : nums1) {
        mapping.push_back(indexMap[num].front());
        indexMap[num].pop_front();
    }
    return mapping;
}

