#include <iostream>
#include <string>
#include <stack>
#include <cctype>
using namespace std;

class Solution {
public:
    int calculate(string s) {
        int index = 0;
        return helper(s, index);
    }

    // Helper function to process the expression from current index
    int helper(const string& s, int &index) {
        stack<int> stk;
        int num = 0;
        char sign = '+';
        for(; index < s.size(); index++){
            char c = s[index];
            // Build the current number if digit encountered
            if(isdigit(c)){
                num = num * 10 + (c - '0');
            }
            // If '(' is encountered, recursively evaluate the inner expression
            if(c == '('){
                index++; // Move past '('
                num = helper(s, index);
            }
            // Process obtained number when an operator or end of expression is reached
            if((!isdigit(c) && c != ' ') || index == s.size() - 1){
                if(sign == '+') {
                    stk.push(num);
                } else if(sign == '-'){
                    stk.push(-num);
                } else if(sign == '*'){
                    int prev = stk.top();
                    stk.pop();
                    stk.push(prev * num);
                } else if(sign == '/'){
                    int prev = stk.top();
                    stk.pop();
                    stk.push(prev / num); // Integer division truncates toward zero
                }
                sign = c;
                num = 0;
            }
            // End recursion when a closing parenthesis is encountered
            if(c == ')'){
                break;
            }
        }
        int sum = 0;
        while(!stk.empty()){
            sum += stk.top();
            stk.pop();
        }
        return sum;
    }
};

int main() {
    Solution sol;
    cout << sol.calculate("2*(5+5*2)/3+(6/2+8)") << endl;
    return 0;
}

