#include <iostream>
#include <queue>
#include <string>
#include <unordered_set>
#include <vector>
using namespace std;

int slidingPuzzle(vector<vector<int>>& board) {
    // Convert the board into a string.
    string start;
    for(auto &row : board)
        for(auto num : row)
            start += to_string(num);
    string goal = "123450";

    // Define neighbors for each position in the 2x3 board.
    vector<vector<int>> neighbors = {
        {1,3}, {0,2,4}, {1,5}, {0,4}, {1,3,5}, {2,4}
    };

    // Initialize BFS.
    queue<pair<string, int>> q;
    q.push({start, 0});
    unordered_set<string> visited;
    visited.insert(start);

    // Process each state.
    while(!q.empty()){
        auto [state, moves] = q.front();
        q.pop();
        if(state == goal)
            return moves;
        int zero_index = state.find('0');
        for(auto neighbor : neighbors[zero_index]){
            string new_state = state;
            swap(new_state[zero_index], new_state[neighbor]);
            if(visited.find(new_state) == visited.end()){
                visited.insert(new_state);
                q.push({new_state, moves + 1});
            }
        }
    }
    return -1;
}

int main(){
    vector<vector<int>> board = {{1,2,3}, {4,0,5}};
    cout << slidingPuzzle(board) << endl; // Expected output: 1
    return 0;
}

