// Using BFS to determine if graph is bipartite
#include <iostream>
#include <vector>
#include <queue>
using namespace std;

bool isBipartite(vector<vector<int>>& graph) {
    int n = graph.size();
    // -1 indicates that the node is uncolored
    vector<int> colors(n, -1);

    // Loop over every node to cover disconnected components
    for (int i = 0; i < n; ++i) {
        if (colors[i] == -1) {
            queue<int> q;
            q.push(i);
            colors[i] = 0; // assign initial color 0
            while (!q.empty()) {
                int node = q.front();
                q.pop();
                // Process adjacent nodes
                for (int neighbor : graph[node]) {
                    if (colors[neighbor] == -1) {
                        // Assign the alternate color
                        colors[neighbor] = 1 - colors[node];
                        q.push(neighbor);
                    } else if (colors[neighbor] == colors[node]) {
                        // Adjacent node has same color: conflict found
                        return false;
                    }
                }
            }
        }
    }
    return true;
}

int main() {
    vector<vector<int>> graph = {{1,3},{0,2},{1,3},{0,2}};
    cout << (isBipartite(graph) ? "true" : "false") << endl; // Expected output: true
    return 0;
}

