using namespace std;

int findCheapestPrice(int n, vector<vector<int>>& flights, int src, int dst, int k) {
    // Build graph as an adjacency list
    vector<vector<pair<int, int>>> graph(n);
    for (const auto& flight : flights) {
        int from = flight[0], to = flight[1], price = flight[2];
        graph[from].push_back({to, price});
    }

    // Priority queue: (total_cost, current_city, stops so far)
    typedef pair<int, pair<int, int>> Node;
    priority_queue<Node, vector<Node>, greater<Node>> minHeap;
    minHeap.push({0, {src, 0}});

    // Map to track the best cost to reach a given (city, stops)
    unordered_map<string, int> best;

    while (!minHeap.empty()) {
        auto [cost, info] = minHeap.top();
        auto [city, stops] = info;
        minHeap.pop();

        // If destination is reached, return the cost
        if (city == dst) return cost;

        // If stops exceed allowed k, skip further expansion
        if (stops > k) continue;

        // Explore neighboring cities
        for (auto [nextCity, price] : graph[city]) {
            int newCost = cost + price;
            string key = to_string(nextCity) + "-" + to_string(stops + 1);
            if (best.find(key) == best.end() || newCost < best[key]) {
                best[key] = newCost;
                minHeap.push({newCost, {nextCity, stops + 1}});
            }
        }
    }

    return -1;
}

