int numBusesToDestination(vector<vector<int>>& routes, int source, int target) {
    if (source == target)
        return 0;

    // Map each stop to buses that go through it.
    unordered_map<int, vector<int>> stopToBuses;
    for (int bus = 0; bus < routes.size(); bus++) {
        for (int stop : routes[bus]) {
            stopToBuses[stop].push_back(bus);
        }
    }

    vector<bool> visitedBuses(routes.size(), false);
    unordered_set<int> visitedStops;
    queue<pair<int, int>> q; // Pair: (bus index, buses taken)

    // Enqueue all buses available at the source.
    for (int bus : stopToBuses[source]) {
        visitedBuses[bus] = true;
        q.push({bus, 1});
    }
    visitedStops.insert(source);

    // BFS traversal.
    while (!q.empty()) {
        auto [bus, busesTaken] = q.front();
        q.pop();
        for (int stop : routes[bus]) {
            if (stop == target)
                return busesTaken;
            if (visitedStops.find(stop) == visitedStops.end()) {
                visitedStops.insert(stop);
                for (int neighborBus : stopToBuses[stop]) {
                    if (!visitedBuses[neighborBus]) {
                        visitedBuses[neighborBus] = true;
                        q.push({neighborBus, busesTaken + 1});
                    }
                }
            }
        }
    }
    return -1;
}

