        }

        // Compare the valid characters from both strings
        if (i >= 0 && j >= 0) {
            if (s[i] != t[j])
                return false;
        } else if (i >= 0 || j >= 0) {
            return false;
        }
        i--;
        j--;
    }
    return true;
}

