// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

#include <vector>
#include <unordered_map>
#include <unordered_set>
#include <queue>
using namespace std;

class Solution {
public:
    vector<int> distanceK(TreeNode* root, int target, int k) {
        // Build an adjacency list for the graph
        unordered_map<int, vector<int>> graph;
        buildGraph(root, nullptr, graph);

        // Use BFS to traverse from the target node.
        unordered_set<int> visited;
        queue<int> q;
        q.push(target);
        visited.insert(target);
        int currentDistance = 0;

        while (!q.empty()) {
            if (currentDistance == k) {
                vector<int> result;
                while (!q.empty()) {
                    result.push_back(q.front());
                    q.pop();
                }
                return result;
            }
            int size = q.size();
            for (int i = 0; i < size; i++) {
                int current = q.front();
                q.pop();
                for (int neighbor : graph[current]) {
                    if (visited.find(neighbor) == visited.end()) {
                        visited.insert(neighbor);
                        q.push(neighbor);
                    }
                }
            }
            currentDistance++;
        }

        return vector<int>();
    }

private:
    // DFS function to build the graph.
    void buildGraph(TreeNode* node, TreeNode* parent, unordered_map<int, vector<int>>& graph) {
        if (!node) return;
        if (parent) {
            graph[node->val].push_back(parent->val);
            graph[parent->val].push_back(node->val);
        }
        buildGraph(node->left, node, graph);
        buildGraph(node->right, node, graph);
    }
};

