#include <iostream>
#include <vector>
using namespace std;

vector<vector<int>> transpose(const vector<vector<int>>& matrix) {
    // Number of rows in the original matrix
    int numRows = matrix.size();
    // Number of columns in the original matrix
    int numCols = matrix[0].size();

    // Create a new matrix with dimensions: numCols x numRows
    vector<vector<int>> transposed(numCols, vector<int>(numRows, 0));

    // Iterate over the original matrix to fill in the transposed matrix
    for (int i = 0; i < numRows; i++) {
        for (int j = 0; j < numCols; j++) {
            // Swap index positions
            transposed[j][i] = matrix[i][j];
        }
    }
    return transposed;
}

int main() {
    vector<vector<int>> matrix = { {1, 2, 3}, {4, 5, 6} };
    vector<vector<int>> result = transpose(matrix);

    // Print the transposed matrix
    for (const auto &row : result) {
        for (const auto &val : row) {
            cout << val << " ";
        }
        cout << endl;
    }
    return 0;
}

