const int MOD = 1e9 + 7;

int threeSumMulti(vector<int>& arr, int target) {
    vector<long long> freq(101, 0);
    // Fill frequency array for numbers 0 to 100
    for (int num : arr) {
        freq[num]++;
    }
    long long count = 0;
    // Iterate through all candidate values for x, y, and calculate z
    for (int x = 0; x <= 100; x++) {
        if (freq[x] == 0) continue;
        for (int y = x; y <= 100; y++) {
            if (freq[y] == 0) continue;
            int z = target - x - y;
            if (z < 0 || z > 100 || freq[z] == 0) continue;
            if (x == y && y == z) {
                // All three numbers are the same: use nC3
                count = (count + freq[x] * (freq[x] - 1) * (freq[x] - 2) / 6) % MOD;
            } else if (x == y && y != z) {
                // Two numbers (x, y) are the same: use nC2 for x times count[z]
                count = (count + (freq[x] * (freq[x] - 1) / 2 * freq[z])) % MOD;
            } else if (x < y && y < z) {
                // Distinct elements: simple product of frequencies
                count = (count + freq[x] * freq[y] * freq[z]) % MOD;
            } else if (x < y && y == z) {
                // x is distinct and y and z are the same: count[x] * nC2 for y
                count = (count + freq[x] * (freq[y] * (freq[y] - 1) / 2)) % MOD;
            }
        }
    }
    return count;
}

