// Function to determine if the array can be reordered into valid doubled pairs
bool canReorderDoubled(vector<int>& arr) {
    // Create a frequency map using unordered_map
    unordered_map<int, int> count;
    for (int num : arr) {
        count[num]++;
    }
    // Sort the array based on absolute value
    sort(arr.begin(), arr.end(), [](int a, int b) {
        return abs(a) < abs(b);
    });
    // Iterate through the sorted array and attempt pairing
    for (int x : arr) {
        if (count[x] == 0) continue; // Already paired
        // If there are not enough occurrences of 2*x, pairing fails
        if (count[2 * x] < count[x]) return false;
        // Reduce the frequency for the double of x
        count[2 * x] -= count[x];
    }
    return true;
}

// Example usage:
int main() {
    vector<int> arr = {4, -2, 2, -4};
    cout << (canReorderDoubled(arr) ? "True" : "False") << endl;  // Expected Output: True
    return 0;
}

