// C++ solution for Maximum Width Ramp

#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    int maxWidthRamp(vector<int>& nums) {
        int n = nums.size();
        vector<int> stack;
        // Build a decreasing stack of indices
        for (int i = 0; i < n; i++) {
            if (stack.empty() || nums[i] < nums[stack.back()]) {
                stack.push_back(i);
            }
        }
        int maxWidth = 0;
        // Traverse from the end of the array backwards to find the maximum ramp
        for (int j = n - 1; j >= 0; j--) {
            while (!stack.empty() && nums[j] >= nums[stack.back()]) {
                maxWidth = max(maxWidth, j - stack.back());
                stack.pop_back();
            }
        }
        return maxWidth;
    }
};

