// Function to return squares of a sorted array in non-decreasing order.
#include <vector>
#include <cmath>
using namespace std;

vector<int> sortedSquares(vector<int>& nums) {
    int left = 0;
    int right = nums.size() - 1;
    // Create a result vector with the same length as nums.
    vector<int> result(nums.size());
    int position = nums.size() - 1;

    // Process until the two pointers cross.
    while (left <= right) {
        // Compare absolute values at the pointers.
        if (abs(nums[left]) > abs(nums[right])) {
            result[position] = nums[left] * nums[left];
            left++;  // Move left pointer forward.
        } else {
            result[position] = nums[right] * nums[right];
            right--; // Move right pointer backward.
        }
        position--; // Update the insertion position.
    }
    return result;
}

