#include <unordered_map>
#include <vector>
#include <string>
using namespace std;

class TimeMap {
public:
    // Hash table mapping keys to a vector of pairs of (timestamp, value)
    unordered_map<string, vector<pair<int, string>>> store;

    TimeMap() {
        // Constructor does not need to initialize anything extra.
    }

    void set(string key, string value, int timestamp) {
        // Append the new (timestamp, value) pair.
        store[key].push_back({timestamp, value});
    }

    string get(string key, int timestamp) {
        // If key does not exist, return empty string.
        if (store.find(key) == store.end())
            return "";

        const auto &values = store[key];
        int left = 0, right = values.size() - 1;

        // Binary search for the rightmost entry with timestamp <= query.
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (values[mid].first <= timestamp) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        // If no valid timestamp was found, return empty string.
        if (right < 0)
            return "";
        return values[right].second;
    }
};

