#include <vector>
#include <queue>
using namespace std;

class Solution {
public:
    int orangesRotting(vector<vector<int>>& grid) {
        int rows = grid.size();
        int cols = grid[0].size();
        int freshCount = 0;
        queue<pair<int,int>> rottenQueue;

        // Step 1: Find initial rotten oranges and fresh count.
        for (int r = 0; r < rows; r++) {
            for (int c = 0; c < cols; c++) {
                if (grid[r][c] == 2) {
                    rottenQueue.push({r, c});
                } else if (grid[r][c] == 1) {
                    freshCount++;
                }
            }
        }

        // If no fresh oranges, return 0.
        if (freshCount == 0) return 0;

        int minutesPassed = 0;
        // Directions for neighbors: up, down, left, right.
        vector<pair<int,int>> directions = {{-1,0}, {1,0}, {0,-1}, {0,1}};

        // Step 2: BFS to process each minute.
        while (!rottenQueue.empty()) {
            int currentLevelSize = rottenQueue.size();
            for (int i = 0; i < currentLevelSize; i++) {
                auto [x, y] = rottenQueue.front();
                rottenQueue.pop();
                for (auto& dir : directions) {
                    int nx = x + dir.first, ny = y + dir.second;
                    // Check if neighbor is within bounds and is a fresh orange.
                    if (nx >= 0 && nx < rows && ny >= 0 && ny < cols && grid[nx][ny] == 1) {
                        grid[nx][ny] = 2;     // Mark the orange as rotten.
                        freshCount--;         // Decrement fresh orange count.
                        rottenQueue.push({nx, ny}); // Add new rotten orange to the queue.
                    }
                }
            }
            minutesPassed++;
        }

        // If there are still fresh oranges, return -1.
        return freshCount == 0 ? minutesPassed - 1 : -1;
    }
};

