#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
#include <functional>
using namespace std;

// Function to check if a number is a perfect square
bool isPerfectSquare(int num) {
    int root = sqrt(num);
    return root * root == num;
}

int numSquarefulPerms(vector<int>& nums) {
    sort(nums.begin(), nums.end());  // Sort to manage duplicates
    int n = nums.size();
    vector<bool> visited(n, false);
    int result = 0;

    // Define the backtracking function using a lambda
    function<void(int, int)> dfs = [&](int lastIndex, int count) {
        if (count == n) {  // All numbers are used
            result++;
            return;
        }
        for (int i = 0; i < n; i++) {
            if (visited[i])
                continue;
            // Skip duplicates: if current is same as previous and previous is not used
            if (i > 0 && nums[i] == nums[i - 1] && !visited[i - 1])
                continue;
            if (lastIndex == -1 || isPerfectSquare(nums[lastIndex] + nums[i])) {
                visited[i] = true;
                dfs(i, count + 1);
                visited[i] = false; // Backtrack
            }
        }
    };

    dfs(-1, 0);
    return result;
}

int main(){
    vector<int> test1 = {1, 17, 8};
    vector<int> test2 = {2, 2, 2};
    cout << numSquarefulPerms(test1) << endl; // Expected output: 2
    cout << numSquarefulPerms(test2) << endl; // Expected output: 1
    return 0;
}

