// C++ solution for merging stones with detailed comments.
#include <vector>
#include <climits>
#include <algorithm>
using namespace std;
class Solution {
public:
    int mergeStones(vector<int>& stones, int k) {
        int n = stones.size();
        // Check if merging into one pile is possible.
        if ((n - 1) % (k - 1) != 0)
            return -1;

        // Precompute prefix sums.
        vector<int> prefix(n + 1, 0);
        for (int i = 0; i < n; i++)
            prefix[i + 1] = prefix[i] + stones[i];

        // dp[i][j] represents the minimum cost to merge stones[i...j].
        vector<vector<int>> dp(n, vector<int>(n, 0));

        // Iterate over segment lengths.
        for (int length = k; length <= n; length++) {
            for (int i = 0; i <= n - length; i++) {
                int j = i + length - 1;
                dp[i][j] = INT_MAX;
                // Try splitting the interval using valid partition boundaries.
                for (int mid = i; mid < j; mid += k - 1)
                    dp[i][j] = min(dp[i][j], dp[i][mid] + dp[mid + 1][j]);
                // If current segment can be merged to one pile, add total stones cost.
                if ((length - 1) % (k - 1) == 0)
                    dp[i][j] += prefix[j+1] - prefix[i];
            }
        }
        return dp[0][n-1];
    }
};

