// C++ solution for counting pairs of songs whose duration sums are divisible by 60
#include <vector>
using namespace std;

class Solution {
public:
    int numPairsDivisibleBy60(vector<int>& time) {
        // Array to store frequency of remainders from 0 to 59
        int remainderFreq[60] = {0};
        int pairCount = 0;

        // Iterate over all song durations
        for (int t : time) {
            // Compute the remainder of the current song duration
            int remainder = t % 60;
            // Compute the complement remainder
            int complement = (60 - remainder) % 60;
            // Increase pairCount by the number of times the complement has been seen
            pairCount += remainderFreq[complement];
            // Update the frequency for the current remainder
            remainderFreq[remainder]++;
        }

        return pairCount;
    }
};

