// C++ solution with detailed comments.
#include <iostream>
#include <string>
#include <algorithm>
using namespace std;

string baseNeg2(int n) {
    // Special case for zero.
    if (n == 0) return "0";

    string result = "";

    // Loop until n becomes zero.
    while (n != 0) {
        int remainder = n % -2;
        n /= -2;

        // Adjust if remainder is negative.
        if (remainder < 0) {
            remainder += 2;
            n += 1;
        }

        // Prepend the digit to the result string.
        result.push_back('0' + remainder);
    }

    // Result was constructed in reverse order, so reverse it.
    reverse(result.begin(), result.end());
    return result;
}

int main() {
    cout << baseNeg2(2) << endl; // Output: "110"
    cout << baseNeg2(3) << endl; // Output: "111"
    cout << baseNeg2(4) << endl; // Output: "100"
    return 0;
}

