#include <vector>
#include <queue>
#include <unordered_set>
#include <string>
using namespace std;

class Solution {
public:
    bool isEscapePossible(vector<vector<int>>& blocked, vector<int>& source, vector<int>& target) {
        int n = blocked.size();
        if (n < 2) return true;
        long long maxSteps = (long long)n * (n - 1) / 2;

        auto coordToStr = [&](int x, int y) {
            return to_string(x) + "," + to_string(y);
        };

        unordered_set<string> blockedSet;
        for (auto &b : blocked)
            blockedSet.insert(coordToStr(b[0], b[1]));

        auto bfs = [&](vector<int> start, vector<int> finish) {
            queue<pair<int, int>> q;
            unordered_set<string> seen;
            q.push({start[0], start[1]});
            seen.insert(coordToStr(start[0], start[1]));
            int steps = 0;
            vector<pair<int, int>> directions = {{0,1}, {1,0}, {0,-1}, {-1,0}};

            while (!q.empty()) {
                auto [x, y] = q.front();
                q.pop();
                if (x == finish[0] && y == finish[1])
                    return true;
                for (auto &d : directions) {
                    int nx = x + d.first, ny = y + d.second;
                    string key = coordToStr(nx, ny);
                    if (nx >= 0 && nx < 1000000 && ny >= 0 && ny < 1000000 &&
                        blockedSet.find(key) == blockedSet.end() &&
                        seen.find(key) == seen.end()) {
                        q.push({nx, ny});
                        seen.insert(key);
                        steps++;
                        if (steps > maxSteps)
                            return true;
                    }
                }
            }
            return false;
        };

        return bfs(source, target) && bfs(target, source);
    }
};

