class Solution {
public:
    int missingElement(vector<int>& nums, int k) {
        // Calculate the number of missing numbers until index i.
        auto missingCount = [&](int i) -> int {
            return nums[i] - nums[0] - i;
        };

        int n = nums.size();

        // If kth missing number is beyond the last element.
        if(k > missingCount(n - 1))
            return nums[n - 1] + k - missingCount(n - 1);

        // Binary search to find the smallest index where missingCount(i) >= k.
        int left = 0, right = n - 1;
        while(left < right) {
            int mid = left + (right - left) / 2;
            if(missingCount(mid) < k)
                left = mid + 1;
            else
                right = mid;
        }
        // Result is derived from the previous element.
        return nums[left - 1] + k - missingCount(left - 1);
    }
};

