#include <iostream>
#include <string>
#include <unordered_set>
using namespace std;

typedef unsigned long long ull;

int longestRepeatingSubstring(string s) {
    int n = s.size();
    // Lambda function to check if a repeating substring exists with length L.
    auto search = [&](int L) -> bool {
        ull h = 0;
        const ull a = 26;
        const ull mod = (1ULL << 32);
        for (int i = 0; i < L; i++) {
            h = (h * a + (s[i] - 'a')) % mod;
        }
        unordered_set<ull> seen;
        seen.insert(h);
        ull aL = 1;
        for (int i = 0; i < L; i++) {
            aL = (aL * a) % mod;
        }
        for (int start = 1; start <= n - L; start++) {
            h = (h * a - (s[start - 1] - 'a') * aL + (s[start + L - 1] - 'a')) % mod;
            if (h < 0) h += mod;  // Adjust if negative.
            if (seen.count(h)) return true;
            seen.insert(h);
        }
        return false;
    };

    int left = 1, right = n, ans = 0;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (search(mid)) {
            ans = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return ans;
}

int main(){
    string s = "aabcaabdaab";
    cout << longestRepeatingSubstring(s) << endl;  // Expected output: 3
    return 0;
}

