// C++ solution for counting number of submatrices that sum to target
#include <vector>
#include <unordered_map>
using namespace std;

class Solution {
public:
    int numSubmatrixSumTarget(vector<vector<int>>& matrix, int target) {
        int n = matrix.size();
        int m = matrix[0].size();
        int result = 0;

        // Consider every possible pair of rows as boundaries for the submatrix
        for (int top = 0; top < n; ++top) {
            vector<int> colSums(m, 0); // initialize column sums for each pair
            for (int bottom = top; bottom < n; ++bottom) {
                // Update column sums for the current bottom row
                for (int col = 0; col < m; ++col) {
                    colSums[col] += matrix[bottom][col];
                }

                // Use unordered_map to find the number of subarrays in colSums that sum to target
                unordered_map<int, int> sumCount;
                sumCount[0] = 1;
                int currSum = 0;
                for (int sum : colSums) {
                    currSum += sum;
                    if (sumCount.count(currSum - target)) {
                        result += sumCount[currSum - target];
                    }
                    sumCount[currSum]++;
                }
            }
        }
        return result;
    }
};

