    // Use an unordered_map to count frequency of each number
    unordered_map<int, int> frequency;
    for (int num : nums) {
        frequency[num]++;
    }

    // Initialize maximum unique number to -1
    int maxUnique = -1;

    // Iterate through the frequency map
    for (auto &entry : frequency) {
        // Check if the number appears exactly once and is greater than current maximum
        if (entry.second == 1 && entry.first > maxUnique) {
            maxUnique = entry.first;
        }
    }

