// C++ solution using sliding window with a frequency array for lowercase letters.
#include <string>
#include <vector>
using namespace std;

class Solution {
public:
    int numKLenSubstrNoRepeats(string s, int k) {
        int n = s.size();
        if (k > n) return 0;

        int count = 0;
        // Frequency array for 26 lowercase letters.
        vector<int> freq(26, 0);
        int left = 0;

        // Iterate through the string using right pointer.
        for (int right = 0; right < n; right++) {
            // Update frequency of current character.
            freq[s[right] - 'a']++;

            // If duplicate found, slide window until duplicate is removed.
            while (freq[s[right] - 'a'] > 1) {
                freq[s[left] - 'a']--;
                left++;
            }

            // When window size is k, count valid substring and slide window.
            if (right - left + 1 == k) {
                count++;
                freq[s[left] - 'a']--;
                left++;
            }
        }
        return count;
    }
};

