    // DFS function returns a pair: first is subtree sum, second is node count
    std::pair<double, int> dfs(TreeNode* node) {
        if (!node) {
            return {0.0, 0};  // base case: null node returns sum 0 and count 0
        }
        auto left = dfs(node->left);    // traverse left subtree
        auto right = dfs(node->right);  // traverse right subtree
        double currentSum = node->val + left.first + right.first; // cumulative sum
        int currentCount = 1 + left.second + right.second;          // cumulative count
        double currentAvg = currentSum / currentCount;              // average for current subtree
        maxAvg = std::max(maxAvg, currentAvg);                      // update global maximum average
        return {currentSum, currentCount};  // return results for parent's computation
    }

    double maximumAverageSubtree(TreeNode* root) {
        dfs(root);       // start DFS from root
        return maxAvg;   // return the maximum average found
    }
};

