#include <iostream>
#include <vector>
#include <unordered_map>
#include <algorithm>
using namespace std;

vector<int> relativeSortArray(vector<int>& arr1, vector<int>& arr2) {
    // Count frequency for each number in arr1
    unordered_map<int, int> count;
    for (int num : arr1) {
        count[num]++;
    }

    vector<int> result;
    // Process elements in arr2: append each element count times
    for (int num : arr2) {
        if (count.find(num) != count.end()) {
            int freq = count[num];
            for (int i = 0; i < freq; ++i) {
                result.push_back(num);
            }
            count.erase(num); // Remove from map after processing
        }
    }

    // Gather remaining numbers not in arr2
    vector<int> remaining;
    for (auto &entry : count) {
        int num = entry.first;
        int freq = entry.second;
        for (int i = 0; i < freq; ++i) {
            remaining.push_back(num);
        }
    }

    // Sort remaining numbers in ascending order
    sort(remaining.begin(), remaining.end());
    // Append sorted remaining numbers to result
    result.insert(result.end(), remaining.begin(), remaining.end());

    return result;
}

// Example usage:
int main() {
    vector<int> arr1 = {2,3,1,3,2,4,6,7,9,2,19};
    vector<int> arr2 = {2,1,4,3,9,6};
    vector<int> sortedArr = relativeSortArray(arr1, arr2);

    for (int num : sortedArr) {
        cout << num << " ";
    }
    return 0;
}

