/* C++ Implementation */

#include <iostream>
#include <vector>
#include <queue>
using namespace std;

int minimumSemesters(int numCourses, vector<vector<int>>& relations) {
    // Build graph and in-degree array.
    vector<vector<int>> graph(numCourses + 1);
    vector<int> inDegree(numCourses + 1, 0);

    // Construct graph from relations.
    for (const auto &rel : relations) {
        int pre = rel[0];
        int course = rel[1];
        graph[pre].push_back(course);
        inDegree[course]++;
    }

    queue<int> q;
    // Enqueue courses with no prerequisites.
    for (int i = 1; i <= numCourses; i++) {
        if (inDegree[i] == 0) {
            q.push(i);
        }
    }

    int semesters = 0, takenCourses = 0;

    // Process each semester level.
    while (!q.empty()) {
        int size = q.size();
        semesters++;
        for (int i = 0; i < size; i++) {
            int course = q.front();
            q.pop();
            takenCourses++;
            // Visit and update neighbors.
            for (int neighbor : graph[course]) {
                inDegree[neighbor]--;
                if (inDegree[neighbor] == 0) {
                    q.push(neighbor);
                }
            }
        }
    }

    return takenCourses == numCourses ? semesters : -1;
}

int main() {
    vector<vector<int>> relations = {{1, 3}, {2, 3}};
    cout << minimumSemesters(3, relations) << endl;  // Expected output: 2
    return 0;
}

