using namespace std;

class Solution {
public:
    string alphabetBoardPath(string target) {
        // Starting position (0,0)
        int currentRow = 0, currentCol = 0;
        string result;

        // Helper lambda to get row and col from a letter.
        auto getPosition = [](char letter) {
            int index = letter - 'a';
            return make_pair(index / 5, index % 5);
        };

        for (char ch : target) {
            auto [targetRow, targetCol] = getPosition(ch);
            // If target letter is 'z', do horizontal moves first.
            if (ch == 'z') {
                // Move left until columns match.
                while (currentCol > targetCol) {
                    result.push_back('L');
                    currentCol--;
                }
                // Move right if needed.
                while (currentCol < targetCol) {
                    result.push_back('R');
                    currentCol++;
                }
                // Then vertical moves: down.
                while (currentRow < targetRow) {
                    result.push_back('D');
                    currentRow++;
                }
                // Then move up if needed.
                while (currentRow > targetRow) {
                    result.push_back('U');
                    currentRow--;
                }
            } else {
                // For non-'z' letters, move vertically first.
                while (currentRow > targetRow) {
                    result.push_back('U');
                    currentRow--;
                }
                while (currentRow < targetRow) {
                    result.push_back('D');
                    currentRow++;
                }
                // Then move horizontally.
                while (currentCol > targetCol) {
                    result.push_back('L');
                    currentCol--;
                }
                while (currentCol < targetCol) {
                    result.push_back('R');
                    currentCol++;
                }
            }
            // Append action to pick the letter.
            result.push_back('!');
        }
        return result;
    }
};

