#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
using namespace std;

// Function to compute the longest common subsequence
int longestCommonSubsequence(string text1, string text2) {
    int m = text1.size(), n = text2.size();
    // Create a (m+1) x (n+1) DP table initialized with 0
    vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));

    // Build the DP table using bottom-up dynamic programming
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            // If the current characters match, extend the subsequence length by 1
            if (text1[i - 1] == text2[j - 1])
                dp[i][j] = dp[i - 1][j - 1] + 1;
            else
                // Otherwise, choose the maximum between omitting one character either from text1 or text2
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
        }
    }
    return dp[m][n];
}

