    vector<tuple<int, string, string>> logs;
    for (int i = 0; i < n; i++)
        logs.push_back({timestamp[i], username[i], website[i]});
    sort(logs.begin(), logs.end());

    // Map user to list of websites visited in order.
    unordered_map<string, vector<string>> userVisits;
    for (auto& log : logs) {
        int time;
        string user, site;
        tie(time, user, site) = log;
        userVisits[user].push_back(site);
    }

    // Map each pattern (as concatenated string with delimiters) to set of users
    unordered_map<string, set<string>> patternUsers;

    // For each user, generate all unique 3-sequences.
    for (auto& p : userVisits) {
        string user = p.first;
        vector<string>& sites = p.second;
        int size = sites.size();
        set<string> seen;
        if (size < 3) continue;
        for (int i = 0; i < size - 2; i++) {
            for (int j = i + 1; j < size - 1; j++) {
                for (int k = j + 1; k < size; k++) {
                    string pattern = sites[i] + " " + sites[j] + " " + sites[k];
                    if (seen.find(pattern) == seen.end()) {
                        seen.insert(pattern);
                        patternUsers[pattern].insert(user);
                    }
                }
            }
        }
    }

    // Determine the pattern with maximum count; if tie, lexicographical smallest.
    string bestPattern;
    int bestCount = 0;
    for (auto& entry : patternUsers) {
        int count = entry.second.size();
        if (count > bestCount || (count == bestCount && (bestPattern.empty() || entry.first < bestPattern))) {
            bestCount = count;
            bestPattern = entry.first;
        }
    }

    // Split the best pattern string by space to return vector<string>
    vector<string> result;
    size_t pos = 0, found;
    while((found = bestPattern.find(' ', pos)) != string::npos) {
        result.push_back(bestPattern.substr(pos, found - pos));
        pos = found + 1;
    }
    result.push_back(bestPattern.substr(pos));
    return result;
}

