#include <string>
#include <unordered_map>
using namespace std;

class FileSystem {
private:
    // Hash map to store the path and its value.
    unordered_map<string, int> paths;
public:
    FileSystem() { }

    bool createPath(string path, int value) {
        // Check if the path already exists.
        if (paths.count(path)) return false;

        // Obtain the index of the last '/'.
        int lastSlash = path.find_last_of('/');
        string parent = (lastSlash == 0) ? "" : path.substr(0, lastSlash);

        // If it's not a root level path, ensure the parent exists.
        if (!parent.empty() && !paths.count(parent)) return false;

        // Insert the new path with its associated value.
        paths[path] = value;
        return true;
    }

    int get(string path) {
        // Return the value if the path exists, otherwise return -1.
        return paths.count(path) ? paths[path] : -1;
    }
};

