#include <iostream>
#include <queue>
#include <vector>
using namespace std;

int connectSticks(vector<int>& sticks) {
    // Create a min-heap using priority_queue with greater comparator
    priority_queue<int, vector<int>, greater<int>> minHeap(sticks.begin(), sticks.end());

    int totalCost = 0;
    // Continue connecting sticks until only one remains
    while(minHeap.size() > 1) {
        // Extract the two smallest sticks
        int stick1 = minHeap.top();
        minHeap.pop();
        int stick2 = minHeap.top();
        minHeap.pop();
        int cost = stick1 + stick2;
        totalCost += cost;
        // Push the combined stick back into the min-heap
        minHeap.push(cost);
    }

    return totalCost;
}

