/**
 * Definition for singly-linked list.
 */
struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* removeZeroSumSublists(ListNode* head) {
        // Create a dummy node to simplify the removal of leading nodes.
        ListNode* dummy = new ListNode(0);
        dummy->next = head;

        // Map to store prefix sum to node mapping.
        unordered_map<int, ListNode*> prefixSumToNode;
        int prefixSum = 0;
        ListNode* current = dummy;

        // First pass: record the last occurrence of each prefix sum.
        while (current != nullptr) {
            prefixSum += current->val;
            prefixSumToNode[prefixSum] = current;
            current = current->next;
        }

        // Second pass: remove zero sum sequences.
        current = dummy;
        prefixSum = 0;
        while (current != nullptr) {
            prefixSum += current->val;
            // Set current->next to the next pointer of the node corresponding to the last occurrence of this prefix sum.
            current->next = prefixSumToNode[prefixSum]->next;
            current = current->next;
        }

        ListNode* result = dummy->next;
        delete dummy; // Free the dummy node.
        return result;
    }
};

