class Solution {
public:
    vector<vector<int>> criticalConnections(int n, vector<vector<int>>& connections) {
        vector<vector<int>> graph(n);
        // Build the adjacency list for the graph
        for (auto& edge : connections) {
            int u = edge[0], v = edge[1];
            graph[u].push_back(v);
            graph[v].push_back(u);
        }

        vector<int> disc(n, -1), low(n, 0);
        vector<vector<int>> bridges;
        int time = 0;
        dfs(0, -1, time, disc, low, graph, bridges);
        return bridges;
    }
private:
    void dfs(int u, int parent, int &time, vector<int>& disc, vector<int>& low,
             const vector<vector<int>>& graph, vector<vector<int>>& bridges) {
        // Set discovery and low-link values for u
        disc[u] = low[u] = time++;

        // Visit all adjacent vertices
        for (int v : graph[u]) {
            if (disc[v] == -1) { // v is not visited
                dfs(v, u, time, disc, low, graph, bridges);
                low[u] = min(low[u], low[v]);
                // Check if edge (u,v) is a bridge
                if (low[v] > disc[u]) {
                    bridges.push_back({u, v});
                }
            } else if (v != parent) { // v is already visited and is not the parent (back edge)
                low[u] = min(low[u], disc[v]);
            }
        }
    }
};

