    int n = 4;
    vector<vector<int>> connections = {{0,1},{1,2},{2,0},{1,3}};
    Solution sol;
    vector<vector<int>> result = sol.criticalConnections(n, connections);

    // Print critical connections
    for (auto &edge : result) {
        cout << "[" << edge[0] << ", " << edge[1] << "] ";
    }
    return 0;
}

