// C++ solution using BFS:
#include <iostream>
#include <queue>
#include <unordered_set>
#include <tuple>
#include <cstdlib>
#include <string>
using namespace std;

// Helper function to generate a unique key for positions
string posKey(int x, int y) {
    return to_string(x) + "," + to_string(y);
}

int minKnightMoves(int x, int y) {
    // Normalize target coordinates using absolute values
    x = abs(x);
    y = abs(y);

    // Array representing the eight possible knight moves
    int moves[8][2] = {{2,1}, {1,2}, {-1,2}, {-2,1}, {-2,-1}, {-1,-2}, {1,-2}, {2,-1}};

    // BFS queue: each element is a tuple (current_x, current_y, move_count)
    queue<tuple<int, int, int>> bfsQueue;
    bfsQueue.push(make_tuple(0, 0, 0));

    // Unordered set to track visited positions
    unordered_set<string> visited;
    visited.insert("0,0");

    while (!bfsQueue.empty()) {
        auto [currX, currY, movesCount] = bfsQueue.front();
        bfsQueue.pop();

        // Return count if target is reached
        if (currX == x && currY == y)
            return movesCount;

        // Explore all possible moves
        for (int i = 0; i < 8; i++) {
            int nextX = currX + moves[i][0];
            int nextY = currY + moves[i][1];
            string key = posKey(nextX, nextY);

            // Prune the search by considering valid bounds
            if (visited.find(key) == visited.end() && nextX >= -1 && nextY >= -1) {
                visited.insert(key);
                bfsQueue.push(make_tuple(nextX, nextY, movesCount + 1));
