class Solution {
public:
    bool twoSumBSTs(TreeNode* root1, TreeNode* root2, int target) {
        // Set to store values from the first BST.
        unordered_set<int> valuesSet;

        // DFS function to traverse and store values from tree.
        function<void(TreeNode*)> dfsCollect = [&](TreeNode* node) {
            if (!node) return;
            valuesSet.insert(node->val);   // Add current node's value.
            dfsCollect(node->left);          // Go to left child.
            dfsCollect(node->right);         // Go to right child.
        };

        dfsCollect(root1);  // Collect values from first tree.

        // DFS function to check each node in the second tree.
        function<bool(TreeNode*)> dfsCheck = [&](TreeNode* node) -> bool {
            if (!node) return false;
            // Check if complement exists in the set.
            if (valuesSet.find(target - node->val) != valuesSet.end()) return true;
            return dfsCheck(node->left) || dfsCheck(node->right);
        };

        return dfsCheck(root2);  // Return true if valid pair exists.
    }
};

