#include <vector>
#include <algorithm>
#include <iostream>
using namespace std;

struct Job {
    int s, e, p;
};

int jobScheduling(vector<int>& startTime, vector<int>& endTime, vector<int>& profit) {
    int n = startTime.size();
    vector<Job> jobs(n);
    // Create jobs array from input arrays.
    for (int i = 0; i < n; i++) {
        jobs[i] = {startTime[i], endTime[i], profit[i]};
    }
    // Sort jobs based on end time.
    sort(jobs.begin(), jobs.end(), [](const Job &a, const Job &b) {
        return a.e < b.e;
    });

    // dpEndTimes and dpProfits store the end times and maximum profit up to those times.
    vector<int> dpEndTimes = {0};
    vector<int> dpProfits = {0};

    // Process each job.
    for (const auto &job : jobs) {
        // Binary search: Find last index where dpEndTimes[index] is <= job.s.
        int low = 0, high = dpEndTimes.size();
        while (low < high) {
            int mid = low + (high - low) / 2;
            if (dpEndTimes[mid] <= job.s)
                low = mid + 1;
            else
                high = mid;
        }
        int index = low - 1;
        int currentProfit = dpProfits[index] + job.p;
        // Update dp arrays if including this job increases profit.
        if (currentProfit > dpProfits.back()) {
            dpEndTimes.push_back(job.e);
            dpProfits.push_back(currentProfit);
        }
    }
    return dpProfits.back();
}

int main() {
    vector<int> startTime = {1,2,3,3};
    vector<int> endTime = {3,4,5,6};
    vector<int> profit = {50,10,40,70};
    cout << jobScheduling(startTime, endTime, profit) << endl;
    return 0;
}

