// C++ Code Solution

class Solution {
public:
    // Helper function to extract hostname from a URL string.
    string getHostname(const string& url) {
        // Remove the protocol part "http://"
        string noProtocol = url.substr(7);
        // The hostname is until the first '/'
        int pos = noProtocol.find('/');
        return pos == string::npos ? noProtocol : noProtocol.substr(0, pos);
    }

    vector<string> crawl(string startUrl, HtmlParser* htmlParser) {
        unordered_set<string> visited;
        queue<string> bfsQueue;

        string startHostname = getHostname(startUrl);
        visited.insert(startUrl);
        bfsQueue.push(startUrl);

        while (!bfsQueue.empty()) {
            string currentUrl = bfsQueue.front();
            bfsQueue.pop();
            // Get all URLs linked from currentUrl
            vector<string> urls = htmlParser->getUrls(currentUrl);
            for (const string &url : urls) {
                if (visited.find(url) == visited.end() && getHostname(url) == startHostname) {
                    visited.insert(url);
                    bfsQueue.push(url);
                }
            }
        }

        // Convert visited set to vector.
        return vector<string>(visited.begin(), visited.end());
    }
};

