#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <queue>
#include <mutex>
#include <thread>
#include <regex>
#include <sstream>
using namespace std;

// HtmlParser interface assumed to be provided
class HtmlParser {
public:
    vector<string> getUrls(string url);
};

// Helper function to extract hostname from the URL (simple implementation)
string getHost(const string &url) {
    regex rgx("http://([^/]+)");
    smatch match;
    if (regex_search(url, match, rgx)) {
        return match[1];
    }
    return "";
}

void worker(queue<string>& urlQueue, set<string>& visited, mutex &m, HtmlParser &htmlParser, const string &startHost) {
    while (true) {
        string currUrl;
        {
            lock_guard<mutex> lock(m);
            if (urlQueue.empty()) break;
            currUrl = urlQueue.front();
            urlQueue.pop();
        }
        vector<string> urls = htmlParser.getUrls(currUrl);
        for (const auto &nextUrl : urls) {
            if (getHost(nextUrl) == startHost) {
                lock_guard<mutex> lock(m);
                if (visited.find(nextUrl) == visited.end()){
                    visited.insert(nextUrl);
                    urlQueue.push(nextUrl);
                }
            }
        }
    }
}

vector<string> crawl(string startUrl, HtmlParser &htmlParser) {
    string startHost = getHost(startUrl);
    set<string> visited;
    queue<string> urlQueue;
    mutex m;

    // Initialize with startUrl
    visited.insert(startUrl);
    urlQueue.push(startUrl);

    int numThreads = 8;
    vector<thread> threads;
    for (int i = 0; i < numThreads; i++) {
        threads.push_back(thread(worker, ref(urlQueue), ref(visited), ref(m), ref(htmlParser), ref(startHost)));
    }

    for (auto &t : threads) {
        t.join();
    }

    return vector<string>(visited.begin(), visited.end());
}

