// C++ solution to remove the specified interval from a list of intervals.
#include <vector>
using namespace std;

class Solution {
public:
    vector<vector<int>> removeInterval(vector<vector<int>>& intervals, vector<int>& toBeRemoved) {
        int removeStart = toBeRemoved[0], removeEnd = toBeRemoved[1];
        vector<vector<int>> result;

        // Iterate over each interval.
        for (auto& interval : intervals) {
            int start = interval[0], end = interval[1];

            // If interval is completely outside of toBeRemoved, add it as is.
            if (end <= removeStart || start >= removeEnd) {
                result.push_back({start, end});
            } else {
                // If there is a left portion not affected by removal.
                if (start < removeStart) {
                    result.push_back({start, removeStart});
                }
                // If there is a right portion not affected by removal.
                if (end > removeEnd) {
                    result.push_back({removeEnd, end});
                }
            }
        }
        return result;
    }
};

