// C++ solution using deque from STL for maintaining sliding window maximum.
#include <vector>
#include <deque>
#include <algorithm>
using namespace std;

class Solution {
public:
    int constrainedSubsequenceSum(vector<int>& nums, int k) {
        int n = nums.size();
        vector<int> dp(n, 0); // dp[i] stores the maximum subsequence sum ending at i
        dp[0] = nums[0];
        int result = dp[0];
        deque<int> deq;
        deq.push_back(0);

        for (int i = 1; i < n; i++) {
            // Remove indices from the front that are out of the window
            while (!deq.empty() && i - deq.front() > k) {
                deq.pop_front();
            }

            int maxInWindow = dp[deq.front()] > 0 ? dp[deq.front()] : 0;
            dp[i] = nums[i] + maxInWindow;
            result = max(result, dp[i]);

            // Maintain deque in decreasing order of dp values
            while (!deq.empty() && dp[i] >= dp[deq.back()]) {
                deq.pop_back();
            }
            deq.push_back(i);
        }

        return result;
    }
};

