// C++ solution to count elements where (x + 1) is in the array
#include <iostream>
#include <vector>
#include <unordered_set>
using namespace std;

int countElements(const vector<int>& arr) {
    // Create an unordered_set for constant time lookups
    unordered_set<int> uniqueNumbers(arr.begin(), arr.end());
    int count = 0;
    // Iterate over every element in the vector
    for (int number : arr) {
        // If (number + 1) is found in the set, increment the count
        if (uniqueNumbers.find(number + 1) != uniqueNumbers.end()) {
            count++;
        }
    }
    return count;
}

