#include <iostream>
#include <vector>
#include <string>
using namespace std;

string stringShift(string s, vector<vector<int>>& shift) {
    int netShift = 0;
    int n = s.size();
    // Compute overall shift
    for(auto& op : shift) {
        int direction = op[0], amount = op[1];
        if (direction == 0)
            netShift -= amount;  // Left shift reduces index
        else
            netShift += amount;  // Right shift increases index
    }

    // Normalize the shift to be within string bounds
    netShift = ((netShift % n) + n) % n;

    // Construct shifted string using substring operations
    return s.substr(n - netShift) + s.substr(0, n - netShift);
}

int main() {
    string s = "abcdefg";
    vector<vector<int>> shiftOps = { {1,1}, {1,1}, {0,2}, {1,3} };
    cout << stringShift(s, shiftOps) << endl;  // Output: "efgabcd"
    return 0;
}

