using namespace std;

class FirstUnique {
private:
    queue<int> q;                   // Queue to maintain order of numbers.
    unordered_map<int, int> count;  // Hash map to store frequency count.

public:
    // Initializes the object with the numbers in the queue.
    FirstUnique(vector<int>& nums) {
        for (int num : nums) {
            add(num);
        }
    }

    // Returns the first unique integer. If none exists, returns -1.
    int showFirstUnique() {
        // Remove non-unique elements from the front.
        while (!q.empty() && count[q.front()] > 1) {
            q.pop();
        }
        return q.empty() ? -1 : q.front();
    }

    // Inserts a value into the queue.
    void add(int value) {
        count[value]++;
        // Only add to the queue if this is the first occurrence.
        if (count[value] == 1) {
            q.push(value);
        }
    }
};

