    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* deleteNodes(ListNode* head, int m, int n) {
        ListNode* current = head;
        while (current != nullptr) {
            // Skip m nodes.
            for (int i = 1; i < m && current != nullptr; i++) {
                current = current->next;
            }
            // If end reached, break.
            if (current == nullptr) break;
            // Start deletion from next node.
            ListNode* temp = current->next;
            // Delete next n nodes.
            for (int j = 0; j < n && temp != nullptr; j++) {
                ListNode* nodeToDelete = temp;
                temp = temp->next;
                // Optionally, free memory: delete nodeToDelete;
            }
            // Link current node to the node after the deleted nodes.
            current->next = temp;
            // Move current pointer forward.
            current = temp;
        }
        return head;
    }
};

