#include <vector>
using namespace std;

class Node {
public:
    int val;
    vector<Node*> children;

    // Constructor
    Node() {}

    Node(int _val) {
        val = _val;
    }

    Node(int _val, vector<Node*> _children) {
        val = _val;
        children = _children;
    }
};

class Solution {
public:
    Node* cloneTree(Node* root) {
        // Base case: if root is null, return null.
        if (!root) return nullptr;

        // Create a new node with the same value as root.
        Node* clonedNode = new Node(root->val);

        // Recursively clone each child and add it to the cloned node's children.
        for (Node* child : root->children) {
            clonedNode->children.push_back(cloneTree(child));
        }

        // Return the cloned node.
        return clonedNode;
    }
};

