class Solution {
public:
    Node* findRoot(vector<Node*> tree) {
        int totalSum = 0;
        int childrenSum = 0;

        // Traverse each node to compute aggregate values
        for (auto node : tree) {
            totalSum += node->val;  // Add the node's value to totalSum
            // Loop through each child of the node and add their values to childrenSum
            for (auto child : node->children) {
                childrenSum += child->val;
            }
        }

        // Identify the root's value by subtracting childrenSum from totalSum
        int rootVal = totalSum - childrenSum;

        // Iterate again to locate and return the root node
        for (auto node : tree) {
            if (node->val == rootVal)
                return node;
        }
        return nullptr; // This scenario should not occur for a valid input tree
    }
};

