class Solution {
public:
    int maxDiameter = 0;

    int dfs(Node* node) {
        if (!node) return 0; // Base case

        // Variables to track the top two depths among children.
        int maxDepth1 = 0, maxDepth2 = 0;

        // Recurse for each child.
        for (auto child : node->children) {
            int childDepth = dfs(child);
            if(childDepth > maxDepth1) {
                maxDepth2 = maxDepth1;
                maxDepth1 = childDepth;
            } else if(childDepth > maxDepth2) {
                maxDepth2 = childDepth;
            }
        }

        // Update the global maximum diameter.
        maxDiameter = max(maxDiameter, maxDepth1 + maxDepth2);

        // Return the maximum depth from the current node.
        return maxDepth1 + 1;
    }

    int diameter(Node* root) {
        dfs(root);
        return maxDiameter;
    }
};

