// C++ solution with line-by-line comments
class Solution {
public:
    int getIndex(ArrayReader &reader) {
        int left = 0, right = reader.length() - 1;

        // Binary search to narrow down the candidate index
        while (left < right) {
            int length = right - left + 1;
            if (length % 2 == 0) {
                // Even length: split into two equal halves
                int mid = left + length / 2;
                // Compare left half [left, mid - 1] with right half [mid, right]
                int comp = reader.compareSub(left, mid - 1, mid, right);
                if (comp == 1)
                    right = mid - 1;  // Candidate is in left half
                else
                    left = mid;       // Candidate is in right half
            } else {
                // Odd length: split into equal halves ignoring the middle element
                int half = length / 2;
                int comp = reader.compareSub(left, left + half - 1, right - half + 1, right);
                if (comp == 1)
                    right = left + half - 1;  // Candidate in left half
                else if (comp == -1)
                    left = right - half + 1;  // Candidate in right half
                else
                    return left + half;       // Middle element is the large integer
            }
        }
        return left;
    }
};

