class Solution {
public:
    Node* lowestCommonAncestor(Node* p, Node* q) {
        auto getDepth = [&](Node* node) -> int {
            int depth = 0;
            while (node) {
                depth++;
                node = node->parent;
            }
            return depth;
        };

        int depthP = getDepth(p);
        int depthQ = getDepth(q);

        // Equalize p and q to the same depth
        while (depthP > depthQ) {
            p = p->parent;
            depthP--;
        }
        while (depthQ > depthP) {
            q = q->parent;
            depthQ--;
        }

        // Traverse upward until a common ancestor is found
        while (p != q) {
            p = p->parent;
            q = q->parent;
        }

        return p;
    }
};

