// BFS solution in C++
#include <iostream>
#include <vector>
#include <queue>
using namespace std;

int getFood(vector<vector<char>>& grid) {
    int rows = grid.size();
    int cols = grid[0].size();
    int startRow, startCol;
    // search for the starting point '*'
    for (int r = 0; r < rows; r++) {
        for (int c = 0; c < cols; c++) {
            if (grid[r][c] == '*') {
                startRow = r;
                startCol = c;
                break;
            }
        }
    }

    // queue for BFS: each element is (row, col, steps)
    queue<tuple<int, int, int>> q;
    q.push({startRow, startCol, 0});

    // visited 2D vector to mark explored cells
    vector<vector<bool>> visited(rows, vector<bool>(cols, false));
    visited[startRow][startCol] = true;

    // possible move directions (up, right, down, left)
    vector<pair<int, int>> directions = {{-1,0}, {0,1}, {1,0}, {0,-1}};

    while (!q.empty()) {
        auto [row, col, steps] = q.front();
        q.pop();
        // if food cell '#' is found, return the steps taken
        if (grid[row][col] == '#') {
            return steps;
        }
        // explore adjacent cells
        for (auto [dr, dc] : directions) {
            int newRow = row + dr;
            int newCol = col + dc;
            // check boundaries, visited and obstacles
            if (newRow >= 0 && newRow < rows && newCol >= 0 && newCol < cols &&
                !visited[newRow][newCol] && grid[newRow][newCol] != 'X') {
                visited[newRow][newCol] = true;
                q.push({newRow, newCol, steps + 1});
            }
        }
    }
    // return -1 if no path to any food cell is found
    return -1;
}

int main() {
    vector<vector<char>> grid = {
        {'X','X','X','X','X','X'},
        {'X','*','O','O','O','X'},
        {'X','O','O','#','O','X'},
        {'X','X','X','X','X','X'}
    };
    cout << getFood(grid) << endl; // Expected output: 3
    return 0;
}

