#include <vector>
#include <algorithm>
using namespace std;

vector<int> findBuildingsWithOceanView(vector<int>& heights) {
    int n = heights.size();
    vector<int> result;
    int maxHeight = 0;
    // Iterate from the rightmost building to the leftmost building.
    for (int i = n - 1; i >= 0; i--) {
        if (heights[i] > maxHeight) {
            result.push_back(i);
            maxHeight = heights[i];
        }
    }
    // Reverse the result to return indices in increasing order.
    reverse(result.begin(), result.end());
    return result;
}

