// C++ solution
#include <vector>
#include <string>
#include <unordered_map>
#include <algorithm>
using namespace std;

class Solution {
public:
    int longestPalindrome(vector<string>& words) {
        unordered_map<string, int> wordCount;
        for (const auto& word : words) {
            wordCount[word]++;
        }
        int length = 0;
        bool centerUsed = false;

        for (auto& [word, count] : wordCount) {
            string reverse = word;
            reverse[0] = word[1];
            reverse[1] = word[0];

            if (word == reverse) {
                // Self-palindromic word
                length += (count / 2) * 2;
                if (count % 2 == 1 && !centerUsed) {
                    length += 1;
                    centerUsed = true;
                }
            } else if (wordCount.find(reverse) != wordCount.end()) {
                // Count pair only once
                int pairCount = min(count, wordCount[reverse]);
                length += pairCount * 2;
                // Mark the reverse as used
                wordCount[reverse] = 0;
            }
        }
        return length * 2; // Each word contributes 2 letters
    }
};

