// C++ implementation using threads to simulate debouncing
#include <iostream>
#include <thread>
#include <chrono>
#include <functional>
#include <mutex>

using namespace std;

class Debounce {
public:
    // Constructor takes the function to debounce and the delay in milliseconds
    Debounce(function<void()> fn, int t) : fn(fn), delay(t), cancelFlag(false) {}

    // Operator() to call the debounced function
    void operator()() {
        {
            lock_guard<mutex> lock(mtx);
            // Flag any existing scheduled call as cancelled
            cancelFlag = true;
        }
        // Start a new detached thread for the new call
        thread([this]() {
            {
                lock_guard<mutex> lock(mtx);
                // Mark this call as the newest (reset cancellation flag)
                cancelFlag = false;
            }
            // Wait for the specified delay
            this_thread::sleep_for(chrono::milliseconds(delay));
            bool execute = false;
            {
                lock_guard<mutex> lock(mtx);
                // Only execute if no newer call has cancelled this one
                if (!cancelFlag) {
                    execute = true;
                }
            }
            if (execute) {
                fn();
            }
        }).detach();
    }

private:
    function<void()> fn;
    int delay;
    mutex mtx;
    bool cancelFlag;
};

// Example usage:
int main() {
    auto start = chrono::steady_clock::now();
    auto log = [start]() {
        auto end = chrono::steady_clock::now();
        auto diff = chrono::duration_cast<chrono::milliseconds>(end - start).count();
        cout << "Time: " << diff << " ms, Executed log" << endl;
    };

    Debounce dlog(log, 50);
    // Simulate first call at t=50ms
    this_thread::sleep_for(chrono::milliseconds(50));
    dlog();
    // Simulate second call at t=75ms which cancels the previous call
    this_thread::sleep_for(chrono::milliseconds(25));
    dlog();
    // Wait enough time for the last call to execute
    this_thread::sleep_for(chrono::milliseconds(100));
    return 0;
}

