// Note: This C++ solution assumes the use of the nlohmann::json library.
// Include the library header and use the nlohmann::json type.
#include <iostream>
#include <nlohmann/json.hpp>
#include <vector>
#include <string>
#include <cassert>
using json = nlohmann::json;

// Recursive function to compare two json objects deeply.
bool deepEqual(const json &o1, const json &o2) {
    // If both are exactly equal, return true.
    if (o1 == o2) return true;

    // If types differ, return false.
    if (o1.type() != o2.type()) return false;

    // If both are arrays, check size and compare each element.
    if (o1.is_array()) {
        if (o1.size() != o2.size()) return false;
        for (size_t i = 0; i < o1.size(); ++i) {
            if (!deepEqual(o1[i], o2[i])) return false;
        }
        return true;
    }

    // If both are objects, compare keys and then each key-value pair.
    if (o1.is_object()) {
        if (o1.size() != o2.size()) return false;
        for (auto it = o1.begin(); it != o1.end(); ++it) {
            std::string key = it.key();
            // Check if the second object contains the key.
            if (o2.find(key) == o2.end()) return false;
            if (!deepEqual(it.value(), o2[key])) return false;
        }
        return true;
    }

    // For number, string, boolean, or null, the operator== check suffices.
    return o1 == o2;
}

int main() {
    // Example usage:
    json obj1 = {{"x", 1}, {"y", 2}};
    json obj2 = {{"y", 2}, {"x", 1}};
    assert(deepEqual(obj1, obj2) == true);
    std::cout << "Test passed!" << std::endl;
    return 0;
}

