#include <iostream>
#include <string>
#include <vector>
#include <sstream>

// To preserve key insertion order in a JSON object, we use a vector of pairs.
struct JsonValue {
    enum Type { Null, Boolean, Number, String, Array, Object } type;
    bool boolVal;
    double numVal;
    std::string strVal;
    std::vector<JsonValue> arrVal;
    std::vector<std::pair<std::string, JsonValue>> objVal;

    // Constructors for various types
    JsonValue() : type(Null) {}
    JsonValue(std::nullptr_t) : type(Null) {}
    JsonValue(bool b) : type(Boolean), boolVal(b) {}
    JsonValue(double d) : type(Number), numVal(d) {}
    JsonValue(const std::string &s) : type(String), strVal(s) {}
    JsonValue(const char* s) : type(String), strVal(s) {}
    JsonValue(const std::vector<JsonValue>& arr) : type(Array), arrVal(arr) {}
    JsonValue(const std::vector<std::pair<std::string, JsonValue>>& obj) : type(Object), objVal(obj) {}
};

std::string myStringify(const JsonValue &value) {
    std::ostringstream oss;
    switch(value.type) {
        case JsonValue::Null:
            return "null";
        case JsonValue::Boolean:
            return value.boolVal ? "true" : "false";
        case JsonValue::Number:
            oss << value.numVal;
            return oss.str();
        case JsonValue::String:
            return "\"" + value.strVal + "\"";
        case JsonValue::Array: {
            std::string res = "[";
            for (size_t i = 0; i < value.arrVal.size(); i++) {
                res += myStringify(value.arrVal[i]);
                if(i < value.arrVal.size() - 1)
                    res += ",";
            }
            res += "]";
            return res;
        }
        case JsonValue::Object: {
            std::string res = "{";
            for (size_t i = 0; i < value.objVal.size(); i++) {
                res += "\"" + value.objVal[i].first + "\":" + myStringify(value.objVal[i].second);
                if(i < value.objVal.size() - 1)
                    res += ",";
            }
            res += "}";
            return res;
        }
    }
    return "";
}

int main(){
    // Example: {"y":1,"x":2}
    JsonValue jsonObj({
        {"y", JsonValue(1)},
        {"x", JsonValue(2)}
    });
    std::cout << myStringify(jsonObj) << std::endl;
    return 0;
}

