// Note: C++ does not have native support for async/await in the same sense as JS/Python,
// but we can mimic this behavior using threads and futures.
// The following is a conceptual implementation using std::async and a thread-safe index.

#include <iostream>
#include <vector>
#include <future>
#include <thread>
#include <chrono>
#include <mutex>
#include <functional>

using AsyncFunction = std::function<void()>;

void promisePool(const std::vector<AsyncFunction>& functions, int n) {
    std::mutex mtx;
    size_t index = 0;

    // Worker function that loops until all tasks are executed.
    auto worker = [&]() {
        while (true) {
            mtx.lock();
            if (index >= functions.size()) {
                mtx.unlock();
                break;
            }
            // Get the current task and increment index.
            auto fn = functions[index++];
            mtx.unlock();
            // Execute the asynchronous task.
            fn();
        }
    };

    // Launch n threads to work concurrently.
    std::vector<std::future<void>> pool;
    for (int i = 0; i < n; ++i) {
        pool.push_back(std::async(std::launch::async, worker));
    }

    // Wait for all workers to finish.
    for (auto& fut : pool) {
        fut.get();
    }
}

// Example usage:
int main() {
    std::vector<AsyncFunction> functions = {
        []() { std::this_thread::sleep_for(std::chrono::milliseconds(300)); },
        []() { std::this_thread::sleep_for(std::chrono::milliseconds(400)); },
        []() { std::this_thread::sleep_for(std::chrono::milliseconds(200)); }
    };
    promisePool(functions, 2);
    std::cout << "All tasks finished." << std::endl;
    return 0;
}

