// Include necessary headers
#include <iostream>
#include <map>
#include <vector>
#include <variant>
#include <string>
#include <optional>
#include <type_traits>
using namespace std;

// Define a variant type for JSON values: 
// it can be double, string, bool, nullptr_t, map<string, JSONValue> or vector<JSONValue>
struct JSONValue;
using JSONObject = map<string, JSONValue>;
using JSONArray = vector<JSONValue>;

struct JSONValue : public std::variant<nullptr_t, double, string, bool, JSONObject, JSONArray> {
    using variant::variant;
};

// Helper function to check equality of two JSONValue objects
bool jsonEquals(const JSONValue &a, const JSONValue &b);

// Recursive function to compute differences. Returns optional<JSONValue> containing JSONObject if differences exist.
optional<JSONValue> diffJSON(const JSONValue &a, const JSONValue &b) {
    // Check if both are JSONObject
    if(auto obj1 = std::get_if<JSONObject>(&a)) {
        if(auto obj2 = std::get_if<JSONObject>(&b)) {
            JSONObject diff;
            // Iterate over keys present in both objects
            for (const auto &entry : *obj1) {
                const string &key = entry.first;
                auto it = obj2->find(key);
                if (it != obj2->end()) {
                    auto subDiff = diffJSON(entry.second, it->second);
                    if (subDiff.has_value()) {
                        // Insert the diff into result
                        diff[key] = subDiff.value();
                    }
                }
            }
            if (!diff.empty()) return JSONValue(diff);
            else return nullopt;
        }
    }
    // Check if both are JSONArray
    if(auto arr1 = std::get_if<JSONArray>(&a)) {
        if(auto arr2 = std::get_if<JSONArray>(&b)) {
            JSONObject diff;
            // Only compare common indices
            size_t len = min(arr1->size(), arr2->size());
            for (size_t i = 0; i < len; i++) {
                auto subDiff = diffJSON((*arr1)[i], (*arr2)[i]);
                if (subDiff.has_value()) {
                    diff[to_string(i)] = subDiff.value();
                }
            }
            if (!diff.empty()) return JSONValue(diff);
            else return nullopt;
        }
    }
    // For primitive values or when types differ
    if (jsonEquals(a, b))
        return nullopt;
    else
        return JSONValue(vector<JSONValue>{a, b}); // Represent the difference as an array of two elements.
}

// Simple equality checker for JSONValue primitives and containers
bool jsonEquals(const JSONValue &a, const JSONValue &b) {
    // Use variant's equality for simple types. For objects/arrays we assume they are deeply compared.
    return a == b;
}

// A wrapper function that returns a JSONObject representing differences
JSONObject differencesBetweenTwoObjects(const JSONValue &obj1, const JSONValue &obj2) {
    auto result = diffJSON(obj1, obj2);
    if (result.has_value()) {
        // The result should be an object
        if(auto diffObj = std::get_if<JSONObject>(&result.value()))
            return *diffObj;
        // If it is not an object, wrap it in an object with a key (rare case).
    }
    return JSONObject{};
}

int main(){
    // For brevity, we simulate example objects using JSONValue.
    // Example: obj1 = { "a": 5, "v": 6, "z": [1, 2, 4, [2, 5, 7]] }
    JSONObject obj1;
    obj1["a"] = 5.0;
    obj1["v"] = 6.0;
    JSONArray z1;
    z1.push_back(1.0);
    z1.push_back(2.0);
    z1.push_back(4.0);
    JSONArray inner1;
    inner1.push_back(2.0);
    inner1.push_back(5.0);
    inner1.push_back(7.0);
    z1.push_back(inner1);
    obj1["z"] = z1;

    // obj2 = { "a": 5, "v": 7, "z": [1, 2, 3, [1]] }
    JSONObject obj2;
    obj2["a"] = 5.0;
    obj2["v"] = 7.0;
    JSONArray z2;
    z2.push_back(1.0);
    z2.push_back(2.0);
    z2.push_back(3.0);
    JSONArray inner2;
    inner2.push_back(1.0);
    z2.push_back(inner2);
    obj2["z"] = z2;

    JSONObject diff = differencesBetweenTwoObjects(JSONValue(obj1), JSONValue(obj2));
    // The printing part is simplified for demonstration.
    cout << "Differences computed in C++ version." << endl;
    return 0;
}

