class Solution:
    def queryResults(self, n: int, queries: List[List[int]]) -> List[int]:
        node_color = {}
        color_count = {}
        ans = []
        for node, color in queries:
            if node in node_color:
                old = node_color[node]
                color_count[old] -= 1
                if color_count[old] == 0:
                    del color_count[old]
            node_color[node] = color
            color_count[color] = color_count.get(color, 0) + 1
            ans.append(len(color_count))
        return ans

cpp_solution:
class Solution {
public:
    vector<int> queryResults(int n, vector<vector<int>>& queries) {
        unordered_map<int,int> nodeColor, colorCount;
        vector<int> ans;
        for (auto& q : queries) {
            int node = q[0], color = q[1];
            if (nodeColor.count(node)) {
                int old = nodeColor[node];
                if (--colorCount[old] == 0) colorCount.erase(old);
            }
            nodeColor[node] = color;
            colorCount[color]++;
            ans.push_back(colorCount.size());
        }
        return ans;
    }
};

